                    $logs = get_db()->query("SELECT * FROM admin_logs ORDER BY created_at DESC LIMIT $log_limit OFFSET $log_offset")->fetchAll();
                    if (empty($logs)): ?>
                      <tr><td colspan="4" class="text-center py-4 text-secondary">No recent admin activity found.</td></tr>
