function romanize_string($string) {
  if (class_exists('Transliterator')) {
    $transliterator = Transliterator::create('Any-Latin; Latin-ASCII; Lower()');
    if ($transliterator) {
      $string = $transliterator->transliterate($string);
    }
  }
  $string = strtolower($string);
  $string = preg_replace('/[^a-z0-9]/', '', $string);
  return empty($string) ? 'unknown' : $string;
}

function sanitize_for_path($string) {
  return romanize_string($string);
}

function get_upload_limit() {
  $max_upload = ini_get('upload_max_filesize');
  $max_post = ini_get('post_max_size');
  return "Max file size: " . min($max_upload, $max_post);
}

function process_image_to_webp($imageData, $target_width = 640, $quality = 78, $crop = true) {
  if (!$imageData || !function_exists('imagecreatefromstring') || !function_exists('imagewebp')) return null;
  $sourceImage = @imagecreatefromstring($imageData);
  if (!$sourceImage) return null;

  $src_w = imagesx($sourceImage);
  $src_h = imagesy($sourceImage);
  
  if ($crop) {
    $min_dim = min($src_w, $src_h);
    $src_x = (int)(($src_w - $min_dim) / 2);
    $src_y = (int)(($src_h - $min_dim) / 2);
    $final_width = min($min_dim, $target_width);
    $final_height = $final_width;
    $copy_w = $min_dim;
    $copy_h = $min_dim;
  } else {
    $src_x = 0; $src_y = 0;
    $copy_w = $src_w; $copy_h = $src_h;
    if ($src_w > $target_width || $src_h > $target_width) {
      $ratio = $src_w / $src_h;
      if ($ratio > 1) {
        $final_width = $target_width;
        $final_height = (int)($target_width / $ratio);
      } else {
        $final_height = $target_width;
        $final_width = (int)($target_width * $ratio);
      }
    } else {
      $final_width = $src_w; $final_height = $src_h;
    }
  }

  $resizedImage = imagecreatetruecolor($final_width, $final_height);
  imagealphablending($resizedImage, false);
  imagesavealpha($resizedImage, true);
  
  $transparent = imagecolorallocatealpha($resizedImage, 255, 255, 255, 127);
  imagefilledrectangle($resizedImage, 0, 0, $final_width, $final_height, $transparent);

  imagecopyresampled($resizedImage, $sourceImage, 0, 0, $src_x, $src_y, $final_width, $final_height, $copy_w, $copy_h);

  ob_start();
  imagewebp($resizedImage, null, $quality);
  $webpData = ob_get_clean();
  
  // Strict 70KB limit enforcer. If it exceeds 71,680 bytes, aggressively compress it.
  if (strlen($webpData) > 71680) {
    ob_start();
    imagewebp($resizedImage, null, 55); 
    $webpData = ob_get_clean();
  }

  imagedestroy($sourceImage);
  imagedestroy($resizedImage);
  return $webpData;
}

function process_image_to_jpeg($imageData, $target_width = 640, $quality = 82, $crop = true) {
  if (!$imageData || !function_exists('imagecreatefromstring') || !function_exists('imagejpeg')) return null;
  $sourceImage = @imagecreatefromstring($imageData);
  if (!$sourceImage) return null;

  $src_w = imagesx($sourceImage);
  $src_h = imagesy($sourceImage);
  
  if ($crop) {
    $min_dim = min($src_w, $src_h);
    $src_x = (int)(($src_w - $min_dim) / 2);
    $src_y = (int)(($src_h - $min_dim) / 2);
    $final_width = min($min_dim, $target_width);
    $final_height = $final_width;
    $copy_w = $min_dim;
    $copy_h = $min_dim;
  } else {
    $src_x = 0; $src_y = 0;
    $copy_w = $src_w; $copy_h = $src_h;
    if ($src_w > $target_width || $src_h > $target_width) {
      $ratio = $src_w / $src_h;
      if ($ratio > 1) {
        $final_width = $target_width;
        $final_height = (int)($target_width / $ratio);
      } else {
        $final_height = $target_width;
        $final_width = (int)($target_width * $ratio);
      }
    } else {
      $final_width = $src_w; $final_height = $src_h;
    }
  }

  $resizedImage = imagecreatetruecolor($final_width, $final_height);
  imagecopyresampled($resizedImage, $sourceImage, 0, 0, $src_x, $src_y, $final_width, $final_height, $copy_w, $copy_h);

  ob_start();
  imagejpeg($resizedImage, null, $quality);
  $jpegData = ob_get_clean();
  
  if (strlen($jpegData) > 71680) {
    ob_start();
    imagejpeg($resizedImage, null, 60);
    $jpegData = ob_get_clean();
  }

  imagedestroy($sourceImage);
  imagedestroy($resizedImage);
  return $jpegData;
}

// =========================================================================================
// EXTERNAL API ROUTER & URL UNTANGLER
// =========================================================================================

$raw_uri = $_SERVER['REQUEST_URI'] ?? '';
$is_public_api = false;

// 1. Aggressive URL matching to detect the exact "access=api" flag regardless of slash mangling
if (strpos($raw_uri, 'access=api') !== false || (isset($_GET['access']) && strpos($_GET['access'], 'api') !== false)) {
  $is_public_api = true;

  // 2. URL Untangler: Extract parameters hidden behind bad slashes (e.g., access=api/?action=...)
  preg_match_all('/(?:[?&]|\/\?)([a-zA-Z0-9_]+)=([^&]+)/', $raw_uri, $matches);
    
  if (!empty($matches[1]) && !empty($matches[2])) {
    foreach ($matches[1] as $index => $key) {
      if (!isset($_GET[$key])) {
        $_GET[$key] = urldecode($matches[2][$index]);
      }
    }
  }

  // 3. Global API Firewall: Require API Key for ALL external requests
  $api_extracted_action = $_GET['action'] ?? '';
  
  $public_media_actions = ['embed', 'get_stream', 'get_image', 'get_profile_picture', 'get_profile_background', 'get_group_image', 'get_app_icon'];
  if (!in_array($api_extracted_action, $public_media_actions)) {
    $api_key = $_GET['api_key'] ?? '';
    
    if (function_exists('init_db')) { init_db(get_db()); }
    $db_fw = get_db();
    
    $is_valid_api = false;

    // Check Master Admin Password (Unlimited uses)
    $stmt_fw = $db_fw->query("SELECT password_hash FROM users WHERE email = 'musiclibrary@mail.com'");
    $master_hash = $stmt_fw->fetchColumn();
          
    if (!empty($master_hash) && password_verify($api_key, $master_hash)) {
      $is_valid_api = true;
    } elseif ($api_key === 'ADMIN_SESSION_BYPASS' && isset($_SESSION['user_id'])) {
      // Securely bypass API check if current active session matches Super Admin
      $stmt_sess = $db_fw->prepare("SELECT email FROM users WHERE id = ?");
      $stmt_sess->execute([$_SESSION['user_id']]);
      if (strtolower(trim($stmt_sess->fetchColumn())) === 'musiclibrary@mail.com') {
        $is_valid_api = true;
      }
    } else {
      // Check Custom API Keys (1,000 uses per month)
      $stmt_key = $db_fw->prepare("SELECT id, uses, reset_month FROM api_keys WHERE token = ?");
      $stmt_key->execute([$api_key]);
      $key_row = $stmt_key->fetch();
      
      if ($key_row) {
        $current_month = date('Y-m');
        if ($key_row['reset_month'] !== $current_month) {
          $db_fw->prepare("UPDATE api_keys SET uses = 0, reset_month = ? WHERE id = ?")->execute([$current_month, $key_row['id']]);
          $key_row['uses'] = 0;
        }
        if ($key_row['uses'] < 1000) {
          $db_fw->prepare("UPDATE api_keys SET uses = uses + 1, updated_at = CURRENT_TIMESTAMP WHERE id = ?")->execute([$key_row['id']]);
          $is_valid_api = true;
        } else {
          http_response_code(429);
          die('{"status":"error", "message":"API limit exceeded (1,000 requests per month)."}');
        }
      }
    }

    if (!$is_valid_api) {
      http_response_code(401);
      die('{"status":"error", "message":"API access denied. Valid API Key required."}');
    }
  }
}

if (isset($_GET['action'])) {
  $action = $_GET['action'];
  $db = get_db();
  
  // 4. STRICT INTERNAL API FIREWALL: Absolute Lockdown
  // If the request does NOT have ?access=api, we enforce strict origin checks.
  if (!$is_public_api) {
    $host = $_SERVER['HTTP_HOST'] ?? '';
    if (strpos($host, ':') !== false) {
      $host = explode(':', $host)[0];
    }
    
    $referer = $_SERVER['HTTP_REFERER'] ?? '';
    $origin = $_SERVER['HTTP_ORIGIN'] ?? $_SERVER['HTTP_X_ORIGIN'] ?? '';
    if ($origin === 'null') $origin = ''; // Explicitly deny local file:/// origin bypasses
    
    $is_valid_internal = false;
    if ($origin && parse_url($origin, PHP_URL_HOST) === $host) {
      $is_valid_internal = true;
    } elseif ($referer && parse_url($referer, PHP_URL_HOST) === $host) {
      $is_valid_internal = true;
    } elseif (in_array($action, ['embed', 'get_stream', 'get_image', 'get_profile_picture', 'get_profile_background', 'get_group_image', 'get_app_icon', 'download_song', 'download_cover', 'export_playlist', 'export_favorites', 'export_offline', 'export_notes'])) {
      // Media routes are allowed internally without headers, but data JSON routes are strictly blocked!
      $is_valid_internal = true;
    }
    
    if (!$is_valid_internal) {
      http_response_code(403);
      send_json([
        'status' => 'error', 
        'message' => 'Access Denied: You must append ?access=api to your URL to fetch data externally.'
      ]);
    }
  }
  
  // Rate Limiting API - ONLY trigger write locks on POST requests or heavy actions to prevent locking concurrent reads on page load
  if ($_SERVER['REQUEST_METHOD'] === 'POST' || in_array($action, ['search', 'full_scan'])) {
    try { 
      $db->exec("CREATE TABLE IF NOT EXISTS api_rate_limits (ip TEXT PRIMARY KEY, hits INTEGER, last_reset INTEGER)"); 
      $ip = $_SERVER['REMOTE_ADDR'];
      $stmt_rl = $db->prepare("SELECT hits, last_reset FROM api_rate_limits WHERE ip = ?");
      $stmt_rl->execute([$ip]);
      $rl = $stmt_rl->fetch();
      $now = time();
      if ($rl) {
        if ($now - $rl['last_reset'] > 60) {
          $db->prepare("UPDATE api_rate_limits SET hits = 1, last_reset = ? WHERE ip = ?")->execute([$now, $ip]);
        } else {
          if ($rl['hits'] > 150) {
            http_response_code(429);
            die('{"status":"error", "message":"Rate limit exceeded. Try again in a minute."}');
          }
          $db->prepare("UPDATE api_rate_limits SET hits = hits + 1 WHERE ip = ?")->execute([$ip]);
        }
      } else {
        $db->prepare("INSERT INTO api_rate_limits (ip, hits, last_reset) VALUES (?, 1, ?)")->execute([$ip, $now]);
      }
    } catch(Exception $e) {}
  }

  // Run database schema updates ONLY ONCE per version/session to prevent massive write-lock congestion on concurrent AJAX requests
  if (!isset($_SESSION['db_initialized']) || $_SESSION['db_initialized'] !== APP_VERSION) {
    
    // Forcefully build blogs table here to ensure it creates immediately
    try {
      $db->exec("
        CREATE TABLE IF NOT EXISTS blogs (
          id INTEGER PRIMARY KEY, 
          user_id INTEGER NOT NULL, 
          title TEXT, 
          content TEXT, 
          status TEXT DEFAULT 'private', 
          public_id TEXT UNIQUE NOT NULL, 
          created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
          updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
