      } else {
        $where = "WHERE user_id = ?";
        $params = [$user_id];
      }
      
      if ($search !== '') {
        $where .= " AND (title LIKE ? OR content LIKE ?)";
        $params[] = "%$search%";
        $params[] = "%$search%";
      }
      if ($filter === 'starred') {
        $where .= " AND starred = 1";
      } elseif ($filter === 'tasks') {
        $where .= " AND note_type = 'task'";
      } elseif ($filter !== 'all' && strpos($filter, 'proj_') !== 0) {
        $where .= " AND category = ?";
        $params[] = $filter;
      }
      
      $stmt = $db->prepare("SELECT id, user_id, title, content, category, starred, note_type, created_at, updated_at FROM personal_notes $where $order_by $limit_clause");
      $stmt->execute($params);
      send_json($stmt->fetchAll());
      break;
    
    case 'get_tasks':
      if (!$user_id) { send_json([]); }
      $sort_key = $_GET['sort'] ?? 'newest';
      $search = $_GET['q'] ?? '';
      $filter = $_GET['filter'] ?? 'all';
      $order_by = ['newest' => 'ORDER BY updated_at DESC', 'oldest' => 'ORDER BY updated_at ASC', 'modified' => 'ORDER BY updated_at DESC'][$sort_key] ?? 'ORDER BY updated_at DESC';
      
      $where = "";
      $params = [];
      if (strpos($filter, 'proj_') === 0) {
        $pid = (int)str_replace('proj_', '', $filter);
        $where = "WHERE project_id = ? AND (project_id IN (SELECT project_id FROM project_members WHERE user_id = ?) OR project_id IN (SELECT id FROM projects WHERE is_public = 1))";
        $params = [$pid, $user_id];
      } else {
        $where = "WHERE user_id = ?";
        $params = [$user_id];
      }
      
      if ($search !== '') {
        $where .= " AND (title LIKE ? OR items LIKE ?)";
        $params[] = "%$search%";
        $params[] = "%$search%";
      }
      if ($filter === 'starred') {
        $where .= " AND starred = 1";
      } elseif ($filter !== 'all' && strpos($filter, 'proj_') !== 0) {
        $where .= " AND category = ?";
