      $stmt->execute([$user_id]);
      $rows = $stmt->fetchAll();
      if (empty($rows)) { http_response_code(404); exit; }

      $export_data = [
        'name' => 'My Blogs',
        'blogs' => $rows
      ];
      
      header('Content-Type: application/json');
      header('Content-Disposition: attachment; filename="my_blogs.json"');
      echo json_encode($export_data, JSON_PRETTY_PRINT);
      exit;

    case 'import_blogs':
      if (!$user_id) { http_response_code(403); exit; }
      $import_data = json_decode(file_get_contents('php://input'), true);
      if (json_last_error() !== JSON_ERROR_NONE || !isset($import_data['blogs']) || !is_array($import_data['blogs'])) {
        http_response_code(400); send_json(['status' => 'error', 'message' => 'Invalid or malformed JSON payload.']);
      }

      $db->beginTransaction();
      try {
        $stmt_insert = $db->prepare("INSERT INTO blogs (user_id, title, content, status, category, public_id, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)");
        $count = 0;
        foreach ($import_data['blogs'] as $blog) {
          $title = isset($blog['title']) ? htmlspecialchars($blog['title']) : 'Imported Blog';
          $content = isset($blog['content']) ? format_user_text($blog['content']) : ''; 
          $status = isset($blog['status']) ? $blog['status'] : 'private';
          $category = isset($blog['category']) ? $blog['category'] : 'all';
          $created_at = isset($blog['created_at']) ? $blog['created_at'] : date('Y-m-d H:i:s');
          $updated_at = isset($blog['updated_at']) ? $blog['updated_at'] : date('Y-m-d H:i:s');
          $public_id = bin2hex(random_bytes(8));
          
          if ($content !== '' || $title !== 'Imported Blog') {
            $stmt_insert->execute([$user_id, $title, $content, $status, $category, $public_id, $created_at, $updated_at]);
            $count++;
          }
        }
        $db->commit();
        send_json(['status' => 'success', 'message' => "Successfully imported {$count} blogs."]);
      } catch (Exception $e) {
        $db->rollBack();
        http_response_code(500); send_json(['status' => 'error', 'message' => 'Database error during import.']);
      }
      break;

    case 'get_blog':
      $public_id = $_GET['public_id'] ?? '';
      $stmt = $db->prepare("SELECT b.*, u.artist as author FROM blogs b JOIN users u ON b.user_id = u.id WHERE b.public_id = ?");
      $stmt->execute([$public_id]);
      $blog = $stmt->fetch();
      if ($blog) {
        if ($blog['status'] === 'private' && $blog['user_id'] != $user_id && $is_super_admin == 0) {
          http_response_code(403); send_json(['status' => 'error', 'message' => 'This blog is private.']);
        }
        send_json($blog);
      } else {
        http_response_code(404); send_json(['status' => 'error', 'message' => 'Blog not found.']);
      }
      break;

    case 'save_blog':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $blog_id = $data['id'] ?? null;
      $title = htmlspecialchars($data['title'] ?? 'Untitled Blog', ENT_QUOTES, 'UTF-8');
      $content = htmlspecialchars($data['content'] ?? '', ENT_QUOTES, 'UTF-8');
      $status = $data['status'] ?? 'private';
      $category = $data['category'] ?? 'all';
      
      $title = str_replace(['&#039;', '&#39;', '&quot;'], ["'", "'", '"'], $title);
      $content = str_replace(['&#039;', '&#39;', '&quot;'], ["'", "'", '"'], $content);
      
      if ($blog_id) {
        $db->prepare("UPDATE blogs SET title = ?, content = ?, status = ?, category = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ? AND user_id = ?")->execute([$title, $content, $status, $category, $blog_id, $user_id]);
        $stmt = $db->prepare("SELECT public_id FROM blogs WHERE id = ?");
        $stmt->execute([$blog_id]);
        $public_id = $stmt->fetchColumn();
      } else {
        $public_id = bin2hex(random_bytes(8));
        $db->prepare("INSERT INTO blogs (user_id, title, content, status, category, public_id) VALUES (?, ?, ?, ?, ?, ?)")->execute([$user_id, $title, $content, $status, $category, $public_id]);
        $blog_id = $db->lastInsertId();
      }
      send_json(['status' => 'success', 'id' => $blog_id, 'public_id' => $public_id]);
      break;

    case 'delete_blog':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $db->prepare("DELETE FROM blogs WHERE id = ? AND (user_id = ? OR {$is_super_admin} = 1)")->execute([intval($data['id']), $user_id]);
      send_json(['status' => 'success']);
      break;

    case 'get_community':
      $sort_key = $_GET['sort'] ?? 'newest';
      $search = $_GET['q'] ?? '';
      $order_by = 'ORDER BY p.created_at DESC';
      $join_cond = "";
      $where_cond = "WHERE p.parent_id IS NULL";
      $params = [$user_id ?? 0];
      
      if ($search !== '') {
        $where_cond .= " AND p.content LIKE ?";
        $params[] = "%$search%";
      }

      if ($sort_key === 'most_liked') {
        $order_by = 'ORDER BY like_count DESC, p.created_at DESC';
      } elseif ($sort_key === 'most_replied') {
        $order_by = 'ORDER BY reply_count DESC, p.created_at DESC';
      } elseif ($sort_key === 'following' && $user_id) {
        $join_cond = "JOIN follows f ON f.following_id = p.user_id AND f.follower_id = " . intval($user_id);
      }
      
      $root_stmt = $db->prepare("
        SELECT p.*, 
        CASE WHEN u.banned = 1 THEN 'Banned User' WHEN u.email LIKE 'deleted_%' THEN 'Deleted User' ELSE u.artist END as artist,
        CASE WHEN u.banned = 1 OR u.email LIKE 'deleted_%' THEN 1 ELSE 0 END as is_disabled,
        (SELECT COUNT(*) FROM community_reactions WHERE post_id = p.id AND reaction = 'like') as like_count,
        (SELECT COUNT(*) FROM community_reactions WHERE post_id = p.id AND reaction = 'dislike') as dislike_count,
        (SELECT COUNT(*) FROM community_posts WHERE parent_id = p.id) as reply_count,
        (SELECT reaction FROM community_reactions WHERE post_id = p.id AND user_id = ?) as my_reaction 
        FROM community_posts p JOIN users u ON p.user_id = u.id $join_cond $where_cond $order_by $limit_clause
      ");
      $root_stmt->execute($params);
      $roots = $root_stmt->fetchAll();
      
      $root_ids = array_column($roots, 'id');
      $replies_filtered = [];
      if (!empty($root_ids)) {
        $placeholders = implode(',', array_fill(0, count($root_ids), '?'));
        $reply_stmt = $db->prepare("
          SELECT p.*, 
          CASE WHEN u.banned = 1 THEN 'Banned User' WHEN u.email LIKE 'deleted_%' THEN 'Deleted User' ELSE u.artist END as artist,
          CASE WHEN u.banned = 1 OR u.email LIKE 'deleted_%' THEN 1 ELSE 0 END as is_disabled,
          (SELECT COUNT(*) FROM community_reactions WHERE post_id = p.id AND reaction = 'like') as like_count,
          (SELECT COUNT(*) FROM community_reactions WHERE post_id = p.id AND reaction = 'dislike') as dislike_count,
          (SELECT COUNT(*) FROM community_posts WHERE parent_id = p.id) as reply_count,
          (SELECT reaction FROM community_reactions WHERE post_id = p.id AND user_id = ?) as my_reaction 
          FROM community_posts p JOIN users u ON p.user_id = u.id
          WHERE p.parent_id IN ($placeholders)
          ORDER BY p.created_at ASC
        ");
        $reply_params = array_merge([$user_id ?? 0], $root_ids);
        $reply_stmt->execute($reply_params);
        $all_replies = $reply_stmt->fetchAll();
          
        $rcounts = [];
        foreach ($all_replies as $r) {
          $pid = $r['parent_id'];
          if (!isset($rcounts[$pid])) $rcounts[$pid] = 0;
          if ($rcounts[$pid] < 25) { // Strict limit of 25 replies per post
            $replies_filtered[] = $r;
            $rcounts[$pid]++;
          }
        }
      }
      
      send_json(array_merge($roots, $replies_filtered));
      break;

    case 'create_community_post':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $content = format_user_text($data['content']);
      $parent_id = empty($data['parent_id']) ? null : intval($data['parent_id']);
      $db->prepare("INSERT INTO community_posts (user_id, parent_id, content) VALUES (?, ?, ?)")->execute([$user_id, $parent_id, $content]);
      send_json(['status' => 'success']);
      break;

    case 'toggle_post_reaction':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $post_id = intval($data['post_id']);
      $reaction = $data['reaction'];
      $stmt = $db->prepare("SELECT reaction FROM community_reactions WHERE user_id = ? AND post_id = ?");
      $stmt->execute([$user_id, $post_id]);
      if ($stmt->fetchColumn() === $reaction) {
        $db->prepare("DELETE FROM community_reactions WHERE user_id = ? AND post_id = ?")->execute([$user_id, $post_id]);
      } else {
        $db->prepare("REPLACE INTO community_reactions (user_id, post_id, reaction) VALUES (?, ?, ?)")->execute([$user_id, $post_id, $reaction]);
      }
      send_json(['status' => 'success']);
      break;

    case 'toggle_block':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $blocked_id = intval($data['blocked_id']);
      if ($blocked_id === $user_id) { send_json(['status' => 'error', 'message' => 'Cannot block yourself.']); }
      
      $stmt = $db->prepare("SELECT 1 FROM blocks WHERE blocker_id = ? AND blocked_id = ?");
      $stmt->execute([$user_id, $blocked_id]);
      if ($stmt->fetch()) {
        $db->prepare("DELETE FROM blocks WHERE blocker_id = ? AND blocked_id = ?")->execute([$user_id, $blocked_id]);
        send_json(['status' => 'unblocked']);
      } else {
        $db->prepare("INSERT INTO blocks (blocker_id, blocked_id) VALUES (?, ?)")->execute([$user_id, $blocked_id]);
        // Remove mutual follows
        $db->prepare("DELETE FROM follows WHERE (follower_id = ? AND following_id = ?) OR (follower_id = ? AND following_id = ?)")->execute([$user_id, $blocked_id, $blocked_id, $user_id]);
        send_json(['status' => 'blocked']);
      }
      break;

    case 'get_inbox':
      if (!$user_id) { send_json([]); }
      
      try { $db->query("SELECT media_type FROM messages LIMIT 1"); } catch (Exception $e) { try { $db->exec("ALTER TABLE messages ADD COLUMN media_type TEXT DEFAULT 'image/webp'"); } catch(Exception $ex) {} }
      
      // FIX 500 ERROR: Ensure new tables exist immediately without needing an app version reset
      $db->exec("
        CREATE TABLE IF NOT EXISTS starred_messages (
          user_id INTEGER NOT NULL, message_id INTEGER NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          PRIMARY KEY (user_id, message_id), FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE, FOREIGN KEY (message_id) REFERENCES messages(id) ON DELETE CASCADE
        );
        CREATE TABLE IF NOT EXISTS user_statuses (
          id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL, content TEXT, image BLOB, media_type TEXT DEFAULT 'image/webp', created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
        );
      ");
      
      $inbox = [];
      
      // 1. Direct Messages (Optimized O(1) Aggregation)
      $stmt_dms = $db->prepare("
        SELECT 
          m.id, m.content, m.image, m.created_at, m.is_read, m.sender_id, m.receiver_id, m.media_type,
          u.artist as name, u.id as target_id, u.last_active,
          (SELECT COUNT(*) FROM messages unread WHERE unread.group_id IS NULL AND unread.sender_id = u.id AND unread.receiver_id = ? AND unread.is_read = 0) as unread_count
        FROM messages m
        JOIN users u ON u.id = CASE WHEN m.sender_id = ? THEN m.receiver_id ELSE m.sender_id END
        WHERE m.id IN (
          SELECT MAX(id) 
          FROM messages 
          WHERE group_id IS NULL AND (sender_id = ? OR receiver_id = ?) 
          GROUP BY CASE WHEN sender_id = ? THEN receiver_id ELSE sender_id END
        )
        AND NOT EXISTS (SELECT 1 FROM blocks b WHERE (b.blocker_id = ? AND b.blocked_id = u.id) OR (b.blocker_id = u.id AND b.blocked_id = ?))
      ");
      $stmt_dms->execute([$user_id, $user_id, $user_id, $user_id, $user_id, $user_id, $user_id]);
      
      while ($msg = $stmt_dms->fetch()) {
        $inbox[] = [
          'id' => $msg['id'],
          'content' => $msg['content'],
          'has_image' => !empty($msg['image']) ? 1 : 0,
          'media_type' => $msg['media_type'] ?? 'image/webp',
          'created_at' => $msg['created_at'],
          'is_read' => $msg['is_read'],
          'sender_id' => $msg['sender_id'],
          'receiver_id' => $msg['receiver_id'],
          'name' => $msg['name'] ?: 'Unknown',
          'target_id' => $msg['target_id'],
          'last_active' => $msg['last_active'],
          'chat_type' => 'dm',
          'unread_count' => $msg['unread_count'],
          'sender_name' => '',
          'member_count' => 0
        ];
      }
      
      // 2. Group Chats (Optimized O(1) Join with Member Count)
      $stmt_groups = $db->prepare("
        SELECT 
          cg.id as target_id, cg.name,
          m.id, m.content, m.image, m.created_at, m.sender_id, m.media_type,
          u.artist as sender_name,
          (SELECT COUNT(*) FROM chat_group_members WHERE group_id = cg.id) as member_count
        FROM chat_groups cg
        JOIN chat_group_members cgm ON cg.id = cgm.group_id
        LEFT JOIN messages m ON m.id = (SELECT MAX(id) FROM messages WHERE group_id = cg.id)
        LEFT JOIN users u ON m.sender_id = u.id
        WHERE cgm.user_id = ?
      ");
      $stmt_groups->execute([$user_id]);
      
      while ($gmsg = $stmt_groups->fetch()) {
        $inbox[] = [
          'id' => $gmsg['id'] ?: 0,
          'content' => $gmsg['content'],
          'has_image' => !empty($gmsg['image']) ? 1 : 0,
          'media_type' => $gmsg['media_type'] ?? 'image/webp',
          'created_at' => $gmsg['created_at'],
          'is_read' => 1,
          'sender_id' => $gmsg['sender_id'] ?: 0,
          'receiver_id' => 0,
          'name' => $gmsg['name'],
          'target_id' => $gmsg['target_id'],
          'last_active' => null,
          'chat_type' => 'group',
          'unread_count' => 0,
          'sender_name' => $gmsg['sender_name'] ?: '',
          'member_count' => $gmsg['member_count']
        ];
      }
      
      usort($inbox, function($a, $b) {
        $timeA = !empty($a['created_at']) ? strtotime($a['created_at']) : 0;
        $timeB = !empty($b['created_at']) ? strtotime($b['created_at']) : 0;
        return $timeB - $timeA;
      });
      
      send_json($inbox);
      break;

    case 'get_chat':
      if (!$user_id) { send_json([]); }
      $target_id = intval($_GET['target_id'] ?? 0);
      $type = $_GET['chat_type'] ?? 'dm';
      $chat_page = isset($_GET['chat_page']) ? max(1, (int)$_GET['chat_page']) : 1;
      $chat_limit = 25 * $chat_page;
      
      try { $db->query("SELECT media_type FROM messages LIMIT 1"); } catch (Exception $e) { try { $db->exec("ALTER TABLE messages ADD COLUMN media_type TEXT DEFAULT 'image/webp'"); } catch(Exception $ex) {} }
      
      // FIX 500 ERROR: Safeguard
      $db->exec("CREATE TABLE IF NOT EXISTS starred_messages (user_id INTEGER NOT NULL, message_id INTEGER NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (user_id, message_id), FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE, FOREIGN KEY (message_id) REFERENCES messages(id) ON DELETE CASCADE);");
      
      $messages = [];
      if ($type === 'group') {
        $stmt_mem = $db->prepare("SELECT 1 FROM chat_group_members WHERE group_id = ? AND user_id = ?");
        $stmt_mem->execute([$target_id, $user_id]);
        if (!$stmt_mem->fetch() && !$is_super_admin) { http_response_code(403); send_json(['status' => 'error', 'message' => 'Not a member.']); }

        $stmt = $db->prepare("
          SELECT m.id, m.sender_id, u.artist as sender_name, m.content, m.image, m.created_at, m.is_edited, m.reply_to_id, m.media_type,
          (SELECT 1 FROM starred_messages sm WHERE sm.message_id = m.id AND sm.user_id = ?) as is_starred
          FROM messages m 
          LEFT JOIN users u ON m.sender_id = u.id 
          WHERE m.group_id = ? 
          ORDER BY m.created_at DESC LIMIT $chat_limit
        ");
        $stmt->execute([$user_id, $target_id]);
        $messages = $stmt->fetchAll();
      } else {
        $stmt_block = $db->prepare("SELECT 1 FROM blocks WHERE (blocker_id = ? AND blocked_id = ?) OR (blocker_id = ? AND blocked_id = ?)");
        $stmt_block->execute([$user_id, $target_id, $target_id, $user_id]);
        if ($stmt_block->fetch()) { send_json([]); }

        $db->prepare("UPDATE messages SET is_read = 1 WHERE sender_id = ? AND receiver_id = ?")->execute([$target_id, $user_id]);
        $stmt = $db->prepare("
          SELECT m.id, m.sender_id, u.artist as sender_name, m.content, m.image, m.created_at, m.is_edited, m.reply_to_id, m.media_type,
          (SELECT 1 FROM starred_messages sm WHERE sm.message_id = m.id AND sm.user_id = ?) as is_starred
          FROM messages m 
          LEFT JOIN users u ON m.sender_id = u.id 
          WHERE m.group_id IS NULL AND ((m.sender_id = ? AND m.receiver_id = ?) OR (m.sender_id = ? AND m.receiver_id = ?)) 
          ORDER BY m.created_at DESC LIMIT $chat_limit
        ");
        $stmt->execute([$user_id, $user_id, $target_id, $target_id, $user_id]);
        $messages = $stmt->fetchAll();
      }
      
      if (!empty($messages)) {
        $messages = array_reverse($messages);
      }
      
      if (!empty($messages)) {
        $stmt_reply = $db->prepare("SELECT m.content, u.artist as sender_name FROM messages m LEFT JOIN users u ON m.sender_id = u.id WHERE m.id = ?");
        $stmt_react = $db->prepare("SELECT reaction, user_id FROM message_reactions WHERE message_id = ?");

        foreach ($messages as &$msg) {
          $msg['has_image'] = !empty($msg['image']) ? 1 : 0;
          $msg['media_type'] = $msg['media_type'] ?? 'image/webp';
          unset($msg['image']);

          if (!empty($msg['reply_to_id'])) {
            $stmt_reply->execute([$msg['reply_to_id']]);
            $rep = $stmt_reply->fetch();
            $msg['reply_content'] = $rep ? $rep['content'] : null;
            $msg['reply_sender'] = $rep ? $rep['sender_name'] : null;
          } else {
            $msg['reply_content'] = null;
            $msg['reply_sender'] = null;
          }

          $stmt_react->execute([$msg['id']]);
          $msg['reactions'] = $stmt_react->fetchAll();
        }
        unset($msg);
      }
      
      send_json($messages);
      break;

    case 'send_message':
      if (!$user_id) { http_response_code(403); exit; }
      $target_id = intval($_POST['target_id'] ?? 0);
      $chat_type = $_POST['chat_type'] ?? 'dm';
      $reply_to_id = !empty($_POST['reply_to_id']) ? intval($_POST['reply_to_id']) : null;
      $content = trim(htmlspecialchars($_POST['content'] ?? '', ENT_QUOTES, 'UTF-8'));
      
      if (mb_strlen($content, 'UTF-8') > 50000) {
        send_json(['status' => 'error', 'message' => 'Message exceeds 50,000 characters limit.']);
      }
      
      if ($chat_type === 'dm') {
        $stmt_block = $db->prepare("SELECT 1 FROM blocks WHERE (blocker_id = ? AND blocked_id = ?) OR (blocker_id = ? AND blocked_id = ?)");
        $stmt_block->execute([$user_id, $target_id, $target_id, $user_id]);
        if ($stmt_block->fetch()) { send_json(['status' => 'error', 'message' => 'Cannot send message. A block is active.']); }
      } else {
        $stmt_mem = $db->prepare("SELECT 1 FROM chat_group_members WHERE group_id = ? AND user_id = ?");
        $stmt_mem->execute([$target_id, $user_id]);
        if (!$stmt_mem->fetch() && !$is_super_admin) { send_json(['status' => 'error', 'message' => 'You are not a member of this group.']); }
      }
      
      $mediaData = null;
      $mediaType = 'image/webp';
      
      if (isset($_FILES['image']) && $_FILES['image']['error'] === UPLOAD_ERR_OK) {
        if ($_FILES['image']['size'] > 10 * 1024 * 1024) {
          send_json(['status' => 'error', 'message' => 'File exceeds 10MB limit.']);
        }
        
        $mime = strtolower($_FILES['image']['type'] ?? '');
        if (empty($mime) && function_exists('mime_content_type')) {
          $mime = strtolower(mime_content_type($_FILES['image']['tmp_name']));
        }
        
        if (strpos($mime, 'image/') === 0 || strpos($mime, 'video/') === 0 || strpos($mime, 'audio/') === 0) {
          $mediaType = $mime;
          $ext = 'bin';
          if (strpos($mime, 'image/') === 0) $ext = 'jpg';
          if (strpos($mime, 'video/mp4') !== false) $ext = 'mp4';
          if (strpos($mime, 'video/webm') !== false) $ext = 'webm';
          if (strpos($mime, 'audio/') === 0) $ext = 'mp3';

          $shard = substr(md5(uniqid()), 0, 2);
          $media_dir = MUSIC_DIR . '/uploads/media/' . $shard;
          $thumb_dir = MUSIC_DIR . '/thumbnails/' . $shard;
          if (!is_dir($media_dir)) @mkdir($media_dir, 0755, true);
          if (!is_dir($thumb_dir)) @mkdir($thumb_dir, 0755, true);

          $filename = uniqid('msg_') . '.' . $ext;
          $dest_path = $media_dir . '/' . $filename;
          $rel_path = 'uploads/media/' . $shard . '/' . $filename;

          if (move_uploaded_file($_FILES['image']['tmp_name'], $dest_path)) {
            $mediaData = $rel_path;
            
            // Generate Thumbnail for Images to optimize (Setting $crop to false maintains aspect ratio)
            if (strpos($mime, 'image/') === 0) {
              $thumb_data = process_image_to_webp(file_get_contents($dest_path), 400, 70, false);
              if ($thumb_data) {
                file_put_contents($thumb_dir . '/' . $filename . '.webp', $thumb_data);
              }
            }
          } else {
            send_json(['status' => 'error', 'message' => 'Failed to save media file.']);
          }
        } else {
          send_json(['status' => 'error', 'message' => 'Invalid file format. Only Images, Audio, and Video are allowed.']);
        }
      }
      
      if ($content !== '' || $mediaData !== null) {
        if ($chat_type === 'group') {
          $db->prepare("INSERT INTO messages (sender_id, receiver_id, group_id, reply_to_id, content, image, media_type) VALUES (?, ?, ?, ?, ?, ?, ?)")->execute([$user_id, $user_id, $target_id, $reply_to_id, format_user_text($content), $mediaData, $mediaType]);
        } else {
          $db->prepare("INSERT INTO messages (sender_id, receiver_id, reply_to_id, content, image, media_type) VALUES (?, ?, ?, ?, ?, ?)")->execute([$user_id, $target_id, $reply_to_id, format_user_text($content), $mediaData, $mediaType]);
        }
        send_json(['status' => 'success']);
      } else {
        send_json(['status' => 'error', 'message' => 'Empty message.']);
      }
      break;

    case 'edit_message':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $db->prepare("UPDATE messages SET content = ?, is_edited = 1 WHERE id = ? AND sender_id = ?")->execute([format_user_text($data['content']), intval($data['id']), $user_id]);
      send_json(['status' => 'success']);
      break;

    case 'delete_message':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
