    <div class="modal fade" id="playlist-downloader-modal" tabindex="-1">
      <div class="modal-dialog modal-fullscreen">
        <div class="modal-content" style="background-color: var(--ytm-bg);">
          <div class="modal-header border-0" style="background-color: var(--ytm-surface-2);">
            <h5 class="modal-title"><i class="bi bi-cloud-arrow-down-fill"></i> Playlist Downloader</h5>
            <button type="button" class="btn-close-white" data-bs-dismiss="modal"></button>
          </div>
          <div class="modal-body p-2 p-md-4">
            <div class="container-fluid mx-auto" style="max-width: 1000px;">
              <div class="card mb-4" style="background-color: var(--ytm-surface); border: none;">
                <div class="card-header" style="background-color: var(--ytm-surface-2); font-weight: bold; border: none; color: #ffffff !important;">Load Playlist / Song</div>
                <div class="card-body">
                  <form id="pd-load-form" class="mb-4">
                    <div class="mb-3">
                      <label for="pd-playlist-id" class="form-label" style="color: #ffffff !important;">Playlist ID</label>
                      <input type="text" class="form-control" id="pd-playlist-id" placeholder="Enter Playlist Public ID">
                    </div>
                    <button type="submit" class="btn btn-danger">Load Playlist</button>
                  </form>
                  <hr class="text-secondary">
                  <div class="mb-3">
                    <label for="pd-song-id" class="form-label" style="color: #ffffff !important;">Download a single song by ID</label>
                    <div class="input-group">
                      <input type="number" class="form-control" id="pd-song-id" placeholder="Song ID">
                      <button class="btn btn-outline-light" type="button" id="pd-download-single" style="color: #ffffff !important;">Download</button>
                    </div>
                  </div>
                </div>
              </div>

              <div id="pd-results-card" class="card d-none" style="background-color: var(--ytm-surface); border: none;">
                <div class="card-header" style="background-color: var(--ytm-surface-2); font-weight: bold; border: none; color: #ffffff !important;" id="pd-playlist-title">
                  Playlist Details
                </div>
                <div class="card-body">
                  <button class="btn btn-danger w-100 mb-3" id="pd-start-auto" style="color: #ffffff !important;">
                    <i class="bi bi-play-fill" style="color: #ffffff !important;"></i> Download All Songs (Sequential)
                  </button>
                  <div class="mb-3">
                    <div class="d-flex justify-content-between align-items-center mb-2" style="color: #ffffff !important;">
                      <span><i class="bi bi-terminal" style="color: #ffffff !important;"></i> Download Log</span>
                      <button class="btn btn-sm btn-outline-secondary" id="pd-clear-log" style="color: #ffffff !important; border-color: #ffffff;">Clear</button>
                    </div>
                    <div class="log-area" id="pd-log" style="background-color: var(--ytm-surface-2); border-radius: 8px; padding: 1rem; font-family: monospace; font-size: 0.85rem; height: 300px; overflow-y: auto; color: #ffffff !important;"></div>
                  </div>
                  <div>
                    <strong style="color: #ffffff !important;">Song List</strong>
                    <div class="song-list mt-2" style="background-color: var(--ytm-surface); border-radius: 12px; overflow: hidden;">
                      <div class="song-item small d-none d-md-grid pd-song-row" style="color: #ffffff !important;">
                        <div style="color: #ffffff !important;" class="d-flex align-items-center"><input class="form-check-input me-2" type="checkbox" id="pd-select-all" checked> #</div>
                        <div style="color: #ffffff !important;">Title</div><div style="color: #ffffff !important;">Artist</div><div style="color: #ffffff !important;">Duration</div><div></div>
                      </div>
                      <div id="pd-song-rows"></div>
                    </div>
                    <div id="pd-infinite-scroll-loader" class="text-center p-3 d-none" style="color: var(--ytm-secondary-text);">Loading more...</div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
    
    <div class="modal fade" id="song-audio-settings-modal" tabindex="-1">
      <div class="modal-dialog modal-dialog-centered">
        <div class="modal-content" style="background: rgba(30, 30, 30, 0.95); backdrop-filter: blur(10px); border: 1px solid #444;">
          <div class="modal-header border-0 pb-0">
            <h5 class="modal-title w-100 text-center text-white">Audio Settings for <br><small id="sas-song-title" class="text-secondary"></small></h5>
            <button type="button" class="btn-close btn-close-white position-absolute end-0 me-3" data-bs-dismiss="modal"></button>
          </div>
          <div class="modal-body text-white">
            <input type="hidden" id="sas-song-id">
            
            <div class="mb-4">
              <label class="form-label d-flex justify-content-between">
                <span>Song Volume Multiplier</span>
                <span id="sas-vol-val">1.0x</span>
              </label>
              <input type="range" class="form-range" id="sas-vol-slider" min="0" max="3" step="0.1" value="1">
              <small class="text-secondary d-block mt-1">Adjust if this specific song is too quiet or loud compared to others.</small>
            </div>
            
            <div class="mb-3">
              <label class="form-label d-flex justify-content-between align-items-center">
                <span>Per-Song Equalizer</span>
                <select class="form-select form-select-sm w-auto" id="sas-eq-preset-select">
                   <option value="Custom">Custom</option>
                   <option value="Flat">Flat</option>
                   <option value="Rock">Rock</option>
                   <option value="Jazz">Jazz</option>
                   <option value="Classical">Classical</option>
                   <option value="Pop">Pop</option>
                   <option value="Bass Boost">Bass Boost</option>
                 </select>
              </label>
              <div class="d-flex justify-content-between text-center small text-secondary mt-3">
                 <span>60Hz</span><span>230Hz</span><span>910Hz</span><span>3.6kHz</span><span>14kHz</span>
              </div>
              <div class="d-flex justify-content-between mt-2 mb-4">
                 <input type="range" class="form-range sas-eq-band" data-band="0" min="-12" max="12" step="1" value="0" style="width:18%; transform: rotate(-90deg); margin-top: 40px; margin-bottom: 40px;">
                 <input type="range" class="form-range sas-eq-band" data-band="1" min="-12" max="12" step="1" value="0" style="width:18%; transform: rotate(-90deg); margin-top: 40px; margin-bottom: 40px;">
                 <input type="range" class="form-range sas-eq-band" data-band="2" min="-12" max="12" step="1" value="0" style="width:18%; transform: rotate(-90deg); margin-top: 40px; margin-bottom: 40px;">
                 <input type="range" class="form-range sas-eq-band" data-band="3" min="-12" max="12" step="1" value="0" style="width:18%; transform: rotate(-90deg); margin-top: 40px; margin-bottom: 40px;">
                 <input type="range" class="form-range sas-eq-band" data-band="4" min="-12" max="12" step="1" value="0" style="width:18%; transform: rotate(-90deg); margin-top: 40px; margin-bottom: 40px;">
              </div>
            </div>

            <div class="d-flex gap-2">
              <button type="button" class="btn btn-outline-secondary w-50" id="sas-reset-btn">Reset to Global</button>
              <button type="button" class="btn btn-danger w-50" id="sas-save-btn">Save to Song</button>
            </div>
          </div>
        </div>
      </div>
    </div>

    <div id="sleep-timer-bubble" class="d-none">
      <i class="bi bi-moon-stars-fill text-info"></i>
      <span class="time" id="sleep-timer-countdown">00:00</span>
      <button class="action-btn text-secondary" id="sleep-timer-wake-btn" title="Toggle Screen Awake"><i class="bi bi-display"></i></button>
      <button class="action-btn text-secondary" id="sleep-timer-cancel-btn" title="Cancel Timer"><i class="bi bi-x-circle-fill"></i></button>
    </div>

    <script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/js/bootstrap.bundle.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/sortablejs@latest/Sortable.min.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/cropperjs/1.6.1/cropper.min.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/nosleep/0.12.0/NoSleep.min.js"></script>
    <script>
      // Global Hashchange Interceptor for Playground
      window.addEventListener('hashchange', () => {
        // If the hash changes to playground and we are inside the main app (where the template exists), force a clean reload to boot it.
        if (window.location.hash.startsWith('#playground') && document.getElementById('play-client-template')) {
          window.location.reload();
        }
      });

      document.addEventListener('DOMContentLoaded', () => {
        // PLAYGROUND ROUTER INTERCEPTOR
        // If the URL contains #playground, halt main app boot and swap out the DOM for the client template.
        if (window.location.hash.startsWith('#playground')) {
          const tpl = document.getElementById('play-client-template');
          if (tpl) {
            document.open();
            document.write(tpl.innerHTML);
            document.close();
          }
          return; // Strictly abort further execution of the main app
        }

        'use strict';

        const getSvgPlaceholder = (title) => {
          let hash = 0;
          for (let i = 0; i < title.length; i++) {
            hash = title.charCodeAt(i) + ((hash << 5) - hash);
          }
          const h = Math.abs(hash % 360);
          const c1 = `hsl(${h}, 50%, 35%)`;
          const c2 = `hsl(${(h + 40) % 360}, 60%, 45%)`;
          const c3 = `hsl(${(h + 80) % 360}, 60%, 35%)`;
          const svgString = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="100%" height="100%"><defs><linearGradient id="grad" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" stop-color="${c1}"/><stop offset="50%" stop-color="${c2}"/><stop offset="100%" stop-color="${c3}"/></linearGradient><filter id="shadow" x="-10%" y="-10%" width="120%" height="120%"><feDropShadow dx="0" dy="8" stdDeviation="12" flood-opacity="0.3"/></filter></defs><rect width="512" height="512" fill="url(#grad)"/><g transform="translate(128, 128) scale(10.66)" fill="none" stroke="#ffffff" stroke-width="1.5" opacity="0.9" filter="url(#shadow)"><circle cx="12" cy="12" r="3"/><path stroke-linecap="round" d="M21.95 13c-.501 5.054-4.765 9-9.95 9c-5.523 0-10-4.477-10-10c0-1.821.487-3.529 1.338-5M11 2.05a9.9 9.9 0 0 0-4 1.288"/><path stroke-linecap="round" stroke-linejoin="round" d="M15 12V2.456a10.02 10.02 0 0 1 6.542 6.542"/></g></svg>`;
          return `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svgString)}`;
        };
        
        window.scrollToCenter = (container, element, smooth = true) => {
          if (!container || !element) return false;
          
          const containerRect = container.getBoundingClientRect();
          const elementRect = element.getBoundingClientRect();
          
          // If the element or container is not visible (e.g. display: none), heights will be 0
          if (containerRect.height === 0 || elementRect.height === 0) return false;
          
          // Accurately calculate the scroll target using absolute bounding box coordinates
          const targetScroll = container.scrollTop + (elementRect.top - containerRect.top) - (container.clientHeight / 2) + (elementRect.height / 2);
          
          container.scrollTo({
            top: targetScroll,
            behavior: smooth ? 'smooth' : 'auto'
          });
          return true;
        };

        window.enforceScrollToActive = (paneId, queueListId, smooth = false) => {
          let attempts = 0;
          const tryScroll = () => {
            attempts++;
            const pane = document.getElementById(paneId);
            const activeItem = document.querySelector(`#${queueListId} .song-item.now-playing`);
            
            if (pane && activeItem) {
              const success = window.scrollToCenter(pane, activeItem, smooth);
              // Double check after 150ms to counteract layout shifts from images loading or modal fading in
              if (success && attempts === 1) {
                setTimeout(tryScroll, 150);
              } else if (!success && attempts < 15) {
                setTimeout(tryScroll, 50);
              }
            } else if (attempts < 15) {
              setTimeout(tryScroll, 50); 
            }
          };
          // Start the first attempt slightly deferred to allow initial DOM render
          setTimeout(tryScroll, 20);
        };

        const mainContent = document.getElementById('main-content');
        const contentArea = document.getElementById('content-area');
        const contentTitle = document.getElementById('content-title');
        const searchInputDesktop = document.getElementById('search-input-desktop');
        const searchInputMobile = document.getElementById('search-input-mobile');
        const searchBtnDesktop = document.getElementById('search-btn-desktop');
        const searchBtnMobile = document.getElementById('search-btn-mobile');
        const sortControls = document.getElementById('sort-controls');
        const sortSelect = document.getElementById('sort-select');
        const historyControls = document.getElementById('history-controls');
        const clearHistoryBtn = document.getElementById('clear-history-btn');
        const allNavLinks = document.querySelectorAll('.sidebar .nav-link');
        const contextMenu = document.getElementById('context-menu');
        const playerBar = document.getElementById('player-bar');
        const infiniteScrollLoader = document.getElementById('infinite-scroll-loader');
        const installPwaBtn = document.getElementById('install-pwa-btn');
        const checkUpdateBtn = document.getElementById('check-update-btn');
        const updateModalEl = document.getElementById('update-modal');
        const updateModal = updateModalEl ? new bootstrap.Modal(updateModalEl) : null;
        const updateModalBody = document.getElementById('update-modal-body');

        const pipBtnDesktop = document.getElementById('pip-btn-desktop');
        const pipBtnMobile = document.getElementById('pip-btn-mobile');
        
        const pipCanvas = document.createElement('canvas');
        pipCanvas.width = 500;
        pipCanvas.height = 500;
        const pipCtx = pipCanvas.getContext('2d', { willReadFrequently: true });
        const pipVideo = document.createElement('video');
        pipVideo.muted = true;
        pipVideo.playsInline = true;
        
        // FIX INFINITE SPINNER: Do not assign endless MediaStreams to video elements before the window finishes loading!
        // Chromium treats captureStream() as a pending network resource if attached too early.
        window.addEventListener('load', () => {
          try {
            const supportsPiP = ('documentPictureInPicture' in window) || document.pictureInPictureEnabled || (pipVideo.webkitSupportsPresentationMode && typeof pipVideo.webkitSetPresentationMode === 'function');
            if (pipCanvas.captureStream && supportsPiP) {
              pipVideo.srcObject = pipCanvas.captureStream(1);
            } else {
              if (pipBtnDesktop) pipBtnDesktop.style.display = 'none';
              if (pipBtnMobile) pipBtnMobile.style.display = 'none';
            }
          } catch(e) {
            if (pipBtnDesktop) pipBtnDesktop.style.display = 'none';
            if (pipBtnMobile) pipBtnMobile.style.display = 'none';
          }
        });
        
        const clearCacheBtn = document.getElementById('clear-cache-btn');
        const fullscreenBtn = document.getElementById('fullscreen-btn');
        const fullScanModalEl = document.getElementById('full-scan-modal');
        const fullScanIframe = document.getElementById('full-scan-iframe');

        const genresModalEl = document.getElementById('genres-modal');
        const genresModal = genresModalEl ? new bootstrap.Modal(genresModalEl) : null;
        const genresModalBody = document.getElementById('genres-modal-body');
        const createPlaylistModalEl = document.getElementById('create-playlist-modal');
        const createPlaylistModal = createPlaylistModalEl ? new bootstrap.Modal(createPlaylistModalEl) : null;
        const editPlaylistModalEl = document.getElementById('edit-playlist-modal');
        const editPlaylistModal = editPlaylistModalEl ? new bootstrap.Modal(editPlaylistModalEl) : null;
        const importPlaylistModalEl = document.getElementById('import-playlist-modal');
        const importPlaylistModal = importPlaylistModalEl ? new bootstrap.Modal(importPlaylistModalEl) : null;
        const importFavoritesModalEl = document.getElementById('import-favorites-modal');
        const importFavoritesModal = importFavoritesModalEl ? new bootstrap.Modal(importFavoritesModalEl) : null;
        const addToPlaylistModalEl = document.getElementById('add-to-playlist-modal');
        const addToPlaylistModal = addToPlaylistModalEl ? new bootstrap.Modal(addToPlaylistModalEl) : null;
        const addToPlaylistModalBody = document.getElementById('add-to-playlist-modal-body');
        const metadataModalEl = document.getElementById('metadata-modal');
        const metadataModal = metadataModalEl ? new bootstrap.Modal(metadataModalEl) : null;
        const metadataModalBody = document.getElementById('metadata-modal-body');
        const editMetadataModalEl = document.getElementById('edit-metadata-modal');
        const editMetadataModal = editMetadataModalEl ? new bootstrap.Modal(editMetadataModalEl) : null;
        const artistsModalEl = document.getElementById('artists-modal');
        const artistsModal = artistsModalEl ? new bootstrap.Modal(artistsModalEl) : null;
        const artistsModalBody = document.getElementById('artists-modal-body');
        const shareModalEl = document.getElementById('share-modal');
        const shareModal = shareModalEl ? new bootstrap.Modal(shareModalEl) : null;
        const shareModalTitle = document.getElementById('share-modal-title');
        const shareModalText = document.getElementById('share-modal-text');
        const shareUrlInput = document.getElementById('share-url-input');
        const copyShareUrlBtn = document.getElementById('copy-share-url-btn');
        const activityModalEl = document.getElementById('activity-modal');
        
        if (activityModalEl) {
          const body = document.getElementById('activity-modal-body');
          
          let activityPage = 1;
          const loadActivityFeed = async (append = false) => {
            if (!append) {
              activityPage = 1;
              body.innerHTML = '<div class="text-center p-4"><div class="spinner-border text-secondary" role="status"></div></div>';
            } else {
              const btn = document.getElementById('load-more-activity-btn');
              if (btn) btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Loading...';
            }
            
            const feed = await fetchData(`?action=get_activity_feed&page=${activityPage}`);
            
            const loadMoreBtnContainer = document.getElementById('load-more-activity-container');
            if (loadMoreBtnContainer) loadMoreBtnContainer.remove();

            if (feed && feed.length > 0) {
              const htmlStr = feed.map(item => {
                if (item.type === 'message_notif') {
                  const unreadBadge = item.is_unread ? '<span class="badge bg-danger ms-2" style="font-size: 0.65rem;">New</span>' : '';
                  const bgClass = item.is_unread ? 'bg-dark' : 'bg-transparent';
                  const cleanContent = item.content ? parseUserText(item.content).replace(/<[^>]*>?/gm, '') : 'Sent an image';

                  return `
                    <li class="list-group-item ${bgClass} text-white border-secondary py-3 open-chat-btn" data-userid="${item.sender_id}" data-artist="${escapeHTML(item.commenter_name)}" style="cursor: pointer;">
                      <div class="d-flex align-items-start gap-3">
                        <div class="mt-1"><i class="bi bi-chat-dots-fill text-info fs-5"></i></div>
                        <div class="flex-grow-1" style="min-width: 0;">
                          <div style="font-size: 0.95rem;"><span class="fw-bold">${escapeHTML(item.commenter_name)}</span> sent you a message${unreadBadge}</div>
                          <div class="text-secondary fst-italic my-1 text-truncate" style="font-size: 0.9rem; border-left: 2px solid #555; padding-left: 8px;">"${cleanContent}"</div>
                          <div class="d-flex justify-content-between align-items-center mt-2">
                            <small class="text-secondary" style="font-size: 0.75rem;">${timeAgo(item.created_at)}</small>
                            <button class="btn btn-sm btn-outline-light"><i class="bi bi-reply-fill"></i> Reply</button>
                          </div>
                        </div>
                      </div>
                    </li>
                  `;
                } else if (item.type === 'comment_notif' || item.type === 'community_notif') {
                  const isCommunity = item.type === 'community_notif';
                  const isReply = item.notif_type === 'reply' || item.notif_type === 'community_reply';
                  const unreadBadge = item.is_unread ? '<span class="badge bg-danger ms-2" style="font-size: 0.65rem;">New</span>' : '';
                  const bgClass = item.is_unread ? 'bg-dark' : 'bg-transparent';

                  let actionText = '';
                  let iconHTML = '';
                  let replyBtnHTML = '';

                  if (isCommunity) {
                    actionText = `<span class="fw-bold">${escapeHTML(item.commenter_name)}</span> replied to your community post${unreadBadge}`;
                    iconHTML = `<i class="bi bi-people-fill text-info fs-5"></i>`;
                    replyBtnHTML = `<button class="btn btn-sm btn-outline-light notif-comm-reply-btn" data-post-id="${item.post_id}" data-username="${escapeHTML(item.commenter_name)}"><i class="bi bi-reply-fill"></i> Reply</button>`;
                  } else {
                    actionText = isReply 
                      ? `<span class="fw-bold">${escapeHTML(item.commenter_name)}</span> replied to your comment on <span class="text-info">${escapeHTML(item.song_title)}</span>${unreadBadge}`
                      : `<span class="fw-bold">${escapeHTML(item.commenter_name)}</span> commented on your song <span class="text-info">${escapeHTML(item.song_title)}</span>${unreadBadge}`;
                    iconHTML = `<i class="bi bi-chat-dots-fill text-primary fs-5"></i>`;
                    replyBtnHTML = `<button class="btn btn-sm btn-outline-light notif-reply-btn" data-song-id="${item.song_id}" data-comment-id="${item.comment_id}" data-username="${escapeHTML(item.commenter_name)}"><i class="bi bi-reply-fill"></i> Reply</button>`;
                  }
                     
                  const cleanContent = parseUserText(item.content).replace(/<[^>]*>?/gm, ''); 

                  return `
                    <li class="list-group-item ${bgClass} text-white border-secondary py-3">
                      <div class="d-flex align-items-start gap-3">
                        <div class="mt-1">${iconHTML}</div>
                        <div class="flex-grow-1" style="min-width: 0;">
                          <div style="font-size: 0.95rem;">${actionText}</div>
                          <div class="text-secondary fst-italic my-1 text-truncate" style="font-size: 0.9rem; border-left: 2px solid #555; padding-left: 8px;">"${cleanContent}"</div>
                          <div class="d-flex justify-content-between align-items-center mt-2">
                            <small class="text-secondary" style="font-size: 0.75rem;">${timeAgo(item.created_at)}</small>
                            ${replyBtnHTML}
                          </div>
                        </div>
                      </div>
                    </li>
                  `;
                } else {
                  const unreadBadge = item.is_unread ? '<span class="badge bg-danger ms-2" style="font-size: 0.65rem;">New</span>' : '';
                  const bgClass = item.is_unread ? 'bg-dark' : 'bg-transparent';
                  return `
                    <li class="list-group-item ${bgClass} text-white border-secondary py-3">
                      <div class="d-flex align-items-center gap-3">
                        <div class="mt-1"><i class="bi bi-clock-history text-secondary fs-5"></i></div>
                        <div>
                          <div style="font-size: 0.95rem;">You ${escapeHTML(item.action)} ${item.target_name ? `<span class="text-info">${escapeHTML(item.target_name)}</span>` : ''}${unreadBadge}</div>
                          <small class="text-secondary" style="font-size: 0.75rem;">${timeAgo(item.created_at)}</small>
                        </div>
                      </div>
                    </li>
                  `;
                }
              }).join('');

              if (!append) {
                body.innerHTML = '<ul class="list-group list-group-flush" id="activity-list">' + htmlStr + '</ul>';
              } else {
                document.getElementById('activity-list').insertAdjacentHTML('beforeend', htmlStr);
              }

              if (feed.length === 25) {
                body.insertAdjacentHTML('beforeend', `
                  <div class="text-center p-3" id="load-more-activity-container">
                    <button class="btn btn-outline-light rounded-pill px-4 btn-sm fw-bold" id="load-more-activity-btn">Load More Activity</button>
                  </div>
                `);
                document.getElementById('load-more-activity-btn').addEventListener('click', () => {
                  activityPage++;
                  loadActivityFeed(true);
                });
              }
               
              if (!append) {
                setTimeout(async () => {
                  document.querySelectorAll('.notif-badge').forEach(b => b.classList.add('d-none'));
                  await fetchData('?action=mark_notifs_read', { method: 'POST' });
                  updateNotifBadge();
                }, 1500);
              }
            } else {
              if (!append) body.innerHTML = '<p class="text-secondary text-center p-4">No recent activity.</p>';
            }
          };

          activityModalEl.addEventListener('show.bs.modal', () => loadActivityFeed(false));

          const connectionsModalEl = document.getElementById('connections-modal');
          if (connectionsModalEl) {
            connectionsModalEl.addEventListener('click', async (e) => {
              const loadMoreBtn = e.target.closest('#load-more-conn-btn');
              if (loadMoreBtn) {
                e.preventDefault();
                window.connPage++;
                window.loadConnections(true);
                return;
              }
              
              const followBtn = e.target.closest('.follow-btn-modal');
              if (followBtn) {
                e.preventDefault();
                e.stopPropagation();
                if (!currentUser) return showToast('Please log in', 'error');
                const userId = followBtn.dataset.userId;
                const res = await fetchData('?action=toggle_follow', {
                  method: 'POST',
                  headers: {'Content-Type': 'application/json'},
                  body: JSON.stringify({ following_id: userId })
                });
                
                if (res && (res.status === 'followed' || res.status === 'unfollowed')) {
                  const isFollowing = res.status === 'followed';
                  followBtn.textContent = isFollowing ? 'Unfollow' : 'Follow';
                  followBtn.className = `btn btn-sm rounded-pill fw-bold follow-btn-modal px-3 flex-shrink-0 ${isFollowing ? 'btn-outline-light' : 'btn-danger'}`;
                  
                  if (currentView.type === 'artist_songs' || currentView.type === 'user_profile' || currentView.type === 'get_following') {
                    loadView(currentView); // Sync background view numbers
                  }
                } else {
                  showToast(res?.message || 'Error toggling follow', 'error');
                }
                return;
              }
            });
          }

          // --- FULL PAGE CHAT APP LOGIC ---
          window.getPreviewText = (htmlStr) => {
            if (!htmlStr) return '';
            const tmp = document.createElement('div');
            tmp.innerHTML = htmlStr;
            return tmp.textContent || tmp.innerText || '';
          };

          if (!window.chatAudioObj) {
            window.chatAudioObj = new Audio();
            window.chatAudioActiveMsgId = null;

            window.chatAudioObj.addEventListener('timeupdate', () => {
              if (window.chatAudioActiveMsgId && isFinite(window.chatAudioObj.duration)) {
                const playerEl = document.querySelector(`.chat-audio-player[data-msg-id="${window.chatAudioActiveMsgId}"]`);
                if (playerEl) {
                  const pct = (window.chatAudioObj.currentTime / window.chatAudioObj.duration) * 100;
                  const track = playerEl.querySelector('.chat-audio-progress');
                  const timeDisplay = playerEl.querySelector('.chat-audio-time');
                  const icon = playerEl.querySelector('.chat-audio-play-btn i');
                     
                  if (track) track.style.width = pct + '%';
                  if (timeDisplay) {
                    const cur = window.chatAudioObj.currentTime;
                    const m = Math.floor(cur / 60);
                    const s = Math.floor(cur % 60).toString().padStart(2, '0');
                    timeDisplay.innerText = `${m}:${s}`;
                  }
                  if (icon && !window.chatAudioObj.paused) {
                    icon.className = 'bi bi-pause-fill fs-4';
                  }
                }
              }
            });
            window.chatAudioObj.addEventListener('ended', () => {
              const playerEl = document.querySelector(`.chat-audio-player[data-msg-id="${window.chatAudioActiveMsgId}"]`);
              if (playerEl) {
                const icon = playerEl.querySelector('.chat-audio-play-btn i');
                const track = playerEl.querySelector('.chat-audio-progress');
                const timeDisplay = playerEl.querySelector('.chat-audio-time');
                if (icon) icon.className = 'bi bi-play-fill fs-4';
                if (track) track.style.width = '0%';
                if (timeDisplay) timeDisplay.innerText = '0:00';
              }
              window.chatAudioActiveMsgId = null;
            });
          }

          window.playChatAudio = (msgId, url) => {
            const isPlayingThis = window.chatAudioActiveMsgId == msgId && !window.chatAudioObj.paused;
             
            document.querySelectorAll('.chat-audio-play-btn i').forEach(i => i.className = 'bi bi-play-fill fs-4');
             
            if (isPlayingThis) {
              window.chatAudioObj.pause();
            } else {
              if (window.chatAudioActiveMsgId != msgId) {
                window.chatAudioObj.src = url;
                window.chatAudioActiveMsgId = msgId;
              }
                
              const mainAudio = document.getElementById('audio-player');
              if (mainAudio && !mainAudio.paused) {
                document.getElementById('btn-play-pause').click();
              }

              window.chatAudioObj.play().catch(e => console.error(e));
            }
          };
          
          window.seekChatAudio = (e, msgId) => {
            if (window.chatAudioActiveMsgId != msgId) return;
            const playerEl = document.querySelector(`.chat-audio-player[data-msg-id="${msgId}"]`);
            if (!playerEl) return;
            const trackContainer = playerEl.querySelector('.chat-audio-track');
            const rect = trackContainer.getBoundingClientRect();
            const pos = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
            if (isFinite(window.chatAudioObj.duration)) {
              window.chatAudioObj.currentTime = pos * window.chatAudioObj.duration;
            }
          };

          window.openChatFull = async (targetId, type, name) => {
            requestNotificationPermission(); // Ask OS permission to send Push Notifications
            activeChatConfig = { id: targetId, type: type, name: name };
            window.currentChatPage = 1; // Reset pagination bounds on new chat
            window.lastMessagesString = null; // Reset comparison state
            window.forceScrollToBottomNext = true; // Flag to snap scroll to bottom
            const mainArea = document.querySelector('.chat-main');
            const sidebarArea = document.querySelector('.chat-sidebar');
            
            const mentionBtn = document.getElementById('chat-mention-btn');
            const chatInput = document.getElementById('chat-input');
            if (mentionBtn) {
              if (type === 'group') mentionBtn.classList.remove('d-none');
              else mentionBtn.classList.add('d-none');
            }
            if (chatInput) {
              chatInput.placeholder = type === 'group' ? 'Type a message...' : 'Type a message...';
            }
             
            if (mainArea) mainArea.classList.add('active');
            if (sidebarArea && window.innerWidth < 768) sidebarArea.classList.add('hidden');
             
            const headerTitle = document.getElementById('chat-header-title');
            if (headerTitle) {
              const cacheBuster = Math.floor(Date.now() / 60000);
              headerTitle.innerHTML = (type === 'group' 
                ? `<div class="d-flex align-items-center justify-content-center rounded-circle me-2 overflow-hidden bg-dark border border-secondary" style="width: 36px; height: 36px; min-width: 36px; flex-shrink: 0; line-height: 1;"><img src="?action=get_group_image&id=${targetId}&v=${cacheBuster}" onerror="this.outerHTML='<i class=\\'bi bi-people-fill text-info fs-5\\'></i>'" style="width: 100%; height: 100%; object-fit: cover; display: block;"></div>` 
                : `<img src="?action=get_profile_picture&id=${targetId}&v=${cacheBuster}" class="rounded-circle me-2 border border-secondary" style="width: 36px; height: 36px; min-width: 36px; object-fit: cover; flex-shrink: 0; display: block;">`) + 
                `<span class="text-truncate" style="max-width: 60vw; display: inline-block; vertical-align: middle;">${escapeHTML(name)}</span>`;
            }
             
            const pipBtn = document.getElementById('chat-pip-btn');
            if (pipBtn) {
              if ('documentPictureInPicture' in window && window.innerWidth >= 768) {
                pipBtn.classList.remove('d-none');
              } else {
                pipBtn.classList.add('d-none');
                pipBtn.classList.remove('d-md-flex');
              }
            }
            const headerDropdown = document.getElementById('chat-header-dropdown');
            if (headerDropdown) {
              headerDropdown.classList.remove('d-none');
              
              const optInfo = document.getElementById('chat-opt-info');
              if (optInfo) {
                optInfo.onclick = (e) => {
                  e.preventDefault();
                  if (type === 'group') window.showGroupInfo(targetId);
                  else window.loadView({ type: 'artist_songs', param: name, sort: 'album_asc', filter_user_id: targetId, artist_name: '' });
                };
              }
              
              const optSearch = document.getElementById('chat-opt-search');
              if (optSearch) {
                optSearch.onclick = (e) => {
                  e.preventDefault();
                  const searchContainer = document.getElementById('chat-floating-search');
                  if (searchContainer) {
                    searchContainer.classList.remove('d-none');
                    searchContainer.classList.add('d-flex');
                    const input = document.getElementById('chat-inner-search');
                    if (input) input.focus();
                  }
                };
              }
            }
            
            const closeChatSearchBtn = document.getElementById('close-chat-search');
            if (closeChatSearchBtn) {
              closeChatSearchBtn.onclick = (e) => {
                e.preventDefault();
                const searchContainer = document.getElementById('chat-floating-search');
                searchContainer.classList.remove('d-flex');
                searchContainer.classList.add('d-none');
                const input = document.getElementById('chat-inner-search');
                if (input) {
                  input.value = '';
                  input.dispatchEvent(new Event('input')); 
                }
              };
            }

            const msgContainer = document.getElementById('chat-messages-container');
            if (msgContainer) {
              msgContainer.innerHTML = '<div class="text-center p-5"><div class="spinner-border text-secondary"></div></div>';
            }
            if (typeof window.clearChatReply === 'function') window.clearChatReply();
             
            await window.refreshChatFull();
            if (window.chatPollingInterval) clearInterval(window.chatPollingInterval);
            window.chatPollingInterval = setInterval(window.refreshChatFull, 1500); // Ultra-fast real-time sync
          };

          window.currentChatFetchId = 0;

          window.loadOlderChatMessages = (e) => {
            if (e) { e.preventDefault(); e.stopPropagation(); }
            const listEl = document.getElementById('chat-messages-container');
            if (!listEl) return;
            
            const oldScrollHeight = listEl.scrollHeight;
            window.currentChatPage = (window.currentChatPage || 1) + 1;
            
            window.refreshChatFull(true).then(() => {
              // Exact scroll correction so position remains static
              setTimeout(() => {
                if (listEl) listEl.scrollTop = listEl.scrollHeight - oldScrollHeight;
              }, 50);
            });
          };

          window.refreshChatFull = async (forceSync = false) => {
            if (!activeChatConfig.id) return;
            // Prevent polling if reaction picker is open or user is reacting
            if ((window.isReacting || document.querySelector('.reaction-picker.show')) && !forceSync) return;
            
            let isMediaPlaying = false;
            if (window.chatAudioObj && !window.chatAudioObj.paused) isMediaPlaying = true;
            document.querySelectorAll('.chat-main video').forEach(v => {
              if (!v.paused && !v.ended) isMediaPlaying = true;
            });
            if (isMediaPlaying && !forceSync) return;
            
            window.currentChatFetchId++;
            const fetchId = window.currentChatFetchId;
            const page = window.currentChatPage || 1;
            
            try {
              // Add silent fetch (true) to prevent global error toasts blocking UI during rapid polls
              const messages = await fetchData(`?action=get_chat&target_id=${activeChatConfig.id}&chat_type=${activeChatConfig.type}&chat_page=${page}`, {}, true);
              
              if (fetchId !== window.currentChatFetchId || (window.isReacting && !forceSync)) return;

              // Prevent DOM flickering: Compare raw JSON state and skip if identical
              const newMessagesString = JSON.stringify(messages);
              if (!forceSync && window.lastMessagesString === newMessagesString) {
                return; // Nothing changed, skip DOM re-render!
              }
              window.lastMessagesString = newMessagesString;

              const doc = window.chatPipWindow ? window.chatPipWindow.document : document;
              const listEl = doc.getElementById('chat-messages-container');
              if (!listEl) return;

              if (messages && messages.status === 'error') {
                listEl.innerHTML = `<div class="text-center text-danger p-4 mt-auto mb-auto">${escapeHTML(messages.message)}</div>`;
                return;
              }

              if (messages && Array.isArray(messages) && messages.length > 0) {
                const isScrolledToBottom = listEl.scrollHeight - listEl.clientHeight <= listEl.scrollTop + 50;

                let olderBtnHtml = '';
                if (messages.length >= page * 25) {
                  olderBtnHtml = `<div class="text-center w-100 mb-4 mt-2" id="load-older-chat-container"><button class="btn btn-sm btn-outline-secondary rounded-pill px-4" onclick="window.loadOlderChatMessages(event)"><i class="bi bi-clock-history"></i> Load Older Messages</button></div>`;
                }

                listEl.innerHTML = olderBtnHtml + messages.map(m => {
                  const isMe = m.sender_id == currentUser.id;
                  const bubbleClass = isMe ? 'me' : 'other';
                  
                  let mediaHtml = '';
                  if (m.has_image) {
                    const mediaUrl = `?action=get_message_image&id=${m.id}`;
                    const thumbUrl = `?action=get_message_image&id=${m.id}&thumb=1`;
                    if (m.media_type && m.media_type.startsWith('video/')) {
                      mediaHtml = window.buildLazyMediaHtml(mediaUrl, m.media_type, thumbUrl, false);
                    } else if (m.media_type && m.media_type.startsWith('audio/')) {
                      mediaHtml = `
                        <div class="chat-audio-player d-flex align-items-center gap-3 mb-2 p-2 rounded shadow-sm" data-msg-id="${m.id}" style="background: rgba(0,0,0,0.25); border: 1px solid rgba(255,255,255,0.05); min-width: 220px;">
                          <button class="btn btn-danger rounded-circle d-flex align-items-center justify-content-center flex-shrink-0 chat-audio-play-btn" onclick="window.playChatAudio(${m.id}, '${mediaUrl}')" style="width: 38px; height: 38px; padding: 0; transition: transform 0.1s;" onmouseover="this.style.transform='scale(1.05)'" onmouseout="this.style.transform='scale(1)'">
                            <i class="bi bi-${window.chatAudioActiveMsgId == m.id && !window.chatAudioObj.paused ? 'pause' : 'play'}-fill fs-4"></i>
                          </button>
                          <div class="chat-audio-track flex-grow-1 position-relative" style="height: 6px; background: rgba(255,255,255,0.2); border-radius: 3px; cursor: pointer;" onclick="window.seekChatAudio(event, ${m.id})">
                            <div class="chat-audio-progress" style="width: ${window.chatAudioActiveMsgId == m.id && isFinite(window.chatAudioObj.duration) ? (window.chatAudioObj.currentTime / window.chatAudioObj.duration) * 100 : 0}%; height: 100%; background: var(--ytm-accent); border-radius: 3px; pointer-events: none; transition: width 0.1s linear;"></div>
                          </div>
                          <span class="chat-audio-time small fw-bold" style="font-size: 0.75rem; min-width: 35px; user-select: none; color: rgba(255,255,255,0.8);">
                            ${window.chatAudioActiveMsgId == m.id ? Math.floor(window.chatAudioObj.currentTime / 60) + ':' + Math.floor(window.chatAudioObj.currentTime % 60).toString().padStart(2, '0') : '0:00'}
                          </span>
                        </div>`;
                    } else {
                      mediaHtml = window.buildLazyMediaHtml(mediaUrl, m.media_type || 'image/webp', thumbUrl, false);
                    }
                  }
                  
                  const editedHtml = m.is_edited ? '<small class="text-white-50 ms-2" style="font-size: 0.65rem;">(Edited)</small>' : '';
                   
                  let replyHtml = '';
                  if (m.reply_to_id) {
                    const cleanRep = (m.reply_content || 'Photo').replace(/<[^>]*>?/gm, '');
                    replyHtml = `
                      <div class="chat-reply-quote" onclick="document.querySelector('.msg-anchor-${m.reply_to_id}')?.scrollIntoView({behavior:'smooth', block:'center'})">
                        <strong style="color: ${isMe ? '#fff' : 'var(--ytm-accent)'};">${escapeHTML(m.reply_sender || 'Someone')}</strong><br>
                        <span class="text-truncate d-block">${escapeHTML(cleanRep)}</span>
                      </div>
                    `;
                  }

                  let reactionsHtml = '';
                  if (m.reactions && m.reactions.length > 0) {
                    const reactMap = {};
                    m.reactions.forEach(r => {
                      if (!reactMap[r.reaction]) reactMap[r.reaction] = { count:0, me:false };
                      reactMap[r.reaction].count++;
                      if (r.user_id == currentUser.id) reactMap[r.reaction].me = true;
                    });
                      
                    const pills = Object.keys(reactMap).map(emoji => `
                      <span class="reaction-pill ${reactMap[emoji].me ? 'reacted' : ''}" onclick="window.toggleMsgReaction(${m.id}, '${emoji}')">
                        ${emoji} <small>${reactMap[emoji].count}</small>
                      </span>
                     `).join('');
                     reactionsHtml = `<div class="reactions-container">${pills}</div>`;
                  }

                  let senderNameHtml = '';
                  if (!isMe && activeChatConfig.type === 'group') {
                    senderNameHtml = `<div class="fw-bold mb-1 user-profile-link" data-userid="${m.sender_id}" data-artist="${encodeURIComponent(m.sender_name)}" style="font-size: 0.8rem; color: var(--ytm-accent); cursor: pointer;">${escapeHTML(m.sender_name)}</div>`;
                  }

                  const safeSender = m.sender_name ? escapeHTML(m.sender_name).replace(/&#39;/g, "\\'") : 'Someone';
                  const safeContent = m.content ? escapeHTML(m.content).replace(/&#39;/g, "\\'").replace(/\n/g, ' ').replace(/\r/g, '') : '';

                  let actionHtml = `
                    <div class="chat-msg-actions">
                      <div class="position-relative">
                        <button class="chat-action-btn" onclick="this.nextElementSibling.classList.toggle('show')"><i class="bi bi-emoji-smile"></i></button>
                        <div class="reaction-picker">
                          ${['👍','❤️','😂','😮','😢'].map(em => `<button class="emoji-btn" onclick="window.toggleMsgReaction(${m.id}, '${em}')">${em}</button>`).join('')}
                        </div>
                      </div>
                      <button class="chat-action-btn" title="Star Message" onclick="window.toggleStarMsg(${m.id})"><i class="bi ${m.is_starred ? 'bi-star-fill text-warning' : 'bi-star'}"></i></button>
                      <button class="chat-action-btn" title="Reply" onclick="window.setChatReply(${m.id}, '${safeSender}', '${safeContent}')"><i class="bi bi-reply-fill"></i></button>
                      <button class="chat-action-btn" title="Copy" onclick="window.copyChatMsg(${m.id})"><i class="bi bi-copy"></i></button>
                      ${isMe ? `
                        <button class="chat-action-btn" title="Edit" onclick="window.editChatMsg(${m.id}, '${safeContent}')"><i class="bi bi-pencil"></i></button>
                        <button class="chat-action-btn text-danger" title="Delete" onclick="window.delChatMsg(${m.id})"><i class="bi bi-trash"></i></button>
                      ` : ''}
                    </div>
                  `;

                  return `
                    <div class="chat-bubble ${bubbleClass} msg-anchor-${m.id}">
                      ${actionHtml}
                      ${senderNameHtml}
                      ${replyHtml}
                      ${mediaHtml}
                      ${m.content ? `<div style="white-space: pre-wrap;" id="msg-content-${m.id}">${parseUserText(m.content)}</div>` : ''}
                      <div class="text-end mt-1" style="font-size: 0.65rem; opacity: 0.7;">${timeAgo(m.created_at)}${editedHtml}</div>
                      ${reactionsHtml}
                    </div>
                  `;
                }).join('');
                
                if (window.forceScrollToBottomNext || isScrolledToBottom) {
                  listEl.scrollTop = listEl.scrollHeight;
                  setTimeout(() => { if (listEl) listEl.scrollTop = listEl.scrollHeight; }, 50);
                  setTimeout(() => { if (listEl) listEl.scrollTop = listEl.scrollHeight; }, 150);
                  window.forceScrollToBottomNext = false;
                }
              } else {
                listEl.innerHTML = '<div class="text-center text-secondary p-4 mt-auto mb-auto">Start the conversation!</div>';
              }
              updateNotifBadge();
              window.checkMediaCache();
            } catch (err) {
              const listEl = document.getElementById('chat-messages-container');
              if (listEl) listEl.innerHTML = '<div class="text-center text-danger p-4 mt-auto mb-auto">Failed to load messages.</div>';
            }
          };

          window.setChatReply = (id, sender, content) => {
            const doc = window.chatPipWindow ? window.chatPipWindow.document : document;
            doc.getElementById('chat-reply-id').value = id;
            const preview = doc.getElementById('chat-reply-preview');
            preview.innerHTML = `<strong>Replying to ${sender}:</strong><br><span class="text-secondary text-truncate d-block">${content.replace(/<[^>]*>?/gm, '')}</span>`;
            doc.getElementById('chat-reply-bar').classList.add('active');
            doc.getElementById('chat-input').focus();
          };
          window.clearChatReply = (doc = document) => {
            const getEl = id => doc.getElementById(id) || document.getElementById(id);
            getEl('chat-reply-id').value = '';
            getEl('chat-reply-bar').classList.remove('active');
          };
          
          window.toggleMsgReaction = async (msgId, emoji) => {
            document.querySelectorAll('.reaction-picker').forEach(p => p.classList.remove('show'));
            
            window.isReacting = true; // Lock background polling
            window.currentChatFetchId++; // Invalidate any currently running background polls

            // Optimistic UI Update: Apply visually before network confirms
            const msgBubble = document.querySelector(`.msg-anchor-${msgId}`);
            if (msgBubble) {
              let container = msgBubble.querySelector('.reactions-container');
              if (!container) {
                container = document.createElement('div');
                container.className = 'reactions-container';
                msgBubble.appendChild(container);
              }
              
              let foundPill = false;
              container.querySelectorAll('.reaction-pill').forEach(pill => {
                const pillEmoji = pill.textContent.replace(/[0-9]/g, '').trim(); // Safely extract emoji
                
                if (pillEmoji === emoji) {
                  foundPill = true;
                  const countEl = pill.querySelector('small');
                  let count = parseInt(countEl.textContent) || 0;
                  if (pill.classList.contains('reacted')) {
                    pill.classList.remove('reacted');
                    count--;
                    if (count <= 0) pill.remove();
                    else countEl.textContent = count;
                  } else {
                    pill.classList.add('reacted');
                    count++;
                    countEl.textContent = count;
                  }
                } else if (pill.classList.contains('reacted')) {
                  pill.classList.remove('reacted');
                  const countEl = pill.querySelector('small');
                  let count = parseInt(countEl.textContent) || 0;
                  count--;
                  if (count <= 0) pill.remove();
                  else countEl.textContent = count;
                }
              });
              
              if (!foundPill) {
                container.insertAdjacentHTML('beforeend', `<span class="reaction-pill reacted" onclick="window.toggleMsgReaction(${msgId}, '${emoji}')">${emoji} <small>1</small></span>`);
              }
            }
            
            // Dispatch async mutation
            await fetchData('?action=toggle_message_reaction', { method: 'POST', body: JSON.stringify({ message_id: msgId, reaction: emoji }) });
            
            window.isReacting = false; // Unlock polling
            window.refreshChatFull(true); // Force an immediate fresh sync from DB
          };
          
          window.copyChatMsg = (id) => {
            const contentEl = document.getElementById('msg-content-' + id);
            if (contentEl) {
              const text = contentEl.innerText || contentEl.textContent;
              if (navigator.clipboard && window.isSecureContext) {
                navigator.clipboard.writeText(text).then(() => showToast('Message copied!', 'success'));
              }
            }
          };

          window.delChatMsg = async (id) => {
            if (confirm('Delete message?')) {
              await fetchData('?action=delete_message', { method: 'POST', body: JSON.stringify({ id: id }) });
              window.refreshChatFull();
            }
          };
          window.editChatMsg = (id, content) => {
            const newContent = prompt('Edit your message:', decodeHTML(content));
            if (newContent !== null && newContent.trim() !== '') {
              fetchData('?action=edit_message', { method: 'POST', body: JSON.stringify({ id: id, content: newContent }) }).then(() => window.refreshChatFull());
            }
          };

          // Chat Media Preview logic
          window.handleChatImageSelection = (file) => {
            if (file) {
              if (file.size > 10 * 1024 * 1024) {
                showToast('File exceeds 10MB limit.', 'error');
                return;
              }
              const dataTransfer = new DataTransfer();
              dataTransfer.items.add(file);
              document.getElementById('chat-image-input').files = dataTransfer.files;
               
              const previewBar = document.getElementById('chat-img-preview-bar');
              const previewImg = document.getElementById('chat-img-preview-src');
              const previewVid = document.getElementById('chat-video-preview-src');
              const previewAud = document.getElementById('chat-audio-preview-src');
              
              previewImg.classList.add('d-none');
              previewVid.classList.add('d-none');
              previewAud.classList.add('d-none');
              
              if (previewVid.src) URL.revokeObjectURL(previewVid.src);
              if (previewAud.src) URL.revokeObjectURL(previewAud.src);
              
              let fileType = file.type;
              if (!fileType) {
                const ext = file.name.split('.').pop().toLowerCase();
                if (['mp3', 'wav', 'ogg', 'm4a'].includes(ext)) fileType = 'audio/' + ext;
                else if (['mp4', 'webm', 'mov'].includes(ext)) fileType = 'video/' + ext;
              }
              
              if (fileType.startsWith('image/')) {
                const reader = new FileReader();
                reader.onload = ev => {
                  previewImg.src = ev.target.result;
                  previewImg.classList.remove('d-none');
                  previewBar.classList.add('active');
                };
                reader.readAsDataURL(file);
              } else if (fileType.startsWith('video/')) {
                previewVid.src = URL.createObjectURL(file);
                previewVid.classList.remove('d-none');
                previewBar.classList.add('active');
              } else if (fileType.startsWith('audio/')) {
                previewAud.src = URL.createObjectURL(file);
                previewAud.classList.remove('d-none');
                previewBar.classList.add('active');
              } else {
                showToast('Format not supported.', 'error');
                document.getElementById('chat-image-input').value = '';
              }
            }
          };

          window.handleChatChangeGlob = e => {
            if (e.target.id === 'chat-image-input') {
              window.handleChatImageSelection(e.target.files[0]);
            }
          };
          document.addEventListener('change', window.handleChatChangeGlob);

          // Drag and Drop Images into Chat
          const chatMainArea = document.querySelector('.chat-main');
          if (chatMainArea) {
            chatMainArea.addEventListener('dragover', (e) => {
              e.preventDefault();
              e.stopPropagation();
              chatMainArea.style.opacity = '0.7';
            });
            chatMainArea.addEventListener('dragleave', (e) => {
              e.preventDefault();
              e.stopPropagation();
              chatMainArea.style.opacity = '1';
            });
            chatMainArea.addEventListener('drop', (e) => {
              e.preventDefault();
              e.stopPropagation();
              chatMainArea.style.opacity = '1';
              if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
                handleChatImageSelection(e.dataTransfer.files[0]);
              }
            });
          }

          window.clearChatImage = (doc = document) => {
            const getEl = id => doc.getElementById(id) || document.getElementById(id);
            getEl('chat-image-input').value = '';
            getEl('chat-img-preview-bar').classList.remove('active');
            getEl('chat-img-preview-src').classList.add('d-none');
            const vid = getEl('chat-video-preview-src');
            const aud = getEl('chat-audio-preview-src');
            vid.classList.add('d-none');
            aud.classList.add('d-none');
            vid.pause(); aud.pause();
            if (vid.src) URL.revokeObjectURL(vid.src);
            if (aud.src) URL.revokeObjectURL(aud.src);
          };

          window.handleChatInputGlob = (e) => {
            if (e.target.id === 'chat-input') {
              e.target.style.height = 'auto';
              e.target.style.height = (e.target.scrollHeight) + 'px';
            }
          };
          document.addEventListener('input', window.handleChatInputGlob);

          window.handleChatKeydownGlob = (e) => {
            if (e.target.id === 'chat-input' && e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault();
              const form = e.target.ownerDocument.getElementById('chat-form-full');
              if (form) form.dispatchEvent(new Event('submit', { cancelable: true, bubbles: true }));
            }
          };
          document.addEventListener('keydown', window.handleChatKeydownGlob);

          // Group Chat Management
          window.showGroupInfo = async (id, page = 1) => {
            const res = await fetchData(`?action=get_group_info&id=${id}&page=${page}`);
            if (res && res.status === 'success') {
              const g = res.group;
              if (page === 1) {
                document.getElementById('group-info-name').textContent = g.name;
                document.getElementById('group-info-desc').textContent = g.description || 'No description provided.';
                document.getElementById('group-info-count').textContent = g.total_members || g.members.length;
              }
                
              // Set the group profile picture
              const groupImgContainer = document.getElementById('group-info-img-container');
              if (groupImgContainer) {
                groupImgContainer.innerHTML = `<img src="?action=get_group_image&id=${g.id}&t=${Date.now()}" onerror="this.outerHTML='<i class=\\'bi bi-people-fill text-secondary\\' style=\\'font-size: 3rem;\\'></i>'" style="width: 100%; height: 100%; object-fit: cover;">`;
              }

              const isOwner = g.owner_id == currentUser.id || (currentUser && currentUser.email === 'musiclibrary@mail.com');
              const controls = document.getElementById('group-owner-controls');
              if (isOwner) {
                controls.classList.remove('d-none');
                document.getElementById('group-btn-edit').onclick = async () => {
                  document.getElementById('group-manage-title').innerHTML = '<i class="bi bi-pencil-square text-warning me-2"></i>Edit Group';
                  document.getElementById('group-manage-id').value = g.id;
                  document.getElementById('group-manage-name').value = g.name;
                  document.getElementById('group-manage-desc').value = g.description || '';
                     
                  const previewImg = document.getElementById('group-manage-image-preview');
                  previewImg.src = `?action=get_group_image&id=${g.id}&t=${Date.now()}`;
                  previewImg.style.display = 'block';
                  if (groupCropper) { groupCropper.destroy(); groupCropper = null; }
                  if (document.getElementById('group-manage-image')) document.getElementById('group-manage-image').value = '';

                  document.getElementById('group-manage-submit').textContent = 'Save Changes';
                  document.getElementById('group-manage-submit').className = 'btn btn-warning text-dark fw-bold w-100';
                  bootstrap.Modal.getOrCreateInstance(document.getElementById('group-info-modal')).hide();
                  bootstrap.Modal.getOrCreateInstance(document.getElementById('group-manage-modal')).show();
                };
                document.getElementById('group-btn-delete').onclick = async () => {
                  if (confirm('Permanently delete this group?')) {
                    await fetchData('?action=delete_chat_group', { method:'POST', body: JSON.stringify({id: g.id}) });
                    bootstrap.Modal.getInstance(document.getElementById('group-info-modal')).hide();
                    loadView(currentView);
                  }
                };
                document.getElementById('group-btn-invite').onclick = async () => {
                  const exp = document.getElementById('group-invite-expire').value;
                  const iRes = await fetchData('?action=generate_group_invite', { method:'POST', body: JSON.stringify({id: g.id, expire: exp==='forever'?null:exp}) });
                  if (iRes && iRes.status === 'success') {
                    const link = window.location.origin + window.location.pathname + '?chat_invite=' + iRes.token;
                    navigator.clipboard.writeText(link);
                    showToast('Invite link copied!', 'success');
                  }
                };
              } else {
                controls.classList.add('d-none');
              }

              const membersHtml = g.members.map(m => `
                <div class="list-group-item bg-transparent text-white px-0 d-flex justify-content-between align-items-center border-secondary">
                   <div class="d-flex align-items-center gap-3 user-profile-link" data-userid="${m.id}" data-artist="${encodeURIComponent(m.artist)}" style="cursor: pointer;">
                     <img src="?action=get_profile_picture&id=${m.id}" class="rounded-circle" style="width:32px; height:32px; object-fit:cover;">
                     <div>
                       <div class="fw-bold fs-6 hover-underline">${escapeHTML(m.artist)}</div>
                       <small class="text-secondary" style="font-size:0.75rem;">ID: ${m.id}</small>
                     </div>
                   </div>
                   <div class="d-flex align-items-center gap-2">
                     ${isOwner && m.role !== 'owner' ? `<button class="btn btn-sm btn-outline-warning fw-bold transfer-owner-btn" data-userid="${m.id}">Make Owner</button>` : ''}
                     ${m.role === 'owner' ? '<span class="badge bg-warning text-dark"><i class="bi bi-star-fill"></i> Owner</span>' : ''}
                   </div>
                </div>
              `).join('');

              const container = document.getElementById('group-info-members');
              if (page === 1) {
                container.innerHTML = membersHtml;
              } else {
                container.insertAdjacentHTML('beforeend', membersHtml);
              }

              container.onclick = async (e) => {
                const transferBtn = e.target.closest('.transfer-owner-btn');
                if (transferBtn) {
                  const newOwnerId = transferBtn.dataset.userid;
                  if (confirm('Transfer ownership to this member? You will become a regular member.')) {
                    const res = await fetchData('?action=transfer_group_ownership', {
                      method: 'POST',
                      body: JSON.stringify({ group_id: g.id, new_owner_id: newOwnerId })
                    });
                    if (res && res.status === 'success') {
                      showToast(res.message, 'success');
                      window.showGroupInfo(g.id, 1);
                    } else {
                      showToast(res?.message || 'Error transferring ownership', 'error');
                    }
                  }
                }
              };

              const existingLoadMore = document.getElementById('group-load-more-btn');
              if (existingLoadMore) existingLoadMore.remove();

              if (g.members.length === 25) {
                container.insertAdjacentHTML('afterend', `
                  <button class="btn btn-outline-light btn-sm w-100 mt-2 mb-3 fw-bold" id="group-load-more-btn" onclick="window.showGroupInfo(${id}, ${page + 1})">
                    Load More Members
                  </button>
                `);
              }

              document.getElementById('group-btn-leave').onclick = async () => {
                const confirmMsg = isOwner ? 'As the owner, if you leave, ownership will be given to a random member. Leave group?' : 'Leave this group?';
                if (confirm(confirmMsg)) {
                  await fetchData('?action=leave_chat_group', { method:'POST', body: JSON.stringify({id: g.id}) });
                  bootstrap.Modal.getInstance(document.getElementById('group-info-modal')).hide();
                  loadView({ type: 'get_inbox', param: '', sort: '', filter_user_id: '' });
                }
              };
              bootstrap.Modal.getOrCreateInstance(document.getElementById('group-info-modal')).show();
            }
          };

          document.addEventListener('submit', async e => {
            if (e.target.id === 'group-manage-form') {
              e.preventDefault();
              const submitBtn = document.getElementById('group-manage-submit');
              submitBtn.disabled = true;
              submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Saving...';
               
              const id = document.getElementById('group-manage-id').value;
              const name = document.getElementById('group-manage-name').value;
              const desc = document.getElementById('group-manage-desc').value;
              const imgInput = document.getElementById('group-manage-image');
               
              const formData = new FormData();
              formData.append('name', name);
              formData.append('description', desc);
              if (id) formData.append('id', id);

              const processUpload = async () => {
                try {
                  const res = await fetch(`?action=${id ? 'edit_chat_group' : 'create_chat_group'}`, { method: 'POST', body: formData });
                  const result = await res.json();
                   
                  if (result && result.status === 'success') {
                    showToast(id ? 'Group updated' : 'Group created', 'success');
                    bootstrap.Modal.getInstance(document.getElementById('group-manage-modal')).hide();
                    loadView(currentView);
                  } else {
                    showToast(result.message || 'Action failed', 'error');
                  }
                } catch (err) {
                  showToast('Network error', 'error');
                }
                submitBtn.disabled = false;
                submitBtn.textContent = id ? 'Save Changes' : 'Create Group';
              };

              if (groupCropper) {
                groupCropper.getCroppedCanvas({ width: 300, height: 300 }).toBlob(blob => {
                  formData.append('image', blob, 'group.jpg');
                  processUpload();
                }, 'image/jpeg', 0.85);
              } else if (imgInput && imgInput.files.length > 0) {
                formData.append('image', imgInput.files[0]);
                processUpload();
              } else {
                processUpload();
              }
            }
          });
             
          window.handleChatSubmitGlob = async e => {
            if (e.target.id === 'chat-form-full') {
              e.preventDefault();
              const doc = e.target.ownerDocument;
              const input = doc.getElementById('chat-input');
              const imgInput = doc.getElementById('chat-image-input');
              const replyId = doc.getElementById('chat-reply-id').value;
               
              if (!input.value.trim() && imgInput.files.length === 0) return;
               
              const formData = new FormData();
              formData.append('target_id', activeChatConfig.id);
              formData.append('chat_type', activeChatConfig.type);
              formData.append('content', input.value);
              if (replyId) formData.append('reply_to_id', replyId);
              if (imgInput.files.length > 0) formData.append('image', imgInput.files[0]);

              const submitBtn = doc.getElementById('chat-submit-btn');
              const originalBtnHtml = submitBtn.innerHTML;
              submitBtn.disabled = true;
              submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm" style="width: 1.2rem; height: 1.2rem;"></span>';
              
              const progContainer = doc.getElementById('chat-upload-progress-container');
              const progBar = doc.getElementById('chat-upload-progress');
            if (imgInput.files.length > 0) {
               progContainer.classList.remove('d-none');
               progBar.style.width = '0%';
            }

            const xhr = new XMLHttpRequest();
            xhr.upload.onprogress = (evt) => {
              if (evt.lengthComputable && imgInput.files.length > 0) {
                const pct = Math.round((evt.loaded / evt.total) * 100);
                progBar.style.width = pct + '%';
              }
            };
            
            xhr.open('POST', '?action=send_message', true);
            xhr.onload = async () => {
              submitBtn.disabled = false;
              submitBtn.innerHTML = originalBtnHtml;
              progContainer.classList.add('d-none');
              
              if (xhr.status === 200) {
                try {
                  const result = JSON.parse(xhr.responseText);
                  if (result && result.status === 'success') {
                    input.value = '';
                    input.style.height = 'auto'; // Reset textarea height
                    window.clearChatImage(doc);
                    window.clearChatReply(doc);
                    window.forceScrollToBottomNext = true; // Snap viewport to bottom for new sent message
                    await window.refreshChatFull();
                  } else {
                    showToast(result.message || 'Failed to send', 'error');
                  }
                } catch (err) {
                  showToast('Invalid server response.', 'error');
                }
              } else {
                showToast('Network error during upload', 'error');
              }
            };
            xhr.onerror = () => {
              submitBtn.disabled = false;
              submitBtn.innerHTML = originalBtnHtml;
              progContainer.classList.add('d-none');
              showToast('Network error during upload', 'error');
            };
            xhr.send(formData);
            }
          };
          document.addEventListener('submit', async e => {
            if (e.target.id === 'chat-form-full') {
              await window.handleChatSubmitGlob(e);
            }
          });
          
          window.chatPipWindow = null;
          document.addEventListener('click', async (e) => {
            const pipBtn = e.target.closest('#chat-pip-btn');
            if (pipBtn) {
              if (window.chatPipWindow) {
                window.chatPipWindow.close();
                return;
              }
              if (!('documentPictureInPicture' in window)) return;
              
              try {
                window.chatPipWindow = await window.documentPictureInPicture.requestWindow({
                  width: 450,
                  height: 700
                });

                [...document.styleSheets].forEach(styleSheet => {
                  try {
                    const cssRules = [...styleSheet.cssRules].map(rule => rule.cssText).join('');
                    const style = document.createElement('style');
                    style.textContent = cssRules;
                    window.chatPipWindow.document.head.appendChild(style);
                  } catch (err) {
                    if (styleSheet.href) {
                      const link = document.createElement('link');
                      link.rel = 'stylesheet';
                      link.href = styleSheet.href;
                      window.chatPipWindow.document.head.appendChild(link);
                    }
                  }
                });

                const iconLink = document.createElement('link');
                iconLink.rel = 'stylesheet';
                iconLink.href = 'https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.min.css';
                window.chatPipWindow.document.head.appendChild(iconLink);

                const chatMain = document.querySelector('.chat-main');
                const chatWrapper = document.querySelector('.chat-wrapper');
                
                window.chatPipWindow.document.body.style.background = 'var(--ytm-bg)';
                window.chatPipWindow.document.body.style.margin = '0';
                window.chatPipWindow.document.body.appendChild(chatMain);

                window.chatPipWindow.document.addEventListener('input', window.handleChatInputGlob);
                window.chatPipWindow.document.addEventListener('change', window.handleChatChangeGlob);
                window.chatPipWindow.document.addEventListener('keydown', window.handleChatKeydownGlob);
                window.chatPipWindow.document.addEventListener('submit', window.handleChatSubmitGlob);

                window.chatPipWindow.addEventListener('pagehide', () => {
                  if (chatWrapper && chatMain) chatWrapper.appendChild(chatMain);
                  window.chatPipWindow = null;
                });
              } catch (err) {
                console.error(err);
                showToast('Failed to open Chat PiP', 'error');
              }
              return;
            }
          });
          
          // --- END FULL PAGE CHAT APP LOGIC ---
          const clearBtn = document.getElementById('clear-activity-btn');
          if (clearBtn) {
            clearBtn.addEventListener('click', async () => {
              if (confirm('Are you sure you want to clear all your notifications?')) {
                const res = await fetchData('?action=clear_activity_feed', { method: 'POST' });
                if (res && res.status === 'success') {
                  showToast('Notifications cleared.', 'success');
                  loadActivityFeed();
                  updateNotifBadge();
                }
              }
            });
          }
          
          body.addEventListener('click', async (e) => {
            const openChatBtn = e.target.closest('.open-chat-btn');
            if (openChatBtn) {
              bootstrap.Modal.getInstance(activityModalEl).hide();
              await loadView({ type: 'get_inbox', param: '', sort: '', filter_user_id: '' });
              window.openChatFull(openChatBtn.dataset.userid, 'dm', openChatBtn.dataset.artist);
              return;
            }
            const replyBtn = e.target.closest('.notif-reply-btn');
            if (replyBtn) {
              const songId = parseInt(replyBtn.dataset.songId);
              const commentId = parseInt(replyBtn.dataset.commentId);
              const username = replyBtn.dataset.username;
              
              bootstrap.Modal.getInstance(activityModalEl).hide();
              window.openCommentsModal(songId, commentId, username);
              return;
            }
            const commReplyBtn = e.target.closest('.notif-comm-reply-btn');
            if (commReplyBtn) {
              bootstrap.Modal.getInstance(activityModalEl).hide();
              loadView({ type: 'get_community', param: '', sort: 'newest', filter_user_id: '', artist_name: '' });
              setTimeout(() => {
                const input = document.getElementById('community-post-input');
                const parentId = document.getElementById('community-parent-id');
                if (input && parentId) {
                  parentId.value = commReplyBtn.dataset.postId;
                  input.placeholder = "Replying to post...";
                  const username = commReplyBtn.dataset.username.replace(/\s+/g, '');
                  input.value = `@${username} `;
                  input.focus();
                  window.scrollTo({ top: 0, behavior: 'smooth' });
                }
              }, 800);
            }
          });
        }

        // API Modal logic
        const apiUrlInput = document.getElementById('api-url-input');
        const copyApiBtn = document.getElementById('copy-api-btn');
        const apiModalEl = document.getElementById('api-modal');
        const apiActionSelect = document.getElementById('api-action-select');
        const apiMethodBadge = document.getElementById('api-method-badge');
        const apiPayloadContainer = document.getElementById('api-payload-container');
        const apiPayloadCode = document.getElementById('api-payload-code');

        const updateApiUrl = () => {
          if (!apiUrlInput || !apiActionSelect) return;
          const selectedOption = apiActionSelect.options[apiActionSelect.selectedIndex];
          const actionVal = selectedOption.value;
          
          const userKeyInput = document.getElementById('custom-api-key-input');
          const finalKey = userKeyInput && userKeyInput.value ? userKeyInput.value.trim() : '';
          
          let baseAppUrl = window.location.href.split('?')[0].split('#')[0];
          if (baseAppUrl.includes('null') || baseAppUrl.includes('srcdoc') || baseAppUrl === 'about:blank') {
            baseAppUrl = '';
          }
          baseAppUrl = baseAppUrl.replace(/\/+$/, ''); // Strip trailing slashes to prevent double slash bug
          
          let url = baseAppUrl + '/?access=api&action=' + actionVal;
          if (finalKey) url += '&api_key=' + encodeURIComponent(finalKey);
          apiUrlInput.value = url;

          const apiVisualOpenTabBtn = document.getElementById('api-visual-open-tab-btn');
          if (apiVisualOpenTabBtn) {
            let sourceType = 'all';
            let idName = '';
            if (actionVal.includes('playlist')) {
              sourceType = 'playlist';
              idName = '1';
            } else if (actionVal.includes('artist')) {
              sourceType = 'artist';
              idName = '1';
            }
            let absoluteBaseUrl = window.location.protocol + '//' + window.location.host + window.location.pathname;
            if (absoluteBaseUrl.includes('null') || absoluteBaseUrl.includes('srcdoc')) {
              absoluteBaseUrl = '';
            }
            absoluteBaseUrl = absoluteBaseUrl.replace(/\/+$/, ''); // Clean absolute URL for Playground injection
            
            apiVisualOpenTabBtn.dataset.sourceType = sourceType;
            apiVisualOpenTabBtn.dataset.idName = idName;
            apiVisualOpenTabBtn.dataset.backendUrl = absoluteBaseUrl;
            apiVisualOpenTabBtn.dataset.apiKey = finalKey;
          }
          
          const method = selectedOption.getAttribute('data-method') || 'GET';
          if (apiMethodBadge) {
            apiMethodBadge.textContent = method;
            apiMethodBadge.className = method === 'POST' ? 'badge bg-warning text-dark' : 'badge bg-primary';
          }

          const payload = selectedOption.getAttribute('data-body');
          if (payload && apiPayloadContainer && apiPayloadCode) {
            apiPayloadCode.textContent = payload;
            apiPayloadContainer.classList.remove('d-none');
          } else if (apiPayloadContainer) {
            apiPayloadContainer.classList.add('d-none');
          }

          // VISUAL CLIENT TESTER INJECTION (Iframe 2)
          const visualIframe = document.getElementById('api-visual-iframe');
          const templateEl = document.getElementById('play-client-template');

          if (visualIframe && templateEl) {
            // Unconditionally render playground client UI, letting it gracefully query using session cookie
            if (!visualIframe.srcdoc || visualIframe.srcdoc.includes('Access Denied')) {
              visualIframe.srcdoc = templateEl.innerHTML;
            }
                
            let sourceType = 'all';
            let idName = '';
            if (actionVal.includes('playlist')) {
              sourceType = 'playlist';
              idName = '1';
            } else if (actionVal.includes('artist')) {
              sourceType = 'artist';
              idName = '1';
            }
            const safeApiKey = finalKey ? encodeURIComponent(finalKey) : '';
            const hash = `#sourcetype=${sourceType}&id/name=${idName}&backendurl=${encodeURIComponent(baseAppUrl)}&apikey=${safeApiKey}`;
          
            if (visualIframe.contentWindow && visualIframe.contentWindow.location && visualIframe.contentWindow.document.readyState === 'complete') {
              visualIframe.contentWindow.location.hash = hash;
            } else {
              visualIframe.onload = () => {
                visualIframe.contentWindow.location.hash = hash;
              };
            }
          }

          // RAW JSON VIEWER LOGIC (Iframe 1)
          const apiExampleIframe = document.getElementById('api-example-iframe');
          if (apiExampleIframe) {
            
            apiExampleIframe.srcdoc = `<html><body style="background-color: #000000; color: #aaaaaa; font-family: monospace; font-size: 13px; margin: 0; padding: 12px;">Querying database for real data...</body></html>`;
            
            const injectIframe = (dataObj, color) => {
              const jsonString = JSON.stringify(dataObj, null, 2);
              apiExampleIframe.srcdoc = `<html><body style="background-color: #000000; color: ${color}; font-family: monospace; font-size: 13px; margin: 0; padding: 12px; white-space: pre-wrap; word-wrap: break-word;">${jsonString}</body></html>`;
            };

            const fallbackToFakeData = () => {
              const randomData = {
                status: "success", action_requested: actionVal, method: method,
                results: [{
                    id: Math.floor(Math.random() * 9000) + 1000, 
                    title: "Example Track " + Math.floor(Math.random() * 100),
                    artist: "Random Artist " + Math.floor(Math.random() * 50),
                    album: "Awesome Album Vol " + Math.floor(Math.random() * 10), 
                    duration: Math.floor(Math.random() * 200) + 120,
                    is_favorite: Math.random() > 0.5 ? 1 : 0
                }]
              };
              injectIframe(randomData, '#4ade80'); // Green text means FAKE data
            };

            if (method === 'GET') {
              let testUrl = apiUrlInput.value;
              
              // ADVANCED: Safely request an actual database entity to populate variables so you don't query empty/invalid IDs
              const fetchRealExample = async () => {
                try {
                  if (testUrl.includes('SONG_ID') || testUrl.includes('USER_ID') || testUrl.includes('PLAYLIST_ID')) {
                    const realSongs = await fetch('?access=api&action=get_songs&limit=1&api_key=' + encodeURIComponent(finalKey)).then(r=>r.json());
                    const realPlaylists = await fetch('?access=api&action=get_user_playlists&api_key=' + encodeURIComponent(finalKey)).then(r=>r.json());
                    
                    const sId = (realSongs && realSongs.length > 0) ? realSongs[0].id : '1';
                    const uId = (realSongs && realSongs.length > 0) ? realSongs[0].user_id : '1';
                    const pId = (realPlaylists && realPlaylists.length > 0) ? realPlaylists[0].public_id : '1';
                    
                    testUrl = testUrl.replace('SONG_ID', sId).replace('USER_ID', uId).replace('PLAYLIST_ID', pId).replace('YOUR_QUERY', 'a');
                  }

                  const res = await fetch(testUrl);
                  const data = await res.json();
                  
                  if (!data || data.status === 'error' || (Array.isArray(data) && data.length === 0)) {
                    fallbackToFakeData();
                  } else {
                    let displayData = Array.isArray(data) ? data.slice(0, 3) : data;
                    injectIframe(displayData, '#60a5fa'); // Blue text means REAL database data
                  }
                } catch (e) {
                  fallbackToFakeData();
                }
              };
              
              fetchRealExample();
            } else {
              fallbackToFakeData(); 
            }
          }
        };

        if (apiModalEl && apiUrlInput) {
          const userKeyInput = document.getElementById('custom-api-key-input');
          const apiVisualOpenTabBtn = document.getElementById('api-visual-open-tab-btn');
          
          // Secure one-time click listener for the Playground Standalone Tab overlay icon
          if (apiVisualOpenTabBtn) {
            apiVisualOpenTabBtn.addEventListener('click', (e) => {
              e.preventDefault();
              e.stopPropagation(); // Avoid triggering any container clicks
              const bUrl = apiVisualOpenTabBtn.dataset.backendUrl || window.location.origin + window.location.pathname;
              const safeApiKey = apiVisualOpenTabBtn.dataset.apiKey ? encodeURIComponent(apiVisualOpenTabBtn.dataset.apiKey) : '';
              const sourceType = apiVisualOpenTabBtn.dataset.sourceType || 'all';
              const idName = apiVisualOpenTabBtn.dataset.idName || '';
              
              // Constructs the secure hash containing the #playground routing indicator
              const hash = `#playground&sourcetype=${sourceType}&id/name=${idName}&backendurl=${encodeURIComponent(bUrl)}&apikey=${safeApiKey}`;
              
              window.open(bUrl + hash, '_blank');
            });
          }

          apiModalEl.addEventListener('show.bs.modal', async () => {
            window.userHasApiKeys = false;
            if (currentUser) {
              const myApis = await fetchData('?action=get_my_apis');
              if (myApis && myApis.length > 0) window.userHasApiKeys = true;
            }
            if (window.adminAutoToken === 'musiclibrary@mail.com' && document.getElementById('custom-api-key-input').value === '') {
              document.getElementById('custom-api-key-input').value = 'ADMIN_SESSION_BYPASS';
            }
            updateApiUrl();
          });
          if (apiActionSelect) apiActionSelect.addEventListener('change', updateApiUrl);
          if (userKeyInput) userKeyInput.addEventListener('input', updateApiUrl);
        }

        // API Visual Client Scaling & Fullscreen (16:9 Desktop Simulation)
        const resizeVisualIframe = () => {
          const iframe = document.getElementById('api-visual-iframe');
          if (!iframe) return;
          const container = iframe.parentElement;
          const containerWidth = container.clientWidth;
          const scale = containerWidth / 1280;
          iframe.style.transform = `scale(${scale})`;
          
          const containerHeight = container.clientHeight;
          const expectedHeight = containerWidth * (9/16);
          if (containerHeight > expectedHeight) {
            iframe.style.top = `${(containerHeight - expectedHeight) / 2}px`;
          } else {
            iframe.style.top = '0px';
          }
        };

        const visualContainer = document.getElementById('api-visual-container');
        const visualFullscreenBtn = document.getElementById('api-visual-fullscreen-btn');
        if (visualContainer && visualFullscreenBtn) {
          visualFullscreenBtn.addEventListener('click', () => {
            if (!document.fullscreenElement) {
              visualContainer.requestFullscreen().catch(err => {
                console.error("Fullscreen initiation failed:", err);
              });
            } else {
              document.exitFullscreen();
            }
          });
          
          visualContainer.addEventListener('dblclick', (e) => {
            if (e.target.closest('#api-visual-fullscreen-btn')) return;
            visualFullscreenBtn.click();
          });
        }

        document.addEventListener('fullscreenchange', () => {
          const btn = document.getElementById('api-visual-fullscreen-btn');
          if (btn) {
            btn.innerHTML = document.fullscreenElement ? '<i class="bi bi-fullscreen-exit"></i>' : '<i class="bi bi-fullscreen"></i>';
          }
          setTimeout(resizeVisualIframe, 100);
        });

        window.addEventListener('resize', resizeVisualIframe);

        const apiVisualTabBtn = document.getElementById('api-visual-tab-btn');
        if (apiVisualTabBtn) {
          apiVisualTabBtn.addEventListener('shown.bs.tab', () => {
            setTimeout(resizeVisualIframe, 100);
          });
        }

        if (copyApiBtn) {
          copyApiBtn.addEventListener('click', () => {
            const onSuccess = () => {
              copyApiBtn.textContent = 'Copied!';
              copyApiBtn.classList.replace('btn-danger', 'btn-success');
              setTimeout(() => {
                copyApiBtn.textContent = 'Copy';
                copyApiBtn.classList.replace('btn-success', 'btn-danger');
              }, 2000);
            };
            const onError = () => showToast('Failed to copy API link.', 'error');

            if (navigator.clipboard && window.isSecureContext) {
              navigator.clipboard.writeText(apiUrlInput.value).then(onSuccess).catch(onError);
            } else {
              const textArea = document.createElement("textarea");
              textArea.value = apiUrlInput.value;
              textArea.style.position = "fixed";
              textArea.style.top = "0";
              textArea.style.left = "0";
              textArea.style.opacity = "0";
              document.body.appendChild(textArea);
              textArea.focus();
              textArea.select();
              try {
                const successful = document.execCommand('copy');
                if (successful) onSuccess();
                else onError();
              } catch (err) {
                onError();
              }
              document.body.removeChild(textArea);
            }
          });
        }

        const getApiBtn = document.getElementById('get-api-btn');
        if (getApiBtn) {
          getApiBtn.addEventListener('click', (e) => {
            e.preventDefault();
            hideMobileSidebar();
            bootstrap.Modal.getOrCreateInstance(document.getElementById('api-modal')).show();
          });
        }

        const clearApiKeyBtn = document.getElementById('clear-api-key-btn');
        if (clearApiKeyBtn) {
          clearApiKeyBtn.addEventListener('click', () => {
            localStorage.removeItem('admin_api_key');
            window.adminApiKey = null;
            bootstrap.Modal.getInstance(document.getElementById('api-modal')).hide();
            showToast("API Master Key successfully scrubbed from cache memory.", "info");
          });
        }
        
        // Connect the Mobile API Jump Menu to the Scrollable Container
        const mobileApiNavSelect = document.getElementById('mobile-api-nav-select');
        if (mobileApiNavSelect) {
          mobileApiNavSelect.addEventListener('change', function() {
            const targetId = this.value;
            const targetElement = document.getElementById(targetId);
            const scrollContainer = document.querySelector('.api-content'); // The scrollable right column
            
            if (targetElement && scrollContainer) {
              // Calculate relative scroll position
              const topPos = targetElement.offsetTop;
              scrollContainer.scrollTo({
                top: topPos - 20, // Add slight padding so it's perfectly visible below the sticky header
                behavior: 'smooth'
              });
            }
          });
        }

        const playerTrackInfoMobile = document.querySelector('.player-bar .track-info.d-md-none');
        const playerModalEl = document.getElementById('player-modal');
        const playerModal = playerModalEl ? new bootstrap.Modal(playerModalEl) : null;
        
        const profilePictureHeaderDesktop = document.getElementById('profile-picture-header-desktop');
        const profilePictureHeaderMobile = document.getElementById('profile-picture-header-mobile');
        const profilePicturePreview = document.getElementById('profile-picture-preview');

        const playerElements = {
          art: [document.getElementById('player-art-desktop'), document.getElementById('player-art-mobile'), document.getElementById('player-modal-art'), document.getElementById('desktop-player-modal-art')],
          title: [document.getElementById('player-title-desktop'), document.getElementById('player-title-mobile'), document.getElementById('player-modal-title'), document.getElementById('desktop-player-modal-title')],
          artist: [document.getElementById('player-artist-desktop'), document.getElementById('player-artist-mobile'), document.getElementById('player-modal-artist'), document.getElementById('desktop-player-modal-artist')],
          currentTime: [document.getElementById('current-time'), document.getElementById('player-modal-current-time'), document.getElementById('desktop-player-modal-current-time')],
          timeLeft: [document.getElementById('time-left'), document.getElementById('player-modal-time-left'), document.getElementById('desktop-player-modal-time-left')],
          progress: [document.getElementById('progress-bar'), document.getElementById('player-modal-progress-bar'), document.getElementById('desktop-player-modal-progress-bar')],
          progressContainer: [document.getElementById('progress-container'), document.getElementById('player-modal-progress-container'), document.getElementById('desktop-player-modal-progress-container')],
          playPauseBtn: [document.getElementById('play-pause-btn-desktop'), document.getElementById('play-pause-btn-mobile'), document.getElementById('player-modal-play-pause-btn'), document.getElementById('desktop-player-modal-play-pause-btn')],
          prevBtn: [document.getElementById('prev-btn-desktop'), document.getElementById('prev-btn-mobile'), document.getElementById('player-modal-prev-btn'), document.getElementById('desktop-player-modal-prev-btn')],
          nextBtn: [document.getElementById('next-btn-desktop'), document.getElementById('next-btn-mobile'), document.getElementById('player-modal-next-btn'), document.getElementById('desktop-player-modal-next-btn')],
          shuffleBtn: [document.getElementById('shuffle-btn-desktop'), document.getElementById('shuffle-btn-mobile'), document.getElementById('player-modal-shuffle-btn'), document.getElementById('desktop-player-modal-shuffle-btn')],
          repeatBtn: [document.getElementById('repeat-btn-desktop'), document.getElementById('repeat-btn-mobile'), document.getElementById('player-modal-repeat-btn'), document.getElementById('desktop-player-modal-repeat-btn')],
          moreBtn: [document.getElementById('player-more-btn-desktop'), document.getElementById('player-more-btn-mobile'), document.getElementById('player-modal-more-btn'), document.getElementById('desktop-player-modal-more-btn')],
          volumeBtn: document.getElementById('volume-btn'),
          volumeSlider: document.getElementById('volume-slider'),
        };
        
        const desktopPlayerModalEl = document.getElementById('desktop-player-modal');
        const desktopPlayerModal = desktopPlayerModalEl ? new bootstrap.Modal(desktopPlayerModalEl) : null;
        
        if (playerModalEl) {
          playerModalEl.addEventListener('shown.bs.modal', () => {
            window.enforceScrollToActive('mp-queue-pane', 'mobile-player-queue-list', false);
          });
          
          const mpQueueTabBtn = document.querySelector('button[data-bs-target="#mp-queue-pane"]');
          if (mpQueueTabBtn) {
            mpQueueTabBtn.addEventListener('shown.bs.tab', () => {
              window.enforceScrollToActive('mp-queue-pane', 'mobile-player-queue-list', false);
            });
          }
        }
        
        if (desktopPlayerModalEl) {
          desktopPlayerModalEl.addEventListener('shown.bs.modal', () => {
            window.enforceScrollToActive('dp-queue-pane', 'desktop-player-queue-list', false);
          });
          
          const dpQueueTabBtn = document.querySelector('button[data-bs-target="#dp-queue-pane"]');
          if (dpQueueTabBtn) {
            dpQueueTabBtn.addEventListener('shown.bs.tab', () => {
              window.enforceScrollToActive('dp-queue-pane', 'desktop-player-queue-list', false);
            });
          }
        }
        
        const renderDesktopLyrics = () => {
          const lyricsContainer = document.getElementById('desktop-synced-lyrics');
          if (!lyricsContainer || !currentSong) return;

          if (currentSong.lyrics) {
            const lrcData = parseLRC(currentSong.lyrics);
            if (lrcData.length > 0) {
              currentLrcData = lrcData;
              currentLrcSongId = currentSong.id;
              currentLyricIndex = -1;
              
              lyricsContainer.innerHTML = lrcData.map((line, idx) => 
                `<div class="lyric-line" data-index="${idx}" data-time="${line.time}">${escapeHTML(line.text)}</div>`
              ).join('');
            } else {
              currentLrcData = null;
              currentLrcSongId = null;
              lyricsContainer.innerHTML = `<pre style="white-space: pre-wrap; font-family: 'Roboto', sans-serif;">${escapeHTML(currentSong.lyrics)}</pre>`;
            }
          } else {
            currentLrcData = null;
            currentLrcSongId = null;
            lyricsContainer.innerHTML = '<p class="text-center text-secondary">No lyrics available.</p>';
          }
        };

        const renderQueue = async (reset = false) => {
          const queueContainerDesktop = document.getElementById('desktop-player-queue-list');
          const queueContainerMobile = document.getElementById('mobile-player-queue-list');
          
          if (reset) {
            renderedQueueCount = 0;
            if (queueContainerDesktop) queueContainerDesktop.innerHTML = '<div class="song-list"></div>';
            if (queueContainerMobile) queueContainerMobile.innerHTML = '<div class="song-list"></div>';
          }
          
          if (renderedQueueCount >= queue.length || isQueueLoading) return;
          isQueueLoading = true;
          
          // Determine chunk size. If resetting, ensure we render up to the active song so it can be scrolled to immediately.
          let chunkSize = 25;
          if (reset && typeof queueIndex !== 'undefined' && queueIndex >= 25) {
            chunkSize = queueIndex + 15;
          }
          
          const nextChunkIds = queue.slice(renderedQueueCount, renderedQueueCount + chunkSize);
          const missingIds = nextChunkIds.filter(id => !globalSongCache[id]);
          
          // Fetch any data that isn't cached yet
          if (missingIds.length > 0) {
            const fetchedData = await fetchData('?action=get_queue_songs', {
              method: 'POST', headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ ids: missingIds })
            }, true); // Silent flag set to true
            if (fetchedData) {
              fetchedData.forEach(song => globalSongCache[song.id] = song);
            }
          }
          
          let html = '';
          const escapeAttr = (str) => str ? String(str).replace(/'/g, "&apos;").replace(/"/g, "&quot;") : '';
          
          nextChunkIds.forEach((songId) => {
            const song = globalSongCache[songId];
            if (!song) return;
            const isNowPlaying = currentSong && (songId === currentSong.id);
            const coverSvg = getSvgPlaceholder(song.title || 'Unknown');
            
            html += `
              <div class="song-item py-md-3 ${isNowPlaying ? 'now-playing' : ''}" 
                data-song-id="${song.id}" 
                data-is-favorite="${song.is_favorite == 1 ? '1' : '0'}"
                data-song-title="${escapeAttr(song.title)}"
                data-song-artist="${escapeAttr(song.artist)}"
                data-song-album="${escapeAttr(song.album)}"
                data-song-genre="${escapeAttr(song.genre)}"
                data-song-user-id="${song.user_id}">
                <div class="song-indicator-wrapper d-flex align-items-center justify-content-center">
                  <img src="?action=get_image&id=${song.id}&v=${song.last_modified || 0}&size=small" onerror="this.onerror=null; this.src='${coverSvg}';" class="song-thumb" loading="lazy" alt="${escapeAttr(song.title)}">
                  <i class="bi bi-soundwave playing-icon"></i>
                </div>
                <div class="song-title-wrapper text-truncate"><div class="song-title text-truncate">${song.is_private == 1 ? '<i class="bi bi-lock-fill text-warning me-1" title="Private Song"></i>' : ''}${song.title}</div></div>
                <div class="song-artist text-truncate" data-userid="${song.user_id}">
                  <div class="text-truncate">${formatArtistsHTML(song.artist, song.user_id)}</div>
                  <div class="text-secondary d-md-none" style="font-size: 0.8rem; margin-top: 2px;" title="Play Count"><i class="bi bi-eye"></i> ${formatSongCount(song.play_count || 0)}</div>
                </div>
                <div class="song-album text-truncate" data-album="${encodeURIComponent(song.album)}" data-userid="${song.user_id}">${song.album}</div>
                <div class="song-views d-none d-md-block text-truncate" title="${song.play_count || 0} views">${formatSongCount(song.play_count || 0)}</div>
                <div class="song-duration d-none d-md-block">${formatTime(song.duration)}</div>
                <div class="song-more"><button class="more-btn" data-song-id="${song.id}"><i class="bi bi-three-dots-vertical"></i></button></div>
                <div class="song-artist-mobile w-100 flex-column align-items-start">
                  <div class="d-flex justify-content-between align-items-center w-100">
                     <span class="song-artist-name text-truncate flex-grow-1" style="min-width: 0;">${formatArtistsHTML(song.artist, song.user_id)}</span>
                     <span class="song-duration-mobile flex-shrink-0">${formatTime(song.duration)}</span>
                  </div>
                  <div class="text-secondary text-start" style="font-size: 0.8rem; margin-top: 2px;"><i class="bi bi-eye"></i> ${formatSongCount(song.play_count || 0)}</div>
                </div>
              </div>`;
          });
          
          // Append to the queue DOM
          if (queueContainerDesktop && queueContainerDesktop.querySelector('.song-list')) {
            const lst = queueContainerDesktop.querySelector('.song-list');
            lst.insertAdjacentHTML('beforeend', html);
            lst.querySelectorAll('.song-item:not(.v-obs)').forEach(el => { el.classList.add('v-obs'); virtualObserver.observe(el); });
          }
          if (queueContainerMobile && queueContainerMobile.querySelector('.song-list')) {
            const lst = queueContainerMobile.querySelector('.song-list');
            lst.insertAdjacentHTML('beforeend', html);
            lst.querySelectorAll('.song-item:not(.v-obs)').forEach(el => { el.classList.add('v-obs'); virtualObserver.observe(el); });
          }
          
          renderedQueueCount += nextChunkIds.length;
          isQueueLoading = false;

          // Dynamically indicate offline availability for ALL queue items
          caches.open('php-music-offline').then(cache => {
            const addedItems = document.querySelectorAll('#desktop-player-queue-list .song-item:not(.queue-cache-checked), #mobile-player-queue-list .song-item:not(.queue-cache-checked)');
            addedItems.forEach(async item => {
              item.classList.add('queue-cache-checked');
              const sid = item.dataset.songId;
              const req = await cache.match(`?action=get_stream&id=${sid}`, { ignoreSearch: false, ignoreVary: true });
              const titleWrapper = item.querySelector('.song-title-wrapper');
              
              if (!req) {
                // It is NOT offline
                item.classList.add('offline-missing');
                if (!navigator.onLine) {
                  item.style.transition = 'opacity 0.3s ease';
                  item.style.opacity = '0.4';
                }
                if (titleWrapper && !titleWrapper.querySelector('.offline-status-icon')) {
                   titleWrapper.insertAdjacentHTML('beforeend', ' <i class="bi bi-cloud-slash text-secondary offline-status-icon ms-1" title="Not saved offline" style="font-size: 0.85rem;"></i>');
                }
              } else {
                // It IS offline
                item.classList.remove('offline-missing');
                item.style.opacity = '1';
                if (titleWrapper && !titleWrapper.querySelector('.offline-status-icon')) {
                   titleWrapper.insertAdjacentHTML('beforeend', ' <i class="bi bi-cloud-check-fill text-success offline-status-icon ms-1" title="Available offline" style="font-size: 0.85rem;"></i>');
                }
              }
            });
          });
          
          // Focus the playing song if it was a total reset
          if (reset && currentSong) {
            if (typeof window.enforceScrollToActive === 'function') {
              window.enforceScrollToActive('dp-queue-pane', 'desktop-player-queue-list', true);
              window.enforceScrollToActive('mp-queue-pane', 'mobile-player-queue-list', true);
            }
          }
        };

        const playerArtDesktop = document.getElementById('player-art-desktop');
        if (playerArtDesktop) {
          playerArtDesktop.addEventListener('click', () => {
            if (currentSong && desktopPlayerModal) {
              renderDesktopLyrics();
              renderQueue();
              desktopPlayerModal.show();
            }
          });
        }

        // Attach click events to BOTH desktop and mobile Up Next queues
        ['desktop-player-queue-list', 'mobile-player-queue-list'].forEach(qId => {
          const queueList = document.getElementById(qId);
          if (queueList) {
            queueList.addEventListener('click', e => {
              
              const moreBtn = e.target.closest('.more-btn');
              if (moreBtn) {
                e.preventDefault(); e.stopPropagation();
                showSongItemContextMenu(moreBtn);
                return;
              }
              
              const songArtistEl = e.target.closest('.artist-link, .song-artist, .song-artist-name');
              if (songArtistEl) {
                e.stopPropagation();
                 
                const songItem = e.target.closest('.song-item');
                const artistRaw = songItem ? songItem.getAttribute('data-song-artist') : (songArtistEl.dataset.artist ? decodeURIComponent(songArtistEl.dataset.artist) : songArtistEl.textContent.trim());
                const userId = songArtistEl.dataset.userid || (songItem ? songItem.getAttribute('data-song-user-id') : '') || '';
                 
                const artistsList = artistRaw.split(/\s*(?:;|\||\s\/\s|\s&\s|\sfeat\.?\s|\sft\.?\s|\sfeaturing\s)\s*|,\s+(?!(?:the|a|an|jr|sr)\b)/i).filter(a => a && a.trim() !== '');
                if (artistsList.length > 1) {
                  // Keep the player modal open, simply display the choices popup on top
                  if (artistsModalBody) {
                    const modalTitle = artistsModalEl.querySelector('.modal-title');
                    if (modalTitle) modalTitle.textContent = 'Artists';
                    artistsModalBody.innerHTML = `
                      <div class="list-group list-group-flush rounded">
                        ${artistsList.map(a => `<button type="button" class="list-group-item list-group-item-action bg-transparent text-white border-secondary artist-modal-item py-3" data-artist="${encodeURIComponent(a)}">${a}</button>`).join('')}
                      </div>
                    `;
                    if (artistsModal) artistsModal.show();
                  }
                } else {
                  // Only one artist exists: Close the player modals and navigate directly
                  closeOpenModals();
                  loadView({ type: 'artist_songs', param: artistRaw, sort: 'album_asc', filter_user_id: userId });
                }
                return;
              }

              const songAlbumEl = e.target.closest('.song-album');
              if (songAlbumEl) {
                e.stopPropagation();
                if (desktopPlayerModal) desktopPlayerModal.hide();
                if (playerModal) playerModal.hide();
                const songItem = e.target.closest('.song-item');
                
                let rawUserId = songAlbumEl.getAttribute('data-userid') || (songItem ? (songItem.getAttribute('data-userid') || songItem.getAttribute('data-song-user-id')) : '') || '';
                let validUserId = parseInt(rawUserId, 10);
                
                let albumRaw = decodeURIComponent(songAlbumEl.getAttribute('data-album') || '');
                let songArtistRaw = songItem ? (songItem.getAttribute('data-song-artist') || '') : '';
                const songArtistsList = songArtistRaw.split(/\s*(?:;|\||\s\/\s|\s&\s|\sfeat\.?\s|\sft\.?\s|\sfeaturing\s)\s*|,\s+(?!(?:the|a|an|jr|sr)\b)/i).filter(a => a && a.trim() !== '');

                if (songArtistsList.length > 1) {
                  if (artistsModalBody) {
                    const modalTitle = artistsModalEl.querySelector('.modal-title');
                    if (modalTitle) modalTitle.textContent = 'Select Album Artist';
                    artistsModalBody.innerHTML = `
                      <div class="list-group list-group-flush rounded">
                        ${songArtistsList.map(a => `<button type="button" class="list-group-item list-group-item-action bg-transparent text-white border-secondary album-modal-item py-3" data-album="${encodeURIComponent(albumRaw)}" data-artist="${encodeURIComponent(a)}" data-userid="${rawUserId}">${escapeHTML(albumRaw)} (${escapeHTML(a)})</button>`).join('')}
                      </div>
                    `;
                    if (artistsModal) artistsModal.show();
                  }
                } else {
                  loadView({ 
                    type: 'album_songs', 
                    param: albumRaw, 
                    sort: 'title_asc', 
                    filter_user_id: (isNaN(validUserId) || validUserId <= 0) ? '' : validUserId,
                    artist_name: songArtistRaw
                  });
                }
                return;
              }

              const songItem = e.target.closest('.song-item');
              if (songItem) {
                const songId = parseInt(songItem.dataset.songId);
                const idx = queue.findIndex(id => id === songId);
                if (idx !== -1) {
                   queueIndex = idx;
                   playSongById(songId);
                } else {
                   setQueueAndPlay(songId);
                }
              }
            });
          }
        });

        const desktopLyricsContainer = document.getElementById('desktop-player-modal-lyrics-container');
        if (desktopLyricsContainer) {
          desktopLyricsContainer.addEventListener('click', (e) => {
            const line = e.target.closest('.lyric-line');
            if (line && currentSong && currentSong.id === currentLrcSongId && audio) {
              audio.currentTime = parseFloat(line.dataset.time);
            }
          });
        }

        const audio = new Audio();
        audio.crossOrigin = 'anonymous'; // CRITICAL: Unlocks Web Audio API effects like Equalizer
        const audioB = new Audio();
        audioB.crossOrigin = 'anonymous';
        
        let audioCtx, sourceA, sourceB, gainA, gainB, perSongGain, compressor, analyser;
        let visualizerDataArray;
        let eqBands = [];
        let spatialPanner, spatialBypass, spatialMix;
        let enableNormalization = true;
        let isEQEnabled = false;
        let isSpatialEnabled = false;
        let globalVolumeMultiplier = 1.0;
        let globalEQBands = [0, 0, 0, 0, 0];
        let crossfadeDuration = 3.0;
        let settingsSaveTimeout = null;

        const EQ_PRESETS = {
          'Flat': [0, 0, 0, 0, 0],
          'Rock': [5, 3, -2, 4, 6],
          'Jazz': [4, 2, -2, 2, 5],
          'Classical': [5, 3, -2, 4, 4],
          'Pop': [-2, 2, 5, 2, -2],
          'Bass Boost': [8, 5, 0, 0, 0]
        };

        const saveGlobalAudioSettings = async () => {
          if (!currentUser) return;
          clearTimeout(settingsSaveTimeout);
          settingsSaveTimeout = setTimeout(async () => {
            try {
               const settings = { 
                  enableNormalization: enableNormalization, 
                  isEQEnabled: isEQEnabled, 
                  isSpatialEnabled: isSpatialEnabled, 
                  globalVolumeMultiplier: parseFloat(globalVolumeMultiplier), 
                  globalEQBands: globalEQBands.map(b => parseFloat(b)), 
                  crossfadeDuration: parseFloat(crossfadeDuration) 
               };
               
               const response = await fetchData('?action=save_global_settings', {
                 method: 'POST', headers: {'Content-Type': 'application/json'},
                 body: JSON.stringify({ settings: settings })
               });
               
               if (response && response.status === 'success') {
                  // Update the local current user memory so it doesn't revert on next checkSession
                  currentUser.settings = JSON.stringify(settings);
               }
            } catch(e) {
               console.error("Failed to save audio settings", e);
            }
          }, 800); // 800ms debounce
        };

        const initWebAudio = () => {
          if (audioCtx) return;
          audioCtx = new (window.AudioContext || window.webkitAudioContext)();
          
          const freqs = [60, 230, 910, 3600, 14000];
          let prevNode = null;
          freqs.forEach((freq, i) => {
            let band = audioCtx.createBiquadFilter();
            band.type = i === 0 ? "lowshelf" : (i === freqs.length - 1 ? "highshelf" : "peaking");
            band.frequency.value = freq;
            band.gain.value = 0;
            eqBands.push(band);
            if (prevNode) prevNode.connect(band);
            prevNode = band;
          });

          compressor = audioCtx.createDynamicsCompressor();
          compressor.threshold.value = -24; 
          compressor.knee.value = 30;
          compressor.ratio.value = 12;      
          compressor.attack.value = 0.003;
          compressor.release.value = 0.25;
          
          spatialPanner = audioCtx.createPanner();
          spatialPanner.panningModel = 'HRTF';
          spatialPanner.distanceModel = 'inverse';
          if (spatialPanner.positionZ) spatialPanner.positionZ.value = 1.0;
          else spatialPanner.setPosition(0, 0, 1.0);
          
          spatialBypass = audioCtx.createGain();
          spatialMix = audioCtx.createGain();
          
          eqBands[eqBands.length - 1].connect(spatialBypass);
          eqBands[eqBands.length - 1].connect(spatialPanner);
          
          spatialBypass.connect(compressor);
          spatialPanner.connect(spatialMix);
          spatialMix.connect(compressor);

          analyser = audioCtx.createAnalyser();
          analyser.fftSize = 128;
          visualizerDataArray = new Uint8Array(analyser.frequencyBinCount);
          compressor.connect(analyser);
          analyser.connect(audioCtx.destination);

          sourceA = audioCtx.createMediaElementSource(audio);
          sourceB = audioCtx.createMediaElementSource(audioB);
          gainA = audioCtx.createGain();
          gainB = audioCtx.createGain();
          perSongGain = audioCtx.createGain();
          perSongGain.gain.value = 1;
          
          sourceA.connect(gainA);
          sourceB.connect(gainB);
          gainA.connect(perSongGain);
          gainB.connect(perSongGain);
          perSongGain.connect(eqBands[0]);
          
          toggleAudioEnhancements();
        };

        const applyAudioSettings = () => {
          if (!audioCtx || !currentSong) return;
          
          let targetVol = parseFloat(globalVolumeMultiplier);
          let targetEQ = globalEQBands.map(v => parseFloat(v) || 0);

          if (currentSong.replaygain && enableNormalization) {
            const rgLinear = Math.pow(10, parseFloat(currentSong.replaygain) / 20);
            targetVol *= Math.max(0.1, Math.min(rgLinear, 3.0));
          }

          if (currentSong.volume_multiplier !== null && currentSong.volume_multiplier !== undefined) {
            targetVol = parseFloat(currentSong.volume_multiplier);
          }
          
          if (currentSong.eq_bands) {
            try {
              const parsedEq = typeof currentSong.eq_bands === 'string' ? JSON.parse(currentSong.eq_bands) : currentSong.eq_bands;
              if (Array.isArray(parsedEq) && parsedEq.length === 5) {
                targetEQ = parsedEq.map(v => parseFloat(v) || 0);
              }
            } catch (err) {
              console.error("EQ Parse Error:", err);
            }
          } else if (!isEQEnabled) {
            targetEQ = [0, 0, 0, 0, 0];
          }

          if (audioCtx.state === 'suspended') {
            audioCtx.resume();
          }

          setTimeout(() => {
            if (perSongGain && perSongGain.gain) {
              perSongGain.gain.setTargetAtTime(targetVol, audioCtx.currentTime, 0.05);
            }
            eqBands.forEach((band, i) => {
              if (band && band.gain) {
                band.gain.setTargetAtTime(targetEQ[i], audioCtx.currentTime, 0.05);
              }
            });
          }, 50);
        };

        const toggleAudioEnhancements = () => {
          if (!audioCtx) return;
          compressor.ratio.value = enableNormalization ? 12 : 1; 
          
          // Direct value assignment to avoid context freezing bugs
          spatialBypass.gain.value = isSpatialEnabled ? 0 : 1;
          spatialMix.gain.value = isSpatialEnabled ? 1 : 0;

          applyAudioSettings();
        };

        // UI Event Listeners for Global Audio Settings
        document.getElementById('toggle-spatial').addEventListener('change', (e) => {
          isSpatialEnabled = e.target.checked;
          toggleAudioEnhancements();
          saveGlobalAudioSettings();
        });
        document.getElementById('global-vol-slider').addEventListener('input', (e) => {
          globalVolumeMultiplier = parseFloat(e.target.value);
          document.getElementById('global-vol-val').textContent = globalVolumeMultiplier + 'x';
          applyAudioSettings();
          saveGlobalAudioSettings();
        });

        document.getElementById('toggle-normalization').addEventListener('change', (e) => {
          enableNormalization = e.target.checked;
          toggleAudioEnhancements();
          saveGlobalAudioSettings();
        });

        document.getElementById('toggle-eq').addEventListener('change', (e) => {
