            }
          });
        }

        // --- BACKGROUND GENERATOR LOGIC ---
        const bgCanvas = document.getElementById('bg-gen-canvas');
        if (bgCanvas) {
          const bgCtx = bgCanvas.getContext('2d');
          const bgState = { pattern: 'blobs', hue: Math.floor(Math.random()*360), saturation: 70, complexity: 5, scale: 100, angle: 0, drawStyle: 'fill', seed: Math.random() };
          let bgRng = null;

          function bgMulberry32(a) {
            return function() {
              var t = a += 0x6D2B79F5; t = Math.imul(t ^ t >>> 15, t | 1);
              t ^= t + Math.imul(t ^ t >>> 7, t | 61); return ((t ^ t >>> 14) >>> 0) / 4294967296;
            }
          }
          function bgGetHsl(h, s, l, a = 1) { return `hsla(${h}, ${s}%, ${l}%, ${a})`; }
          function bgGetPalette() {
            const h = bgState.hue; const s = bgState.saturation;
            return [
                bgGetHsl(h, s, 40), bgGetHsl(h, s*0.6, 30), bgGetHsl((h + 40) % 360, s*0.8, 40), 
                bgGetHsl((h - 40 + 360) % 360, s*0.8, 40), bgGetHsl(h, s, 80, 0.7)
            ];
          }
          function bgApplyStyle(color) {
            bgCtx.fillStyle = color; bgCtx.strokeStyle = color;
            bgCtx.lineWidth = Math.max(1, (bgState.scale / 100) * 15 / (bgState.complexity * 0.5));
            bgCtx.lineCap = 'round'; bgCtx.lineJoin = 'round';
          }
          function bgDrawPath() {
            if (bgState.drawStyle === 'fill') bgCtx.fill();
            else if (bgState.drawStyle === 'stroke') bgCtx.stroke();
            else { if (bgRng() > 0.5) bgCtx.fill(); else bgCtx.stroke(); }
          }

          const bgDrawFns = {
            blobs: (b, pal) => {
              const count = bgState.complexity * 3; const baseSize = (b.w * (bgState.scale / 100)) / 4;
              for (let i = 0; i < count; i++) {
                const cx = b.x + bgRng() * b.w; const cy = b.y + bgRng() * b.h; const size = baseSize * (0.5 + bgRng());
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]);
                bgCtx.beginPath(); const points = 5 + Math.floor(bgRng() * 3); let angle = 0;
                for(let j=0; j<=points; j++) {
                  const r = size * (0.6 + bgRng() * 0.4); const x = cx + Math.cos(angle) * r; const y = cy + Math.sin(angle) * r;
                  if (j === 0) bgCtx.moveTo(x, y); else {
                      const cp1x = cx + Math.cos(angle - Math.PI/points) * size; const cp1y = cy + Math.sin(angle - Math.PI/points) * size;
                      bgCtx.quadraticCurveTo(cp1x, cp1y, x, y);
                  }
                  angle += (Math.PI * 2) / points;
                }
                bgDrawPath();
              }
            },
            geometric: (b, pal) => {
              const count = bgState.complexity * 5; const baseSize = (b.w * (bgState.scale / 100)) / 6;
              for (let i = 0; i < count; i++) {
                  const x = b.x + bgRng() * b.w; const y = b.y + bgRng() * b.h; const size = baseSize * (0.2 + bgRng());
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]);
                  const type = Math.floor(bgRng() * 3);
                  bgCtx.save(); bgCtx.translate(x, y); bgCtx.rotate(bgRng() * Math.PI * 2); bgCtx.beginPath();
                  if (type === 0) bgCtx.arc(0, 0, size, 0, Math.PI * 2); else if (type === 1) bgCtx.arc(0, 0, size, 0, Math.PI);
                  else { const rw = size * 2; const rh = size * 0.5; bgCtx.roundRect(-rw/2, -rh/2, rw, rh, rh/2); }
                  bgDrawPath(); bgCtx.restore();
              }
            },
            mesh: (b, pal) => {
              const count = bgState.complexity * 2; const baseSize = b.w * (bgState.scale / 100) * 0.8;
              for (let i = 0; i < count; i++) {
                  const cx = b.x + bgRng() * b.w; const cy = b.y + bgRng() * b.h; const size = baseSize * (0.5 + bgRng());
                  const cBase = pal[Math.floor(bgRng() * pal.length)];
                  const grad = bgCtx.createRadialGradient(cx, cy, 0, cx, cy, size);
                  grad.addColorStop(0, cBase.replace(/[\d\.]+\)$/, '1)')); grad.addColorStop(1, cBase.replace(/[\d\.]+\)$/, '0)'));
                  bgCtx.fillStyle = grad; bgCtx.globalCompositeOperation = 'screen';
                  bgCtx.fillRect(cx - size, cy - size, size * 2, size * 2); bgCtx.globalCompositeOperation = 'source-over';
              }
            },
            waves: (b, pal) => {
              const count = bgState.complexity * 3; const sp = b.h / count; const amp = (bgState.scale / 100) * 200;
              for (let i = 0; i <= count; i++) {
                  bgApplyStyle(pal[i % pal.length]); bgCtx.beginPath(); bgCtx.moveTo(b.x, b.y + b.h); bgCtx.lineTo(b.x, b.y + i * sp + (bgRng() * 50));
                  const pts = 5; const step = b.w / pts; let cx = b.x; let cy = b.y + i * sp;
                  for(let j=0; j<pts; j++) {
                      const nX = cx + step; const nY = cy + (bgRng() > 0.5 ? 1 : -1) * amp * bgRng();
                      bgCtx.bezierCurveTo(cx + step/2, cy, nX - step/2, nY, nX, nY); cx = nX; cy = nY;
                  }
                  bgCtx.lineTo(b.x + b.w, b.y + b.h); bgDrawPath();
              }
            },
            stripes: (b, pal) => {
              const w = (bgState.scale / 100) * 100; const gap = w * (10 / bgState.complexity);
              for(let x = b.x; x < b.x + b.w * 2; x += (w + gap)) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.rect(x - b.w, b.y, w, b.h); bgDrawPath(); }
            },
            dots: (b, pal) => {
              const sp = (bgState.scale / 100) * 100 + 20; const rad = sp * (bgState.complexity / 20);
              for(let y = b.y; y < b.y + b.h; y += sp) { for(let x = b.x; x < b.x + b.w; x += sp) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.arc(x + (bgRng()*sp*0.2), y + (bgRng()*sp*0.2), rad * (0.5+bgRng()), 0, Math.PI*2); bgDrawPath(); } }
            },
            particles: (b, pal) => {
              const count = bgState.complexity * 10; const pts = []; for(let i=0; i<count; i++) pts.push({ x: b.x + bgRng()*b.w, y: b.y + bgRng()*b.h, c: pal[Math.floor(bgRng()*pal.length)] });
              const cDist = (bgState.scale / 100) * 300; bgCtx.lineWidth = 2;
              for(let i=0; i<pts.length; i++) {
                  for(let j=i+1; j<pts.length; j++) {
                      const d = Math.hypot(pts[i].x - pts[j].x, pts[i].y - pts[j].y);
                      if (d < cDist) { bgCtx.strokeStyle = pts[i].c; bgCtx.globalAlpha = 1 - (d/cDist); bgCtx.beginPath(); bgCtx.moveTo(pts[i].x, pts[i].y); bgCtx.lineTo(pts[j].x, pts[j].y); bgCtx.stroke(); bgCtx.globalAlpha = 1; }
                  }
                  bgApplyStyle(pts[i].c); bgCtx.beginPath(); bgCtx.arc(pts[i].x, pts[i].y, 5 + bgRng()*10, 0, Math.PI*2); bgDrawPath();
              }
            },
            triangles: (b, pal) => {
              const step = (bgState.scale / 100) * 150 + 20;
              for(let y = b.y; y < b.y + b.h; y += step) { for(let x = b.x; x < b.x + b.w; x += step) { if (bgRng() > bgState.complexity/10) continue; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.moveTo(x + bgRng()*step, y + bgRng()*step); bgCtx.lineTo(x + step + bgRng()*step, y + bgRng()*step); bgCtx.lineTo(x + bgRng()*step, y + step + bgRng()*step); bgCtx.closePath(); bgDrawPath(); } }
            },
            rays: (b, pal) => {
              const count = bgState.complexity * 8; const rad = b.w; 
              for(let i=0; i<count; i++) { bgApplyStyle(pal[i % pal.length]); const a1 = (i / count) * Math.PI * 2; const a2 = ((i + (bgRng()*0.5 + 0.5)) / count) * Math.PI * 2; bgCtx.beginPath(); bgCtx.moveTo(0, 0); bgCtx.lineTo(Math.cos(a1) * rad, Math.sin(a1) * rad); bgCtx.lineTo(Math.cos(a2) * rad, Math.sin(a2) * rad); bgCtx.closePath(); bgDrawPath(); }
            },
            squares: (b, pal) => {
              const count = bgState.complexity * 5; for (let i = 0; i < count; i++) { const s = (bgState.scale / 100) * 200 * (0.2 + bgRng()); const x = b.x + bgRng() * b.w; const y = b.y + bgRng() * b.h; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.rect(x-s/2, y-s/2, s, s); bgDrawPath(); }
            },
            hexagons: (b, pal) => {
              const r = (bgState.scale / 100) * 50 + 10; const dx = r * Math.sqrt(3); const dy = r * 1.5; let row = 0;
              for(let y = b.y; y < b.y + b.h + r; y += dy) { let offset = (row % 2 === 0) ? 0 : dx / 2; for(let x = b.x; x < b.x + b.w + r; x += dx) { if (bgRng() > (bgState.complexity / 10)) continue; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); for (let i = 0; i < 6; i++) { const angle = i * Math.PI / 3 + Math.PI/6; const px = x + offset + r * Math.cos(angle); const py = y + r * Math.sin(angle); if (i === 0) bgCtx.moveTo(px, py); else bgCtx.lineTo(px, py); } bgCtx.closePath(); bgDrawPath(); } row++; }
            },
            concentric: (b, pal) => {
              const count = bgState.complexity * 2; const maxR = (bgState.scale / 100) * 300;
              for(let i=0; i<count; i++) { const cx = b.x + bgRng() * b.w; const cy = b.y + bgRng() * b.h; const rings = 3 + Math.floor(bgRng()*5); for(let r=rings; r>0; r--) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.arc(cx, cy, (r/rings)*maxR, 0, Math.PI*2); bgDrawPath(); } }
            },
            noise: (b, pal) => {
              const size = Math.max(5, (bgState.scale / 100) * 30); const den = bgState.complexity * 0.08; 
              for(let y = b.y; y < b.y + b.h; y += size) { for(let x = b.x; x < b.x + b.w; x += size) { if (bgRng() < den) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.rect(x, y, size, size); bgDrawPath(); } } }
            },
            scribble: (b, pal) => {
              const count = bgState.complexity * 3; for(let i=0; i<count; i++) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); let cx = b.x + bgRng() * b.w; let cy = b.y + bgRng() * b.h; bgCtx.moveTo(cx, cy); const segs = 20 + bgRng() * 50; const jump = (bgState.scale / 100) * 100; for(let j=0; j<segs; j++) { cx += (bgRng() - 0.5) * jump; cy += (bgRng() - 0.5) * jump; bgCtx.lineTo(cx, cy); } bgCtx.stroke(); }
            },
            diamonds: (b, pal) => {
              const size = (bgState.scale / 100) * 60 + 10; for(let y = b.y; y < b.y + b.h; y += size) { for(let x = b.x; x < b.x + b.w; x += size) { if (bgRng() > (bgState.complexity / 10)) continue; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save(); bgCtx.translate(x, y); bgCtx.rotate(Math.PI/4); bgCtx.beginPath(); bgCtx.rect(-size/2, -size/2, size, size); bgDrawPath(); bgCtx.restore(); } }
            },
            checkers: (b, pal) => {
              const size = (bgState.scale / 100) * 60 + 10; for(let y = b.y; y < b.y + b.h; y += size) { for(let x = b.x; x < b.x + b.w; x += size) { if (bgRng() > (bgState.complexity / 10)) continue; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.rect(x, y, size, size); bgDrawPath(); } }
            },
            maze: (b, pal) => {
              const step = (bgState.scale / 100) * 40 + 10; bgCtx.lineWidth = step * (bgState.complexity / 20) + 2; bgCtx.lineCap = 'round';
              for(let y = b.y; y < b.y + b.h; y += step) { for(let x = b.x; x < b.x + b.w; x += step) { bgCtx.strokeStyle = pal[Math.floor(bgRng() * pal.length)]; bgCtx.beginPath(); if (bgRng() > 0.5) { bgCtx.moveTo(x, y); bgCtx.lineTo(x + step, y + step); } else { bgCtx.moveTo(x + step, y); bgCtx.lineTo(x, y + step); } bgCtx.stroke(); } }
            },
            lines: (b, pal) => {
              const count = bgState.complexity * 10; const len = (bgState.scale / 100) * 300; for(let i=0; i<count; i++) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); const x = b.x + bgRng() * b.w; const y = b.y + bgRng() * b.h; bgCtx.moveTo(x, y); if (bgRng() > 0.5) bgCtx.lineTo(x + len * (bgRng()>0.5?1:-1), y); else bgCtx.lineTo(x, y + len * (bgRng()>0.5?1:-1)); bgCtx.stroke(); }
            },
            crosses: (b, pal) => {
              const step = (bgState.scale / 100) * 80 + 20; const size = step * (bgState.complexity / 15); bgCtx.lineWidth = size * 0.3;
              for(let y = b.y; y < b.y + b.h; y += step) { for(let x = b.x; x < b.x + b.w; x += step) { if (bgRng() > 0.8) continue; bgCtx.strokeStyle = pal[Math.floor(bgRng() * pal.length)]; bgCtx.beginPath(); bgCtx.moveTo(x - size/2, y); bgCtx.lineTo(x + size/2, y); bgCtx.moveTo(x, y - size/2); bgCtx.lineTo(x, y + size/2); bgCtx.stroke(); } }
            },
            spirals: (b, pal) => {
              const count = bgState.complexity * 2; const maxR = (bgState.scale / 100) * 150; for(let i=0; i<count; i++) { const cx = b.x + bgRng() * b.w; const cy = b.y + bgRng() * b.h; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); let loops = 2 + bgRng() * 4; for(let a=0; a<Math.PI * 2 * loops; a+=0.1) { const r = (a / (Math.PI*2)) * (maxR / loops); const x = cx + Math.cos(a) * r; const y = cy + Math.sin(a) * r; if (a===0) bgCtx.moveTo(x,y); else bgCtx.lineTo(x,y); } bgDrawPath(); }
            }
          };

          const bgShapes = {
            circle: (s) => { bgCtx.arc(0, 0, s, 0, Math.PI*2); },
            square: (s) => { bgCtx.rect(-s/2, -s/2, s, s); },
            diamond: (s) => { bgCtx.moveTo(0, -s); bgCtx.lineTo(s, 0); bgCtx.lineTo(0, s); bgCtx.lineTo(-s, 0); bgCtx.closePath(); },
            triangle: (s) => { bgCtx.moveTo(0, -s*0.8); bgCtx.lineTo(s*0.866, s*0.6); bgCtx.lineTo(-s*0.866, s*0.6); bgCtx.closePath(); },
            star: (s) => { for(let i=0;i<10;i++){ const r = i%2===0?s:s/2; const a = i*Math.PI/5 - Math.PI/2; if (i===0)bgCtx.moveTo(Math.cos(a)*r,Math.sin(a)*r); else bgCtx.lineTo(Math.cos(a)*r,Math.sin(a)*r); } bgCtx.closePath(); },
            cross: (s) => { const q=s/3; bgCtx.moveTo(-s,-q); bgCtx.lineTo(-q,-q); bgCtx.lineTo(-q,-s); bgCtx.lineTo(q,-s); bgCtx.lineTo(q,-q); bgCtx.lineTo(s,-q); bgCtx.lineTo(s,q); bgCtx.lineTo(q,q); bgCtx.lineTo(q,s); bgCtx.lineTo(-q,s); bgCtx.lineTo(-q,q); bgCtx.lineTo(-s,q); bgCtx.closePath(); },
            hexagon: (s) => { for(let i=0;i<6;i++){ const a = i*Math.PI/3; if (i===0)bgCtx.moveTo(s*Math.cos(a),s*Math.sin(a)); else bgCtx.lineTo(s*Math.cos(a),s*Math.sin(a)); } bgCtx.closePath(); },
            pentagon: (s) => { for(let i=0;i<5;i++){ const a = i*Math.PI*2/5 - Math.PI/2; if (i===0)bgCtx.moveTo(s*Math.cos(a),s*Math.sin(a)); else bgCtx.lineTo(s*Math.cos(a),s*Math.sin(a)); } bgCtx.closePath(); },
            octagon: (s) => { for(let i=0;i<8;i++){ const a = i*Math.PI/4 - Math.PI/8; if (i===0)bgCtx.moveTo(s*Math.cos(a),s*Math.sin(a)); else bgCtx.lineTo(s*Math.cos(a),s*Math.sin(a)); } bgCtx.closePath(); },
            ring: (s) => { bgCtx.arc(0, 0, s, 0, Math.PI*2); bgCtx.moveTo(s*0.7,0); bgCtx.arc(0, 0, s*0.7, 0, Math.PI*2, true); },
            heart: (s) => { const x=0, y=0; bgCtx.moveTo(x, y+s/3); bgCtx.bezierCurveTo(x, y-s/2, x-s, y-s/2, x-s, y); bgCtx.bezierCurveTo(x-s, y+s/2, x, y+s*0.8, x, y+s); bgCtx.bezierCurveTo(x, y+s*0.8, x+s, y+s/2, x+s, y); bgCtx.bezierCurveTo(x+s, y-s/2, x, y-s/2, x, y+s/3); },
            moon: (s) => { bgCtx.arc(0, 0, s, 0, Math.PI*2); bgCtx.arc(s*0.3, -s*0.3, s*0.8, 0, Math.PI*2, true); },
            spade: (s) => { bgCtx.moveTo(0, s*0.2); bgCtx.bezierCurveTo(s, s*0.2, s, -s, 0, -s); bgCtx.bezierCurveTo(-s, -s, -s, s*0.2, 0, s*0.2); bgCtx.moveTo(0, 0); bgCtx.lineTo(-s*0.3, s); bgCtx.lineTo(s*0.3, s); bgCtx.closePath(); },
            club: (s) => { bgCtx.arc(0, -s*0.5, s*0.4, 0, Math.PI*2); bgCtx.arc(-s*0.4, s*0.2, s*0.4, 0, Math.PI*2); bgCtx.arc(s*0.4, s*0.2, s*0.4, 0, Math.PI*2); bgCtx.moveTo(0, 0); bgCtx.lineTo(-s*0.2, s); bgCtx.lineTo(s*0.2, s); bgCtx.closePath(); },
            leaf: (s) => { bgCtx.moveTo(0, -s); bgCtx.quadraticCurveTo(s, 0, 0, s); bgCtx.quadraticCurveTo(-s, 0, 0, -s); },
            shield: (s) => { bgCtx.moveTo(-s, -s*0.8); bgCtx.lineTo(s, -s*0.8); bgCtx.quadraticCurveTo(s, s*0.5, 0, s); bgCtx.quadraticCurveTo(-s, s*0.5, -s, -s*0.8); },
            gem: (s) => { bgCtx.moveTo(-s*0.6, -s); bgCtx.lineTo(s*0.6, -s); bgCtx.lineTo(s, -s*0.2); bgCtx.lineTo(0, s); bgCtx.lineTo(-s, -s*0.2); bgCtx.closePath(); },
            droplet: (s) => { bgCtx.moveTo(0, -s); bgCtx.quadraticCurveTo(s, 0, s, s*0.4); bgCtx.arc(0, s*0.4, s, 0, Math.PI); bgCtx.quadraticCurveTo(-s, 0, 0, -s); },
            burst: (s) => { for(let i=0;i<16;i++){ const r = i%2===0?s:s*0.3; const a = i*Math.PI/8; if (i===0)bgCtx.moveTo(Math.cos(a)*r,Math.sin(a)*r); else bgCtx.lineTo(Math.cos(a)*r,Math.sin(a)*r); } bgCtx.closePath(); },
            sparkle: (s) => { for(let i=0;i<8;i++){ const r = i%2===0?s:s*0.1; const a = i*Math.PI/4; if (i===0)bgCtx.moveTo(Math.cos(a)*r,Math.sin(a)*r); else bgCtx.lineTo(Math.cos(a)*r,Math.sin(a)*r); } bgCtx.closePath(); },
            clover: (s) => { for(let i=0; i<4; i++){ const a=i*Math.PI/2; bgCtx.arc(Math.cos(a)*s*0.5, Math.sin(a)*s*0.5, s*0.5, 0, Math.PI*2); } },
            flower: (s) => { for(let i=0; i<6; i++){ const a=i*Math.PI/3; bgCtx.arc(Math.cos(a)*s*0.6, Math.sin(a)*s*0.6, s*0.4, 0, Math.PI*2); } bgCtx.arc(0,0,s*0.3,0,Math.PI*2); }
          };

          const bgLayouts = {
            scatter: (b, pal, shapeFn) => {
              const count = bgState.complexity * 12; const baseSize = (b.w * (bgState.scale / 100)) / 15;
              for(let i=0;i<count;i++){ 
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(b.x+bgRng()*b.w, b.y+bgRng()*b.h); bgCtx.rotate(bgRng()*Math.PI*2);
                bgCtx.beginPath(); shapeFn(baseSize * (0.3+bgRng())); bgDrawPath(); bgCtx.restore();
              }
            },
            grid: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 80 + 20; const size = step * (bgState.complexity / 20);
              for(let y=b.y; y<b.y+b.h; y+=step) { for(let x=b.x; x<b.x+b.w; x+=step) {
                if (bgRng() > 0.9) continue;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(x, y); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
              }}
            },
            isometric: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 80 + 20; const size = step * (bgState.complexity / 20); let row=0;
              for(let y=b.y; y<b.y+b.h; y+=step*0.866) { let off=(row%2===0)?0:step/2; for(let x=b.x; x<b.x+b.w; x+=step) {
                if (bgRng() > 0.9) continue;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(x+off, y); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
              } row++;}
            },
            concentric: (b, pal, shapeFn) => {
              const count = bgState.complexity * 3; const maxR = (bgState.scale / 100) * 150;
              for(let i=0;i<count;i++){ 
                const cx=b.x+bgRng()*b.w; const cy=b.y+bgRng()*b.h; const rings=3+Math.floor(bgRng()*5);
                for(let r=rings; r>0; r--) {
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(cx, cy); bgCtx.beginPath(); shapeFn(maxR*(r/rings)); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            radial: (b, pal, shapeFn) => {
              const count = bgState.complexity * 12; const maxR = b.w; const cx=0, cy=0;
              for(let i=0;i<count;i++){ 
                const a = (i/count)*Math.PI*2; const r = bgRng()*maxR;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(cx+Math.cos(a)*r, cy+Math.sin(a)*r); bgCtx.rotate(a + Math.PI/2);
                bgCtx.beginPath(); shapeFn((bgState.scale/100)*40 * (0.5+bgRng())); bgDrawPath(); bgCtx.restore();
              }
            },
            spiral: (b, pal, shapeFn) => {
              const count = bgState.complexity * 15; const maxR = b.w; const cx = b.x + b.w/2; const cy = b.y + b.h/2;
              for(let i=0; i<count; i++) {
                const a = i * 0.5; const r = (i/count) * maxR;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(cx + Math.cos(a)*r, cy + Math.sin(a)*r); bgCtx.rotate(a);
                bgCtx.beginPath(); shapeFn((bgState.scale/100) * 20 * (1 + bgRng())); bgDrawPath(); bgCtx.restore();
              }
            },
            waveGrid: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 60 + 20; const size = step * (bgState.complexity / 20);
              for(let x=b.x; x<b.x+b.w; x+=step) {
                let yOffset = Math.sin(x * 0.05) * 100;
                for(let y=b.y; y<b.y+b.h; y+=step) {
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(x, y + yOffset); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            zigzag: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 60 + 20; const size = step * (bgState.complexity / 20);
              let flip = false;
              for(let y=b.y; y<b.y+b.h; y+=step) {
                flip = !flip;
                for(let x=b.x; x<b.x+b.w; x+=step) {
                  let px = x + (flip ? step/2 : 0);
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(px, y); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            orbit: (b, pal, shapeFn) => {
              const cx = b.x + b.w/2; const cy = b.y + b.h/2; const rings = bgState.complexity; const maxR = b.w;
              for(let r=1; r<=rings; r++) {
                const rad = (r/rings) * maxR; const items = r * 6;
                for(let i=0; i<items; i++) {
                  const a = (i/items) * Math.PI * 2 + (bgRng()*0.5);
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(cx + Math.cos(a)*rad, cy + Math.sin(a)*rad); bgCtx.rotate(a);
                  bgCtx.beginPath(); shapeFn((bgState.scale/100) * 30); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            pyramid: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 60 + 20; const size = step * (bgState.complexity / 20);
              const rows = Math.floor(b.h / step);
              for(let r=0; r<rows; r++) {
                const cols = r + 1; const startX = (b.x + b.w/2) - (cols * step)/2;
                const y = b.y + r * step;
                for(let c=0; c<cols; c++) {
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(startX + c * step, y); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            waterfall: (b, pal, shapeFn) => {
              const cols = bgState.complexity * 5; const stepX = b.w / cols;
              for(let c=0; c<cols; c++) {
                const x = b.x + c * stepX;
                const offset = bgRng() * 1000;
                for(let y=b.y; y<b.y+b.h; y+= (bgState.scale/100)*40) {
                  const px = x + Math.sin((y+offset)*0.02) * 30;
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(px, y); bgCtx.beginPath(); shapeFn((bgState.scale/100) * 15); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            vortex: (b, pal, shapeFn) => {
              const count = bgState.complexity * 12; const maxR = b.w; const cx = b.x + b.w/2; const cy = b.y + b.h/2;
              for(let i=count; i>0; i--) {
                const a = Math.pow(i, 1.1) * 0.2; const r = (i/count) * maxR;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(cx + Math.cos(a)*r, cy + Math.sin(a)*r); bgCtx.rotate(a + Math.PI/4);
                bgCtx.beginPath(); shapeFn((bgState.scale/100) * 40 * (i/count)); bgDrawPath(); bgCtx.restore();
              }
            }
          };

          // Compile all combinatoric variants and merge them into the master drawing function map
          Object.keys(bgLayouts).forEach(layout => {
            Object.keys(bgShapes).forEach(shape => {
              bgDrawFns[`${layout}_${shape}`] = (b, pal) => bgLayouts[layout](b, pal, bgShapes[shape]);
            });
          });

          const drawWallpaper = () => {
            bgRng = bgMulberry32(Math.floor(bgState.seed * 100000));
            const w = 1200; const h = 400;
            bgCanvas.width = w; bgCanvas.height = h;

            bgCtx.fillStyle = bgGetHsl(bgState.hue, bgState.saturation * 0.3, 10);
            bgCtx.fillRect(0, 0, w, h);

            bgCtx.save();
            bgCtx.translate(w/2, h/2);
            bgCtx.rotate(bgState.angle * Math.PI / 180);
            
            const diag = Math.sqrt(w*w + h*h);
            const b = { x: -diag/2, y: -diag/2, w: diag, h: diag };

            if (bgDrawFns[bgState.pattern]) bgDrawFns[bgState.pattern](b, bgGetPalette());
            bgCtx.restore();
          };

          const settingsModalEl = document.getElementById('settings-modal');
          if (settingsModalEl) {
            settingsModalEl.addEventListener('show.bs.modal', () => {
              document.getElementById('bg-gen-hue').value = bgState.hue;
              drawWallpaper();
            });
          }

          document.getElementById('bg-gen-pattern').addEventListener('change', e => { bgState.pattern = e.target.value; drawWallpaper(); });
          document.getElementById('bg-gen-style').addEventListener('change', e => { bgState.drawStyle = e.target.value; drawWallpaper(); });
          document.getElementById('bg-gen-hue').addEventListener('input', e => { bgState.hue = parseInt(e.target.value); drawWallpaper(); });
          
          document.getElementById('bg-gen-random-btn').addEventListener('click', () => {
            bgState.seed = Math.random();
            bgState.hue = Math.floor(Math.random() * 360);
            document.getElementById('bg-gen-hue').value = bgState.hue;
            
            const patterns = Object.keys(bgDrawFns);
            bgState.pattern = patterns[Math.floor(Math.random() * patterns.length)];
            document.getElementById('bg-gen-pattern').value = bgState.pattern;
            
            const styles = ['fill', 'stroke', 'mixed'];
            bgState.drawStyle = styles[Math.floor(Math.random() * styles.length)];
            document.getElementById('bg-gen-style').value = bgState.drawStyle;

            drawWallpaper();
          });

          document.getElementById('bg-gen-save-btn').addEventListener('click', () => {
            bgCanvas.toBlob(async (blob) => {
              const submitBtn = document.getElementById('bg-gen-save-btn');
              submitBtn.disabled = true;
              submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Saving...';
              const formData = new FormData();
              formData.append('profile_background', blob, 'generated_bg.jpg');
              
              try {
                const res = await fetch('?action=upload_profile_background', { method: 'POST', body: formData });
                const result = await res.json();
                showToast(result.message, result.status);
                if (result.status === 'success') {
                   await checkSession();
                   if (currentView.type === 'user_profile') loadView(currentView);
                }
              } catch (err) {
                showToast('Upload failed', 'error');
              }
              submitBtn.disabled = false;
              submitBtn.innerHTML = 'Set Background';
            }, 'image/jpeg', 0.9);
          });
        }

        if (bioForm) {
          bioForm.addEventListener('submit', async e => {
            e.preventDefault();
            const bio = document.getElementById('settings-bio').value;
            const res = await fetchData('?action=save_bio', { method: 'POST', body: JSON.stringify({ bio }) });
            if (res && res.status === 'success') {
              showToast(res.message, 'success');
              await checkSession();
              if (currentView.type === 'user_profile') loadView(currentView);
            }
          });
        }

        changeNameForm.addEventListener('submit', async e => {
          e.preventDefault();
          const new_name = document.getElementById('new-name').value;
          const data = await fetchData('?action=change_name', {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ new_name })
          });
          if (data && data.status === 'success') {
            bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
            changeNameForm.reset();
            showToast(data.message, 'success');
            await checkSession();
            if (currentView.type === 'user_profile') loadView(currentView);
          }
        });

        changePwForm.addEventListener('submit', async e => {
          e.preventDefault();
          const new_password = document.getElementById('new-password').value;
          const data = await fetchData('?action=change_password', {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ new_password })
          });
          if (data && data.status === 'success') {
            bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
            changePwForm.reset();
            showToast(data.message, 'success');
          }
        });
        
        let profileCropper = null;
        let groupCropper = null;
        const profilePicInput = document.getElementById('profile-picture-input');
        const profilePicPreview = document.getElementById('profile-picture-preview');
        const presetContainer = document.getElementById('preset-avatar-container');
        const refreshPresetsBtn = document.getElementById('refresh-presets-btn');
        const groupPicInput = document.getElementById('group-manage-image');
        const groupPicPreview = document.getElementById('group-manage-image-preview');
        const groupPresetContainer = document.getElementById('group-preset-avatar-container');

        const loadPresets = (targetContainer, isGroup = false) => {
          if (!targetContainer || typeof multiavatar === 'undefined') return;
          targetContainer.innerHTML = '';
          for (let i = 0; i < 6; i++) {
            const seed = Math.random().toString(36).substring(2, 8);
            const svgCode = multiavatar(seed);
            const blob = new Blob([svgCode], {type: 'image/svg+xml'});
            const url = URL.createObjectURL(blob);
            
            const img = document.createElement('img');
            img.src = url;
            img.className = 'rounded-circle shadow-sm';
            img.style.width = '55px';
            img.style.height = '55px';
            img.style.cursor = 'pointer';
            img.style.border = '2px solid transparent';
            img.style.transition = 'transform 0.2s, border-color 0.2s';
            img.style.flexShrink = '0';
            
            img.addEventListener('mouseover', () => img.style.transform = 'scale(1.1)');
            img.addEventListener('mouseout', () => img.style.transform = 'scale(1)');
            
            img.addEventListener('click', () => {
              if (isGroup) {
                groupPicPreview.src = url;
                groupPicPreview.style.display = 'block';
                if (groupCropper) groupCropper.destroy();
                groupCropper = new Cropper(groupPicPreview, {
                  aspectRatio: 1, viewMode: 1, autoCropArea: 1, dragMode: 'move', background: false
                });
                if (groupPicInput) groupPicInput.value = '';
              } else {
                profilePicPreview.src = url;
                if (profileCropper) profileCropper.destroy();
                profileCropper = new Cropper(profilePicPreview, {
                  aspectRatio: 1, viewMode: 1, autoCropArea: 1, dragMode: 'move', background: false
                });
                if (profilePicInput) profilePicInput.value = '';
              }
            });
            
            targetContainer.appendChild(img);
          }
        };

        if (refreshPresetsBtn) {
          refreshPresetsBtn.addEventListener('click', () => loadPresets(presetContainer, false));
        }

        const settingsModalEl = document.getElementById('settings-modal');
        if (settingsModalEl) {
          settingsModalEl.addEventListener('show.bs.modal', () => loadPresets(presetContainer, false));
        }

        const groupManageModalEl = document.getElementById('group-manage-modal');
        if (groupManageModalEl) {
          groupManageModalEl.addEventListener('show.bs.modal', () => {
            loadPresets(groupPresetContainer, true);
            if (!document.getElementById('group-manage-id').value) {
               groupPicPreview.src = 'data:image/gif;base64,R0lGODlhAQABAAD/ACwAAAAAAQABAAACADs=';
               groupPicPreview.style.display = 'none';
               if (groupCropper) { groupCropper.destroy(); groupCropper = null; }
               if (groupPicInput) groupPicInput.value = '';
            }
          });
          groupManageModalEl.addEventListener('hidden.bs.modal', () => {
            if (groupCropper) { groupCropper.destroy(); groupCropper = null; }
          });
        }
        
        if (profilePicInput) {
          profilePicInput.addEventListener('change', function(e) {
            if (this.files && this.files[0]) {
              const reader = new FileReader();
              reader.onload = ev => {
                profilePicPreview.src = ev.target.result;
                if (profileCropper) profileCropper.destroy();
                profileCropper = new Cropper(profilePicPreview, {
                  aspectRatio: 1, viewMode: 1, autoCropArea: 1, dragMode: 'move', background: false
                });
              };
              reader.readAsDataURL(this.files[0]);
            }
          });
        }
        
        if (groupPicInput) {
          groupPicInput.addEventListener('change', function(e) {
            if (this.files && this.files[0]) {
              const reader = new FileReader();
              reader.onload = ev => {
                groupPicPreview.src = ev.target.result;
                groupPicPreview.style.display = 'block';
                if (groupCropper) groupCropper.destroy();
                groupCropper = new Cropper(groupPicPreview, {
                  aspectRatio: 1, viewMode: 1, autoCropArea: 1, dragMode: 'move', background: false
                });
              };
              reader.readAsDataURL(this.files[0]);
            }
          });
        }

        profilePicForm.addEventListener('submit', async e => {
          e.preventDefault();
          if (profilePicInput.files.length === 0 && !profileCropper) {
            showToast('Please select an image file.', 'error');
            return;
          }

          const submitBtn = document.getElementById('profile-picture-submit-btn');
          const progContainer = document.getElementById('profile-pic-progress-container');
          const progBar = document.getElementById('profile-pic-progress');
          
          submitBtn.disabled = true;
          progContainer.classList.remove('d-none');
          progBar.style.width = '0%';
          progBar.textContent = '0%';

          const doUpload = (blob) => {
            const formData = new FormData();
            formData.append('profile_picture', blob, 'profile.jpg');

            const xhr = new XMLHttpRequest();
            xhr.upload.onprogress = (evt) => {
              if (evt.lengthComputable) {
                const pct = Math.round((evt.loaded / evt.total) * 100);
                progBar.style.width = pct + '%';
                progBar.textContent = pct + '%';
              }
            };
            xhr.open('POST', '?action=upload_profile_picture', true);
            xhr.onload = async () => {
              submitBtn.disabled = false;
              progContainer.classList.add('d-none');
              if (xhr.status === 200) {
                try {
                  const result = JSON.parse(xhr.responseText);
                  if (result.status === 'success') {
                    showToast(result.message, 'success');
                    if (profileCropper) { profileCropper.destroy(); profileCropper = null; }
                    await checkSession();
                    bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
                  } else {
                    showToast(result.message || 'Upload failed', 'error');
                  }
                } catch(err) {
                  showToast('Invalid server response.', 'error');
                }
              } else {
                showToast('Upload error', 'error');
              }
            };
            xhr.onerror = () => {
              submitBtn.disabled = false;
              progContainer.classList.add('d-none');
              showToast('Network error during upload', 'error');
            };
            xhr.send(formData);
          };

          if (profileCropper) {
            profileCropper.getCroppedCanvas({ width: 500, height: 500 }).toBlob(blob => {
              doUpload(blob);
            }, 'image/jpeg', 0.85);
          } else {
             doUpload(profilePicInput.files[0]);
          }
        });

        document.getElementById('toggle-normalization').addEventListener('change', (e) => {
          enableNormalization = e.target.checked;
          toggleAudioEnhancements();
        });

        document.getElementById('toggle-eq').addEventListener('change', (e) => {
          isEQEnabled = e.target.checked;
          document.getElementById('eq-sliders').classList.toggle('d-none', !isEQEnabled);
          toggleAudioEnhancements();
        });

        if (btnDeleteKeep) {
          btnDeleteKeep.addEventListener('click', async () => {
            if (!confirm('Are you sure you want to delete your account but keep the data? A backup key will be downloaded.')) return;
            const data = await fetchData('?action=delete_account_keep_data');
            if (data && data.status === 'success') {
              const blob = new Blob([data.backup_key], { type: 'text/plain' });
              const a = document.createElement('a');
              a.href = URL.createObjectURL(blob);
              a.download = 'backup.txt';
              document.body.appendChild(a);
              a.click();
              document.body.removeChild(a);
              showToast('Account deleted. Backup key downloaded.', 'success');
              bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
              await checkSession();
              
              const authRequiredViews = ['user_profile', 'get_user_stats', 'get_offline_songs', 'get_favorites', 'get_listen_later', 'get_notes', 'get_community', 'get_history', 'get_following', 'get_recommendations', 'get_user_playlists', 'get_collab_playlists'];
              if (authRequiredViews.includes(currentView.type)) {
                loadView({ type: 'get_songs', param: '', sort: 'random', filter_user_id: '', artist_name: '' });
              } else {
                loadView(currentView);
              }
            }
          });
        }

        if (btnDeleteAll) {
          btnDeleteAll.addEventListener('click', async () => {
            if (!confirm('Are you sure you want to permanently delete your account and ALL your data? This cannot be undone!')) return;
            const data = await fetchData('?action=delete_account_all');
            if (data && data.status === 'success') {
              showToast('Account and data permanently deleted.', 'success');
              bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
              await checkSession();
              
              const authRequiredViews = ['user_profile', 'get_user_stats', 'get_offline_songs', 'get_favorites', 'get_listen_later', 'get_notes', 'get_community', 'get_history', 'get_following', 'get_recommendations', 'get_user_playlists', 'get_collab_playlists'];
              if (authRequiredViews.includes(currentView.type)) {
                loadView({ type: 'get_songs', param: '', sort: 'random', filter_user_id: '', artist_name: '' });
              } else {
                loadView(currentView);
              }
            }
          });
        }

        const uploadLimitText = document.getElementById('upload-limit-text');
        const uploadRemainingText = document.getElementById('upload-remaining-text');
        const songFilesInput = document.getElementById('song-files');
        const songGenreInput = document.getElementById('song-genre');
        const startUploadBtn = document.getElementById('start-upload-btn');
        const uploadProgressArea = document.getElementById('upload-progress-area');
        let filesToUpload = [];

        songFilesInput.addEventListener('change', () => { filesToUpload = Array.from(songFilesInput.files); });
        
        startUploadBtn.addEventListener('click', async () => {
          if (filesToUpload.length === 0) {
            showToast('Please select files to upload.', 'error'); return;
          }
          startUploadBtn.disabled = true;
          uploadProgressArea.innerHTML = '';

          for (let i = 0; i < filesToUpload.length; i++) {
            const file = filesToUpload[i];
            const progressId = `upload-prog-${Date.now()}-${i}`;
            
            uploadProgressArea.insertAdjacentHTML('beforeend', `
              <div class="mb-3 p-3 rounded" style="background-color: var(--ytm-surface-2); border: 1px solid #404040;">
                <div class="d-flex justify-content-between align-items-center mb-2">
                  <small class="text-white text-truncate fw-bold" style="max-width: 80%;">${escapeHTML(file.name)}</small>
                  <small class="text-secondary fw-bold" id="${progressId}-text">0%</small>
                </div>
                <div class="progress" style="height: 8px; background-color: #000;">
                  <div id="${progressId}" class="progress-bar bg-danger" role="progressbar" style="width: 0%; transition: width 0.1s linear;"></div>
                </div>
              </div>`);

            const formData = new FormData();
            formData.append('song', file);
            formData.append('genre', songGenreInput.value);
            formData.append('is_private', document.getElementById('song-is-private').checked ? 1 : 0);

            const xhr = new XMLHttpRequest();
            
            xhr.upload.onprogress = (e) => {
              if (e.lengthComputable) {
                const percentComplete = Math.round((e.loaded / e.total) * 100);
                const progressBar = document.getElementById(progressId);
                const progressText = document.getElementById(`${progressId}-text`);
                if (progressBar) progressBar.style.width = `${percentComplete}%`;
                if (progressText) progressText.textContent = `${percentComplete}%`;
              }
            };
            
            xhr.open('POST', '?action=upload_song', true);
            
            await new Promise(resolve => {
              xhr.onload = () => {
                const progressBar = document.getElementById(progressId);
                const progressText = document.getElementById(`${progressId}-text`);
                if (xhr.status === 200) {
                  if (progressBar) progressBar.classList.replace('bg-danger', 'bg-success');
                  if (progressText) progressText.classList.replace('text-secondary', 'text-success');
                } else {
                  if (progressBar) progressBar.classList.replace('bg-danger', 'bg-warning');
                  if (progressText) {
                    progressText.classList.replace('text-secondary', 'text-warning');
                    progressText.textContent = 'Failed';
                  }
                  try {
                    showToast(`Upload failed for ${file.name}: ${JSON.parse(xhr.responseText).message}`, 'error');
                  } catch (e) {
                    showToast(`Upload failed for ${file.name}: Server error.`, 'error');
                  }
                }
                resolve();
              };
              xhr.onerror = () => {
                const progressBar = document.getElementById(progressId);
                const progressText = document.getElementById(`${progressId}-text`);
                if (progressBar) progressBar.classList.replace('bg-danger', 'bg-warning');
                if (progressText) {
                  progressText.classList.replace('text-secondary', 'text-warning');
                  progressText.textContent = 'Network Error';
                }
                showToast(`A network error occurred during upload of ${file.name}.`, 'error');
                resolve();
              };
              xhr.send(formData);
            });
          }
          startUploadBtn.disabled = false;
          showToast('All uploads complete.', 'success');
          await checkSession();
          loadView(currentView);
          filesToUpload = [];
          songFilesInput.value = '';
          songGenreInput.value = '';
        });

        if (copyShareUrlBtn) {
          copyShareUrlBtn.addEventListener('click', () => {
            const onSuccess = () => {
              copyShareUrlBtn.textContent = 'Copied!';
              copyShareUrlBtn.disabled = true;
              setTimeout(() => {
                copyShareUrlBtn.textContent = 'Copy';
                copyShareUrlBtn.disabled = false;
              }, 2000);
            };
            const onError = () => showToast('Failed to copy link.', 'error');

            if (navigator.clipboard && window.isSecureContext) {
              navigator.clipboard.writeText(shareUrlInput.value).then(onSuccess).catch(onError);
            } else {
              const textArea = document.createElement("textarea");
              textArea.value = shareUrlInput.value;
              textArea.style.position = "fixed";
              textArea.style.top = "0";
              textArea.style.left = "0";
              textArea.style.opacity = "0";
              document.body.appendChild(textArea);
              textArea.focus();
              textArea.select();
              try {
                const successful = document.execCommand('copy');
                if (successful) onSuccess();
                else onError();
              } catch (err) {
                onError();
              }
              document.body.removeChild(textArea);
            }
          });
        }

        const embedModalElGlobal = document.getElementById('embed-modal');
        if (embedModalElGlobal) {
          embedModalElGlobal.addEventListener('hidden.bs.modal', () => {
            const previewContainer = document.getElementById('embed-preview-container');
            if (previewContainer) previewContainer.innerHTML = '';
          });
        }

        const copyEmbedCodeBtn = document.getElementById('copy-embed-code-btn');
        if (copyEmbedCodeBtn) {
          copyEmbedCodeBtn.addEventListener('click', () => {
            const embedInput = document.getElementById('embed-code-input');
            const onSuccess = () => {
              copyEmbedCodeBtn.innerHTML = '<i class="bi bi-check-lg"></i> Copied!';
              copyEmbedCodeBtn.classList.replace('btn-danger', 'btn-success');
              copyEmbedCodeBtn.disabled = true;
              setTimeout(() => {
                copyEmbedCodeBtn.innerHTML = '<i class="bi bi-clipboard"></i> Copy';
                copyEmbedCodeBtn.classList.replace('btn-success', 'btn-danger');
                copyEmbedCodeBtn.disabled = false;
              }, 2000);
            };
            const onError = () => showToast('Failed to copy embed code.', 'error');

            if (navigator.clipboard && window.isSecureContext) {
              navigator.clipboard.writeText(embedInput.value).then(onSuccess).catch(onError);
            } else {
              const textArea = document.createElement("textarea");
              textArea.value = embedInput.value;
              textArea.style.position = "fixed";
              textArea.style.opacity = "0";
              document.body.appendChild(textArea);
              textArea.focus();
              textArea.select();
              try {
                if (document.execCommand('copy')) onSuccess();
                else onError();
              } catch (err) {
                onError();
              }
              document.body.removeChild(textArea);
            }
          });
        }

        let pdAllSongs = [];
        let pdCurrentPage = 1;
        const pdItemsPerPage = 50;
        let pdIsDownloading = false;
        let pdStopRequested = false;

        const pdPlaylistIdInput = document.getElementById('pd-playlist-id');
        const pdSongIdInput = document.getElementById('pd-song-id');
        const pdLoadForm = document.getElementById('pd-load-form');
        const pdDownloadSingleBtn = document.getElementById('pd-download-single');
        const pdResultsCard = document.getElementById('pd-results-card');
        const pdPlaylistTitle = document.getElementById('pd-playlist-title');
        const pdStartAutoBtn = document.getElementById('pd-start-auto');
        const pdLogArea = document.getElementById('pd-log');
        const pdClearLogBtn = document.getElementById('pd-clear-log');
        const pdSongRows = document.getElementById('pd-song-rows');

        const pdEscapeHtml = (str) => {
          if (!str) return '';
          return str.replace(/[&<>'"]/g, m => ({'&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;'}[m] || m))
                    .replace(/[\uD800-\uDBFF][\uDC00-\uDFFF]/g, c => c);
        };
        const pdTruncate = (str, len = 50) => str.length > len ? str.substring(0, len) + '…' : str;

        const pdLog = (message, isError = false) => {
          const time = new Date().toLocaleTimeString();
          const div = document.createElement('div');
          div.className = 'log-line';
          div.style.color = isError ? '#ff8888' : '#aaaaaa';
          div.style.borderBottom = '1px solid #404040';
          div.style.padding = '0.25rem 0';
          div.innerHTML = `[${time}] ${message}`;
          pdLogArea.appendChild(div);
          div.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        };

        const pdDownloadSong = async (song, isAuto = false, index = null, total = null) => {
          const safeTitle = (song.title + ' - ' + (song.artist || 'Unknown')).replace(/[^a-zA-Z0-9\s\.\-\(\)\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]/g, '_');
          const url = `?action=download_song&id=${encodeURIComponent(song.id)}`;
          if (isAuto) {
            pdLog(`Downloading ${index+1}/${total}: ${song.title} - ${song.artist || 'Unknown'}`);
          } else {
            pdLog(`Manual download: ${song.title} - ${song.artist || 'Unknown'}`);
          }
          const a = document.createElement('a');
          a.href = url;
          a.download = safeTitle + '.mp3';
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);
          await new Promise(r => setTimeout(r, 1200));
        };

        const handleManualDl = async (e) => {
          e.preventDefault();
          const songId = parseInt(e.currentTarget.dataset.id);
          const song = pdAllSongs.find(s => s.id === songId);
          if (song) await pdDownloadSong(song, false);
        };

        const pdRenderSongRows = () => {
          pdSongRows.innerHTML = '';
          const start = 0;
          const end = pdItemsPerPage;
          const pageSongs = pdAllSongs.slice(start, end);
          
          const rowsHtml = pageSongs.map((song, idx) => {
            const globalIdx = start + idx;
            return `
              <div class="song-item pd-song-row" style="color: #ffffff !important;">
                <div class="text-secondary small d-flex align-items-center" style="color: #ffffff !important;">
                  <input class="form-check-input pd-song-checkbox me-2" type="checkbox" data-id="${song.id}" ${song.pdSelected !== false ? 'checked' : ''}>
                  <span class="d-none d-md-inline">${globalIdx + 1}</span>
                </div>
                <div class="title-col text-truncate" title="${pdEscapeHtml(song.title)}" style="color: #ffffff !important;">${pdEscapeHtml(pdTruncate(song.title, 60))}</div>
                <div class="artist-col text-truncate d-none d-md-block" title="${pdEscapeHtml(song.artist)}" style="color: #ffffff !important;">${pdEscapeHtml(song.artist ? pdTruncate(song.artist, 40) : 'Unknown')}</div>
                <div class="duration-col d-none d-md-block" style="color: #ffffff !important;">${formatTime(song.duration)}</div>
                <div class="download-col"><button class="btn btn-sm btn-outline-light pd-manual-dl" data-id="${song.id}" style="color: #ffffff !important; border-color: #ffffff !important;"><i class="bi bi-download"></i></button></div>
                <div class="pd-mobile-artist d-md-none text-truncate" style="color: #ffffff !important;">${pdEscapeHtml(song.artist ? pdTruncate(song.artist, 40) : 'Unknown')}</div>
              </div>
            `;
          }).join('');
          
          pdSongRows.innerHTML = rowsHtml;
          
          document.querySelectorAll('.pd-manual-dl').forEach(btn => {
            btn.removeEventListener('click', handleManualDl);
            btn.addEventListener('click', handleManualDl);
          });
          document.querySelectorAll('.pd-song-checkbox').forEach(chk => {
            chk.addEventListener('change', (e) => {
              const s = pdAllSongs.find(song => song.id === parseInt(e.target.dataset.id));
              if (s) s.pdSelected = e.target.checked;
              updatePdSelectAllState();
            });
          });
        };

        const updatePdSelectAllState = () => {
          const selectAllChk = document.getElementById('pd-select-all');
          if (selectAllChk) {
            const allSelected = pdAllSongs.every(s => s.pdSelected !== false);
            selectAllChk.checked = allSelected;
          }
        };

        const selectAllChk = document.getElementById('pd-select-all');
        if (selectAllChk) {
          selectAllChk.addEventListener('change', (e) => {
            const isChecked = e.target.checked;
            pdAllSongs.forEach(s => s.pdSelected = isChecked);
            pdRenderSongRows();
            const pdModalBody = document.querySelector('#playlist-downloader-modal .modal-body');
            if (pdModalBody) pdModalBody.dispatchEvent(new Event('scroll'));
          });
        }

        const pdStopAutoDownload = () => {
          if (!pdIsDownloading) return;
          pdStopRequested = true;
          pdLog('⏹️ Stopping download process...', false);
          pdStartAutoBtn.disabled = true;
          pdStartAutoBtn.innerHTML = '<i class="bi bi-stop-fill" style="color: #ffffff !important;"></i> Stopping...';
        };

        const pdStartAutoDownload = async () => {
          if (pdIsDownloading) return;
          pdIsDownloading = true;
          pdStopRequested = false;
          
          pdStartAutoBtn.removeEventListener('click', pdStartAutoDownload);
          pdStartAutoBtn.addEventListener('click', pdStopAutoDownload);
          pdStartAutoBtn.classList.replace('btn-danger', 'btn-warning');
          pdStartAutoBtn.innerHTML = '<i class="bi bi-stop-fill" style="color: #ffffff !important;"></i> Stop Download';
          pdStartAutoBtn.disabled = false;
          
          const songsToDownload = pdAllSongs.filter(s => s.pdSelected !== false);
          pdLog(`🚀 Starting sequential download of ${songsToDownload.length} selected songs. Click "Stop Download" to cancel.`);
          
          for (let i = 0; i < songsToDownload.length; i++) {
            if (pdStopRequested) {
              pdLog(`⏹️ Download stopped by user after ${i}/${songsToDownload.length} songs.`);
              break;
            }
            await pdDownloadSong(songsToDownload[i], true, i, songsToDownload.length);
          }
          
          pdStartAutoBtn.removeEventListener('click', pdStopAutoDownload);
          pdStartAutoBtn.addEventListener('click', pdStartAutoDownload);
          pdStartAutoBtn.classList.replace('btn-warning', 'btn-danger');
          pdStartAutoBtn.innerHTML = '<i class="bi bi-play-fill" style="color: #ffffff !important;"></i> Download Selected Songs (Sequential)';
          pdStartAutoBtn.disabled = false;
          
          if (!pdStopRequested) pdLog(`✅ All ${songsToDownload.length} selected songs have been sent for download!`);
          pdIsDownloading = false;
          pdStopRequested = false;
        };

        pdLoadForm.addEventListener('submit', async (e) => {
          e.preventDefault();
          const publicId = pdPlaylistIdInput.value.trim();
          if (!publicId) return;
          
          pdLogArea.innerHTML = '';
          pdLog(`Fetching playlist details for: ${publicId}`);
          
          try {
            const data = await fetchData(`?action=get_playlist_songs&public_id=${publicId}&sort=manual_order&all=1`);
            if (data && data.length > 0) {
              pdAllSongs = data.map(s => ({...s, pdSelected: true}));
              pdCurrentPage = 1;
              
              let totalSizeBytes = pdAllSongs.reduce((sum, song) => sum + ((song.duration || 0) * (song.bitrate || 128000) / 8), 0);
              const formatBytes = (bytes) => {
                if (bytes === 0) return '0 Bytes';
                const k = 1024;
                const sizes = ['Bytes', 'KB', 'MB', 'GB'];
                const i = Math.floor(Math.log(bytes) / Math.log(k));
                return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
              };
              
              pdResultsCard.classList.remove('d-none');
              pdPlaylistTitle.innerHTML = `<i class="bi bi-music-note-beamed" style="color: #ffffff !important;"></i> Playlist loaded <span class="badge bg-secondary ms-2">${pdAllSongs.length} songs</span> <span class="badge bg-info ms-2">~${formatBytes(totalSizeBytes)}</span>`;
              pdLog(`✅ Successfully loaded ${pdAllSongs.length} songs (~${formatBytes(totalSizeBytes)}).`);
              pdRenderSongRows();
              const loader = document.getElementById('pd-infinite-scroll-loader');
              if (loader) {
                if (pdCurrentPage * pdItemsPerPage < pdAllSongs.length) {
                  loader.classList.remove('d-none');
                } else {
                  loader.classList.add('d-none');
                }
              }
            } else {
              showToast('Playlist not found or empty', 'error');
              pdLog('❌ Failed to load playlist or it is empty.', true);
            }
          } catch (err) {
            showToast('Error fetching playlist', 'error');
          }
        });

        pdDownloadSingleBtn.addEventListener('click', async () => {
          const songId = parseInt(pdSongIdInput.value);
          if (isNaN(songId) || songId <= 0) {
            showToast('Enter a valid song ID', 'error');
            return;
          }
          try {
            const song = await fetchData(`?action=get_song_data&id=${songId}`);
            if (song && song.id) {
              await pdDownloadSong(song, false);
            } else {
              showToast('Song not found', 'error');
            }
          } catch (err) {
            showToast('Error fetching song', 'error');
          }
        });

        pdStartAutoBtn.addEventListener('click', pdStartAutoDownload);
        pdClearLogBtn.addEventListener('click', () => { pdLogArea.innerHTML = ''; pdLog('Log cleared.'); });

        const pdModalBody = document.querySelector('#playlist-downloader-modal .modal-body');
        if (pdModalBody) {
          pdModalBody.addEventListener('scroll', () => {
            if (pdResultsCard.classList.contains('d-none') || pdAllSongs.length === 0) return;
            const scrollBottom = pdModalBody.scrollHeight - pdModalBody.scrollTop - pdModalBody.clientHeight;
            if (scrollBottom < 200 && pdCurrentPage * pdItemsPerPage < pdAllSongs.length) {
              const start = pdCurrentPage * pdItemsPerPage;
              pdCurrentPage++;
              const end = pdCurrentPage * pdItemsPerPage;
              const pageSongs = pdAllSongs.slice(start, end);
              
              const rowsHtml = pageSongs.map((song, idx) => {
                const globalIdx = start + idx;
                return `
                  <div class="song-item pd-song-row" style="color: #ffffff !important;">
                    <div class="text-secondary small d-flex align-items-center" style="color: #ffffff !important;">
                      <input class="form-check-input pd-song-checkbox me-2" type="checkbox" data-id="${song.id}" ${song.pdSelected !== false ? 'checked' : ''}>
                      <span class="d-none d-md-inline">${globalIdx + 1}</span>
                    </div>
                    <div class="title-col text-truncate" title="${pdEscapeHtml(song.title)}" style="color: #ffffff !important;">${pdEscapeHtml(pdTruncate(song.title, 60))}</div>
                    <div class="artist-col text-truncate d-none d-md-block" title="${pdEscapeHtml(song.artist)}" style="color: #ffffff !important;">${pdEscapeHtml(song.artist ? pdTruncate(song.artist, 40) : 'Unknown')}</div>
                    <div class="duration-col d-none d-md-block" style="color: #ffffff !important;">${formatTime(song.duration)}</div>
                    <div class="download-col"><button class="btn btn-sm btn-outline-light pd-manual-dl" data-id="${song.id}" style="color: #ffffff !important; border-color: #ffffff !important;"><i class="bi bi-download"></i></button></div>
                    <div class="pd-mobile-artist d-md-none text-truncate" style="color: #ffffff !important;">${pdEscapeHtml(song.artist ? pdTruncate(song.artist, 40) : 'Unknown')}</div>
                  </div>
                `;
              }).join('');
              pdSongRows.insertAdjacentHTML('beforeend', rowsHtml);
              document.querySelectorAll('.pd-manual-dl').forEach(btn => {
                btn.removeEventListener('click', handleManualDl);
                btn.addEventListener('click', handleManualDl);
              });
              document.querySelectorAll('.pd-song-checkbox').forEach(chk => {
                chk.addEventListener('change', (e) => {
                  const s = pdAllSongs.find(song => song.id === parseInt(e.target.dataset.id));
                  if (s) s.pdSelected = e.target.checked;
                  updatePdSelectAllState();
                });
              });
              const loader = document.getElementById('pd-infinite-scroll-loader');
              if (loader) {
                if (pdCurrentPage * pdItemsPerPage >= pdAllSongs.length) {
                  loader.classList.add('d-none');
                }
              }
            }
          });
        }

        let lastNotifiedMsgId = localStorage.getItem('ytm_lastMsgId') || 0;

        const requestNotificationPermission = async () => {
          if (!('Notification' in window)) return;
          if (Notification.permission === 'default') {
            try { await Notification.requestPermission(); } catch (e) {}
          }
        };

        const showNativeNotification = (title, body) => {
          if (!('Notification' in window) || Notification.permission !== 'granted') return;
          
          const opts = {
            body: body,
            icon: '?action=get_app_icon&size=192',
            badge: '?action=get_app_icon&size=192',
            vibrate: [200, 100, 200]
          };

          if ('serviceWorker' in navigator && navigator.serviceWorker.ready) {
            navigator.serviceWorker.ready.then(reg => {
              reg.showNotification(title, opts);
            });
          } else {
            const n = new Notification(title, opts);
            n.onclick = () => { window.focus(); };
          }
        };

        const updateNotifBadge = async () => {
          if (!currentUser) return;
          const data = await fetchData('?action=get_unread_notif_count', {}, true);
          const badges = document.querySelectorAll('.notif-badge');
          const dots = document.querySelectorAll('.notif-dot');
          if (data && typeof data.count === 'number') {
            if (data.count > 0) {
              const displayCount = data.count > 99 ? '99+' : data.count;
              badges.forEach(b => { b.textContent = displayCount; b.classList.remove('d-none'); });
              dots.forEach(d => d.classList.remove('d-none'));
            } else {
              badges.forEach(b => b.classList.add('d-none'));
              dots.forEach(d => d.classList.add('d-none'));
            }
          }

          // Check Unread Inbox Badges only if viewing inbox or if inbox badges exist
          const inboxBadges = document.querySelectorAll('.inbox-badge');
          if (inboxBadges.length > 0 && currentView.type === 'get_inbox') {
            const inboxData = await fetchData('?action=get_inbox', {}, true);
            let totalUnread = 0;
            let highestMsgId = parseInt(lastNotifiedMsgId);

            if (Array.isArray(inboxData) && inboxData.length > 0) {
              inboxData.forEach(m => {
                totalUnread += m.unread_count;
                if (m.unread_count > 0 && m.id > highestMsgId && m.sender_id != currentUser.id) {
                  highestMsgId = m.id;
                  let previewText = window.getPreviewText(m.content);
                  if (m.has_image) {
                    if (m.media_type && m.media_type.startsWith('video/')) previewText = '📹 Video';
                    else if (m.media_type && m.media_type.startsWith('audio/')) previewText = '🎵 Audio';
                    else previewText = '📷 Photo';
                  }
                  showNativeNotification(`New message from ${m.name}`, previewText);
                }
              });
            }

            if (highestMsgId > parseInt(lastNotifiedMsgId)) {
              lastNotifiedMsgId = highestMsgId;
              localStorage.setItem('ytm_lastMsgId', highestMsgId);
            }

            if (totalUnread > 0) {
              inboxBadges.forEach(b => { b.textContent = totalUnread; b.classList.remove('d-none'); });
            } else {
              inboxBadges.forEach(b => b.classList.add('d-none'));
            }
          }
        };
        
        // Background Real-Time Notification Poller
        // This ensures you get notifications even if the tab is minimized!
        setInterval(() => {
          if (currentUser && document.visibilityState !== 'visible') {
            updateNotifBadge();
          }
        }, 5000);

        function updateUIForAuthState() {
          const isLoggedIn = !!currentUser;
          document.body.classList.toggle('logged-in', isLoggedIn);
          document.body.classList.toggle('logged-out', !isLoggedIn);
          if (isLoggedIn) {
            document.body.classList.toggle('user-verified', currentUser.verified === 'yes');
            const picUrl = currentUser.profile_picture_url + '&t=' + new Date().getTime();
            profilePictureHeaderDesktop.src = picUrl;
            profilePictureHeaderMobile.src = picUrl;
            profilePicturePreview.src = picUrl;
            
            const bgUrl = `?action=get_profile_background&id=${currentUser.id}&v=${Date.now()}`;
            document.querySelectorAll('.phpmusic-profile-bg-placeholder').forEach(el => el.style.backgroundImage = `url('${bgUrl}')`);
            
            const bgPreviewEl = document.getElementById('profile-bg-preview');
            const bgPreviewContainer = document.getElementById('profile-bg-preview-container');
            if (bgPreviewEl && bgPreviewContainer) {
              bgPreviewContainer.style.display = 'block';
              bgPreviewEl.src = bgUrl;
              if (typeof profileBgCropper !== 'undefined' && profileBgCropper) {
                profileBgCropper.destroy();
                profileBgCropper = null;
              }
            }
            document.querySelectorAll('.phpmusic-profile-img-placeholder').forEach(img => img.src = picUrl);
            document.querySelectorAll('.phpmusic-profile-name').forEach(el => el.textContent = currentUser.artist);
            document.querySelectorAll('.phpmusic-profile-subtext').forEach(el => el.textContent = currentUser.email || 'Verified Artist');

            const scanAllBtn = document.getElementById('nav-scan-all');
            const adminPanelBtn = document.getElementById('nav-admin-panel');
            const isSuperAdmin = currentUser.email && currentUser.email.toLowerCase() === 'musiclibrary@mail.com';
            const isAdmin = currentUser.is_admin == 1 || isSuperAdmin;
            
            // Scan All is now globally visible for emergencies.
            
            if (adminPanelBtn) {
              if (isAdmin) {
                adminPanelBtn.style.setProperty('display', 'flex', 'important');
              } else {
                adminPanelBtn.style.setProperty('display', 'none', 'important');
              }
            }
          } else {
            document.body.classList.remove('user-verified');
          }
        }

        async function checkSession() {
          const data = await fetchData('?action=get_session');
          if (data && data.status === 'loggedin') {
            currentUser = data.user;
            if (currentUser.settings) {
              try {
                // Highly robust JSON extraction for settings
                const s = typeof currentUser.settings === 'string' ? JSON.parse(currentUser.settings) : currentUser.settings;
                
                enableNormalization = s.enableNormalization !== undefined ? s.enableNormalization : true;
                isEQEnabled = s.isEQEnabled !== undefined ? s.isEQEnabled : false;
                isSpatialEnabled = s.isSpatialEnabled !== undefined ? s.isSpatialEnabled : false;
                globalVolumeMultiplier = s.globalVolumeMultiplier !== undefined ? parseFloat(s.globalVolumeMultiplier) : 1.0;
                globalEQBands = Array.isArray(s.globalEQBands) ? s.globalEQBands.map(b => parseFloat(b)) : [0, 0, 0, 0, 0];
                crossfadeDuration = s.crossfadeDuration !== undefined ? parseFloat(s.crossfadeDuration) : 3.0;
                
                // Propagate to UI DOM
                const normEl = document.getElementById('toggle-normalization');
                if (normEl) normEl.checked = enableNormalization;
                
                const crossEl = document.getElementById('crossfade-slider');
                if (crossEl) {
                   crossEl.value = crossfadeDuration;
                   document.getElementById('crossfade-val').textContent = crossfadeDuration + 's';
                }
                
                const eqToggleEl = document.getElementById('toggle-eq');
                if (eqToggleEl) eqToggleEl.checked = isEQEnabled;
                
                const spatialToggleEl = document.getElementById('toggle-spatial');
                if (spatialToggleEl) spatialToggleEl.checked = isSpatialEnabled;
                
                const eqSlidersContainer = document.getElementById('eq-sliders');
                if (eqSlidersContainer) eqSlidersContainer.classList.toggle('d-none', !isEQEnabled);
                
                const volSliderEl = document.getElementById('global-vol-slider');
                if (volSliderEl) {
                   volSliderEl.value = globalVolumeMultiplier;
                   document.getElementById('global-vol-val').textContent = globalVolumeMultiplier + 'x';
                }
                
                const eqSliders = document.querySelectorAll('#eq-sliders .eq-band');
                globalEQBands.forEach((val, i) => { if (eqSliders[i]) eqSliders[i].value = val; });
                
                // Immediately apply audio processing if active
                if (audioCtx) {
                   applyAudioSettings();
                   toggleAudioEnhancements();
                }
              } catch(e) { 
                console.error("Error parsing settings JSON during checkSession:", e); 
              }
            }
            
            const newNameInput = document.getElementById('new-name');
            if (newNameInput) newNameInput.value = currentUser.artist;
            const bioInput = document.getElementById('settings-bio');
            if (bioInput) bioInput.value = currentUser.bio || '';
            if (uploadLimitText) uploadLimitText.textContent = data.upload_limit;
            if (uploadRemainingText) {
              uploadRemainingText.textContent = `Today's remaining uploads: ${currentUser.uploads_remaining}`;
            }
          } else {
            currentUser = null;
          }
          updateUIForAuthState();
        }

        window.noteCategories = [];
        window.taskCategories = [];
        window.blogCategories = [];
        window.noteViewerStates = {}; // Holds markdown state
        
        window.getCategoryName = (id, type = 'note') => {
          const arr = type === 'task' ? window.taskCategories : (type === 'blog' ? window.blogCategories : window.noteCategories);
          if (!arr) return 'Uncategorized';
          const c = arr.find(c => c.id === id);
          return c ? c.name : 'Uncategorized';
        };

        window.renderNoteCategories = () => {
          const catSelect = document.getElementById('editorCategorySelect');
          if (catSelect) {
            catSelect.innerHTML = '<option value="all" style="background: var(--ytm-surface-2);">Uncategorized</option>';
            window.noteCategories.forEach(c => {
              const opt = document.createElement('option');
              opt.value = c.id; opt.innerText = c.name;
              opt.style.background = 'var(--ytm-surface-2)';
              catSelect.appendChild(opt);
            });
          }

          const taskCatSelect = document.getElementById('taskEditorCategorySelect');
          if (taskCatSelect) {
            taskCatSelect.innerHTML = '<option value="all" style="background: var(--ytm-surface-2);">Uncategorized</option>';
            window.taskCategories.forEach(c => {
              const opt = document.createElement('option');
              opt.value = c.id; opt.innerText = c.name;
              opt.style.background = 'var(--ytm-surface-2)';
              taskCatSelect.appendChild(opt);
            });
          }

          const blogCatSelect = document.getElementById('blogEditorCategorySelect');
          if (blogCatSelect) {
            blogCatSelect.innerHTML = '<option value="all" style="background: var(--ytm-surface-2);">Uncategorized</option>';
            (window.blogCategories || []).forEach(c => {
