        let findNoteMatches = [];
        let currentNoteMatchIdx = -1;

        const executeNoteFind = (fromInput = true) => {
          const text = document.getElementById('editorContent').value;
          const query = document.getElementById('findInput').value;
          findNoteMatches = [];
          if (!query) { updateNoteFindUI(-1, false); return; }

          const regex = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
          let match;
          while ((match = regex.exec(text)) !== null) {
            findNoteMatches.push({ index: match.index, length: match[0].length });
          }
          
          if (findNoteMatches.length > 0) {
            if (fromInput) {
              if (currentNoteMatchIdx < 0 || currentNoteMatchIdx >= findNoteMatches.length) currentNoteMatchIdx = 0;
              updateNoteFindUI(currentNoteMatchIdx, false); // Update counts without focus jumping
            } else {
              currentNoteMatchIdx = 0;
              updateNoteFindUI(currentNoteMatchIdx, true); // Actually scroll to it
            }
          } else {
            updateNoteFindUI(-1, false);
          }
        };

        const updateNoteFindUI = (idx, doFocusJump = true) => {
          currentNoteMatchIdx = idx;
          const counter = document.getElementById('findCounter');
          if (findNoteMatches.length === 0 || idx < 0) {
            counter.innerText = '0/0'; return;
          }
          counter.innerText = `${idx + 1}/${findNoteMatches.length}`;
          
          if (doFocusJump) {
            const ta = document.getElementById('editorContent');
            const match = findNoteMatches[idx];
            ta.focus({ preventScroll: true });
            ta.setSelectionRange(match.index, match.index + match.length);
          }
        };

        document.getElementById('editorFindBtn').addEventListener('click', () => {
          if (isMarkdownPreview) return;
          const p = document.getElementById('findReplacePanel');
          p.classList.toggle('active');
          if (p.classList.contains('active')) {
            document.getElementById('findInput').focus();
            executeNoteFind();
          } else {
            document.getElementById('editorContent').focus();
          }
        });
        document.getElementById('closeFindBtn').addEventListener('click', () => document.getElementById('findReplacePanel').classList.remove('active'));
        document.getElementById('findInput').addEventListener('input', executeNoteFind);
        document.getElementById('findNextBtn').addEventListener('click', () => {
          if (findNoteMatches.length === 0) return;
          let next = currentNoteMatchIdx + 1;
          if (next >= findNoteMatches.length) next = 0;
          updateNoteFindUI(next, true);
        });
        document.getElementById('findPrevBtn').addEventListener('click', () => {
          if (findNoteMatches.length === 0) return;
          let next = currentNoteMatchIdx - 1;
          if (next < 0) next = findNoteMatches.length - 1;
          updateNoteFindUI(next, true);
        });
        document.getElementById('replaceBtn').addEventListener('click', () => {
          if (currentNoteMatchIdx < 0 || findNoteMatches.length === 0) return;
          const rep = document.getElementById('replaceInput').value;
          const ta = document.getElementById('editorContent');
          const match = findNoteMatches[currentNoteMatchIdx];
          ta.value = ta.value.substring(0, match.index) + rep + ta.value.substring(match.index + match.length);
          ta.dispatchEvent(new Event('input'));
          executeNoteFind(false);
        });
        document.getElementById('replaceAllBtn').addEventListener('click', () => {
          const query = document.getElementById('findInput').value;
          if (!query) return;
          const rep = document.getElementById('replaceInput').value;
          const ta = document.getElementById('editorContent');
          const regex = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
          ta.value = ta.value.replace(regex, rep);
          ta.dispatchEvent(new Event('input'));
          executeNoteFind(false);
        });

        let findTaskMatches = [];
        let currentTaskMatchIdx = -1;

        const executeTaskFind = (fromInput = true) => {
          const query = document.getElementById('taskFindInput').value;
          findTaskMatches = [];
          if (!query) { updateTaskFindUI(-1, false); return; }

          const regex = new RegExp(query.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\$&'), 'gi');
          
          window.currentTaskItems.forEach((item, itemIdx) => {
            let match;
            regex.lastIndex = 0; 
            while ((match = regex.exec(item.text)) !== null) {
              findTaskMatches.push({ itemIndex: itemIdx, index: match.index, length: match[0].length });
            }
          });
          
          if (findTaskMatches.length > 0) {
            if (fromInput) {
              if (currentTaskMatchIdx < 0 || currentTaskMatchIdx >= findTaskMatches.length) currentTaskMatchIdx = 0;
              updateTaskFindUI(currentTaskMatchIdx, false);
            } else {
              currentTaskMatchIdx = 0;
              updateTaskFindUI(currentTaskMatchIdx, true);
            }
          } else {
            updateTaskFindUI(-1, false);
          }
        };

        const updateTaskFindUI = (idx, doFocusJump = true) => {
          currentTaskMatchIdx = idx;
          const counter = document.getElementById('taskFindCounter');
          if (findTaskMatches.length === 0 || idx < 0) {
            counter.innerText = '0/0'; return;
          }
          counter.innerText = `${idx + 1}/${findTaskMatches.length}`;
          
          if (doFocusJump) {
            const match = findTaskMatches[idx];
            const inputs = document.querySelectorAll('.task-item-input');
            if (inputs.length > match.itemIndex) {
              const targetInput = inputs[match.itemIndex];
              targetInput.focus({ preventScroll: true });
              targetInput.setSelectionRange(match.index, match.index + match.length);
            }
          }
        };

        document.getElementById('taskEditorFindBtn')?.addEventListener('click', () => {
          const p = document.getElementById('taskFindReplacePanel');
          p.classList.toggle('active');
          if (p.classList.contains('active')) {
            document.getElementById('taskFindInput').focus();
            executeTaskFind();
          }
        });

        document.getElementById('closeTaskFindBtn')?.addEventListener('click', () => {
          document.getElementById('taskFindReplacePanel').classList.remove('active');
        });

        document.getElementById('taskFindInput')?.addEventListener('input', executeTaskFind);

        document.getElementById('taskFindNextBtn')?.addEventListener('click', () => {
          if (findTaskMatches.length === 0) return;
          let next = currentTaskMatchIdx + 1;
          if (next >= findTaskMatches.length) next = 0;
          updateTaskFindUI(next, true);
        });

        document.getElementById('taskFindPrevBtn')?.addEventListener('click', () => {
          if (findTaskMatches.length === 0) return;
          let next = currentTaskMatchIdx - 1;
          if (next < 0) next = findTaskMatches.length - 1;
          updateTaskFindUI(next, true);
        });

        document.getElementById('taskReplaceBtn')?.addEventListener('click', () => {
          if (currentTaskMatchIdx < 0 || findTaskMatches.length === 0) return;
          const rep = document.getElementById('taskReplaceInput').value;
          const match = findTaskMatches[currentTaskMatchIdx];
          
          const text = window.currentTaskItems[match.itemIndex].text;
          window.currentTaskItems[match.itemIndex].text = text.substring(0, match.index) + rep + text.substring(match.index + match.length);
          
          window.renderTaskItems();
          window.saveCurrentTask(false);
          executeTaskFind(false);
        });

        document.getElementById('taskReplaceAllBtn')?.addEventListener('click', () => {
          const query = document.getElementById('taskFindInput').value;
          if (!query) return;
          const rep = document.getElementById('taskReplaceInput').value;
          const regex = new RegExp(query.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\$&'), 'gi');
          
          let changed = false;
          window.currentTaskItems.forEach(item => {
            if (regex.test(item.text)) {
              item.text = item.text.replace(regex, rep);
              changed = true;
            }
          });
          
          if (changed) {
            window.renderTaskItems();
            window.saveCurrentTask(false);
            executeTaskFind(false);
          }
        });

        document.getElementById('toggleSelectAllNotesBtn').addEventListener('click', () => {
          const allSelected = window.currentNotesList && window.currentNotesList.length > 0 && window.currentNotesList.every(n => window.selectedNoteIds.has(n.id.toString()));
          if (allSelected) {
            window.currentNotesList.forEach(n => window.selectedNoteIds.delete(n.id.toString()));
            if (window.selectedNoteIds.size === 0) window.multiSelectNoteMode = false;
          } else {
            window.currentNotesList.forEach(n => window.selectedNoteIds.add(n.id.toString()));
          }
          updateNoteSelectionUI();
        });

        document.getElementById('cancelSelectNotesBtn').addEventListener('click', () => {
          window.multiSelectNoteMode = false; 
          window.selectedNoteIds.clear();
          updateNoteSelectionUI();
        });

        document.getElementById('bulkDeleteNotesBtn').addEventListener('click', async () => {
          const isTask = currentView.type === 'get_tasks';
          if (confirm(`Delete ${window.selectedNoteIds.size} ${isTask ? 'tasks' : 'notes'} permanently?`)) {
            for (let id of window.selectedNoteIds) {
              const endpoint = isTask ? '?action=delete_task' : '?action=delete_note';
              await fetchData(endpoint, { method:'POST', body: JSON.stringify({id}) }, true);
            }
            window.selectedNoteIds.clear(); 
            window.multiSelectNoteMode = false;
            updateNoteSelectionUI();
            loadView(currentView);
          }
        });

        document.getElementById('bulkDownloadNotesBtn').addEventListener('click', async () => {
          const zip = new JSZip();
          const isTask = currentView.type === 'get_tasks';
          window.selectedNoteIds.forEach(id => {
            if (isTask) {
              const t = window.currentTasksList.find(x => x.id.toString() === id.toString());
              if (t) {
                let items = [];
                try { items = JSON.parse(t.items); } catch(e) {}
                const content = items.map(i => (i.completed ? '[x] ' : '[ ] ') + decodeHTML(i.text)).join('\n');
                const displayTitle = (t.title && t.title.trim()) ? decodeHTML(t.title) : 'task_list';
                zip.file(`${displayTitle.replace(/[^\w\s-]/gi, '_')}.txt`, content);
              }
            } else {
              const n = window.currentNotesList.find(x => x.id.toString() === id.toString());
              if (n) {
                const cleanContent = n.content.replace(/<[^>]*>?/gm, '');
                const displayTitle = (n.title && n.title.trim()) ? decodeHTML(n.title) : 
                                     (cleanContent.trim() ? cleanContent.split(/\s+/).slice(0, 5).join(' ') : 'title');
                zip.file(`${displayTitle.replace(/[^\w\s-]/gi, '_')}.txt`, decodeHTML(n.content) || '');
              }
            }
          });
          const blob = await zip.generateAsync({ type: 'blob' });
          const a = document.createElement('a');
          a.href = URL.createObjectURL(blob);
          a.download = `${isTask ? 'Tasks' : 'Notes'}_Selection_${Date.now()}.zip`;
          a.click();
          
          window.selectedNoteIds.clear();
          window.multiSelectNoteMode = false;
          updateNoteSelectionUI();
        });

       const init = async () => {
          // Fix: Prevent aggressive audio preloading from causing infinite network buffering spinners on an empty src
          audio.preload = 'none';
          
          audio.addEventListener('waiting', () => {
            if (isPlaying) updatePlayPauseIcons(true); 
          });

          audio.addEventListener('playing', () => {
            updatePlayPauseIcons(false);
            if (audioCtx) {
              if (audioCtx.state === 'suspended') audioCtx.resume();
              applyAudioSettings();
            }
          });

          audio.addEventListener('canplay', () => {
            if (isPlaying) updatePlayPauseIcons(false);
          });

          audio.addEventListener('error', (e) => {
            console.error('Audio playback error:', e);
            if (audio.error && audio.error.code === 2 && isPlaying && currentSong) {
              updatePlayPauseIcons(true); 
              const currentPos = audio.currentTime;
              setTimeout(() => {
                audio.load();
                audio.currentTime = currentPos;
                audio.play().catch(() => updatePlayPauseIcons(false));
              }, 3000);
            } else {
              updatePlayPauseIcons(false);
            }
          });

          if ('serviceWorker' in navigator) {
            navigator.serviceWorker.register('?pwa=sw').catch(err => console.error('SW registration failed:', err));
          }
          
          playerElements.prevBtn.forEach(b => b.innerHTML = ICONS.prev);
          playerElements.nextBtn.forEach(b => b.innerHTML = ICONS.next);
          playerElements.shuffleBtn.forEach(b => b.innerHTML = ICONS.shuffle);
          updatePlayPauseIcons();
          updateRepeatIcons();
          updateShuffleButtons();
          updateVolumeIcon();
          if (playerElements.volumeSlider) {
            audio.volume = playerElements.volumeSlider.value;
            updateVolumeSliderFill();
          }

          await checkSession();

          // Intercept Invite Links before normal rendering
          const urlParams = new URLSearchParams(window.location.search);
          
          const chatInviteToken = urlParams.get('chat_invite');
          if (chatInviteToken) {
            if (!currentUser) {
              showToast("Please log in to join the group chat.", "warning");
              const loginModal = new bootstrap.Modal(document.getElementById('login-modal'));
              loginModal.show();
            } else {
              fetchData('?action=join_group', { method:'POST', body: JSON.stringify({token: chatInviteToken}) }).then(res => {
                if (res && res.status === 'success') {
                  showToast('Joined group successfully!', 'success');
                  window.history.replaceState({}, document.title, window.location.pathname);
                  loadView({ type: 'get_inbox', param: '', sort: '', filter_user_id: '' });
                  setTimeout(() => window.openChatFull(res.group_id, 'group', 'Group Chat'), 1000);
                } else {
                  showToast(res?.message || "Invalid invite link.", "error");
                  window.history.replaceState({}, document.title, window.location.pathname);
                }
              });
            }
          }

          const resetToken = urlParams.get('reset_token');
          if (resetToken) {
            document.getElementById('reset-token-input').value = resetToken;
            window.history.replaceState({}, document.title, window.location.pathname);
            new bootstrap.Modal(document.getElementById('reset-password-modal')).show();
            return; // Halt default loading since we want the user to set a password first
          }

          const inviteToken = urlParams.get('collab_invite');
          const projToken = urlParams.get('project_invite');
          if (projToken) {
            if (!currentUser) {
              showToast("Please log in to join the project.", "warning");
              new bootstrap.Modal(document.getElementById('login-modal')).show();
            } else {
              const projModalEl = document.getElementById('project-invite-modal');
              if (projModalEl) {
                const projModal = new bootstrap.Modal(projModalEl);
                document.getElementById('project-invite-accept-btn').onclick = async () => {
                  const res = await fetchData('?action=manage_project', {
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({ action_type: 'join', token: projToken })
                  });
                  if (res) {
                    showToast(res.message || 'Joined successfully', res.status);
                    projModal.hide();
                    window.history.replaceState({}, document.title, window.location.pathname);
                    loadView({ type: 'get_projects', param: '', sort: '', filter: '' });
                  }
                };
                projModal.show();
              }
            }
          }

          if (inviteToken) {
            if (!currentUser) {
              showToast("Please log in to accept the collaboration invite.", "warning");
              const loginModal = new bootstrap.Modal(document.getElementById('login-modal'));
              loginModal.show();
            } else {
              const inviteData = await fetchData(`?action=get_invite_info&token=${encodeURIComponent(inviteToken)}`);
              if (inviteData && inviteData.status === 'success' && inviteData.details) {
                const playlistInfo = inviteData.details;
                if (playlistInfo.user_id == currentUser.id) {
                  showToast("Are you try to befriend yourself because you don't have a friend?", "warning");
                  window.history.replaceState({}, document.title, window.location.pathname);
                } else {
                  const inviteModalEl = document.getElementById('collab-invite-modal');
                  if (inviteModalEl) {
                    document.getElementById('invite-playlist-name').textContent = playlistInfo.name;
                    document.getElementById('invite-playlist-creator').textContent = playlistInfo.creator;
                    const inviteModal = new bootstrap.Modal(inviteModalEl);
                    
                    document.getElementById('invite-accept-btn').onclick = async () => {
                      const res = await fetchData('?action=manage_collaborators', {
                        method: 'POST', headers: {'Content-Type': 'application/json'},
                        body: JSON.stringify({ public_id: playlistInfo.public_id, collab_action: 'join', token: inviteToken })
                      });
                      if (res) {
                        showToast(res.message, res.status);
                        inviteModal.hide();
                        window.history.replaceState({}, document.title, window.location.pathname);
                        loadView({ type: 'playlist_songs', param: playlistInfo.public_id, sort: 'manual_order', filter_user_id: '' });
                      }
                    };
                    
                    document.getElementById('invite-reject-btn').onclick = () => {
                      window.history.replaceState({}, document.title, window.location.pathname);
                    };
                    
                    inviteModal.show();
                  }
                }
              } else {
                showToast("Invalid or expired invite link.", "error");
                window.history.replaceState({}, document.title, window.location.pathname);
              }
            }
          }

          if (chatInviteToken || inviteToken) return; // Prevent overwriting view when handling invites

          if (window.initialView) {
            history.replaceState({ viewConfig: window.initialView }, "");
            loadView(window.initialView, false);
          } else {
            let savedViewStr = localStorage.getItem('ytm_lastView');
            let savedView = null;
            try { savedView = savedViewStr ? JSON.parse(savedViewStr) : null; } catch(e) {}
            const defaultView = savedView || { type: 'get_songs', param: '', sort: 'random', filter_user_id: '' };
            history.replaceState({ viewConfig: defaultView }, "");
            loadView(defaultView, false);
          }
        };

        window.addEventListener('popstate', (e) => {
          const edOver = document.getElementById('editorOverlay');
          const taskOver = document.getElementById('taskEditorOverlay');
          
          if (e.state && e.state.overlay) {
            // An overlay is meant to be active. We will let standard navigation handle it for now, 
            // but if we are here, we don't close it yet.
          } else {
            // No overlay in state. Close any open overlays securely.
            if (edOver && edOver.classList.contains('active')) {
              saveCurrentEditorNote(true);
              edOver.classList.remove('active');
              activeEditorNote = null;
              if (currentView.type === 'get_notes') loadView(currentView, false);
            }
            if (taskOver && taskOver.classList.contains('active')) {
              window.saveCurrentTask(true);
              taskOver.classList.remove('active');
              if (currentView.type === 'get_tasks') loadView(currentView, false);
            }
          }

          if (e.state && e.state.viewConfig) {
            loadView(e.state.viewConfig, false);
          } else {
            loadView({ type: 'get_songs', param: '', sort: 'random', filter_user_id: '', artist_name: '' }, false);
          }
        });

        // Forbid inspecting the page, bypassable by super admin
        document.addEventListener('contextmenu', e => {
          if (localStorage.getItem('dev_mode_token') === 'admin') return;
          if (e.target.tagName !== 'INPUT' && e.target.tagName !== 'TEXTAREA') {
            e.preventDefault();
          }
        });

        document.addEventListener('keydown', async e => {
          // Anti-inspect
          if (e.key === 'F12' || 
          (e.ctrlKey && e.shiftKey && (e.key === 'I' || e.key === 'C' || e.key === 'J')) || 
          (e.ctrlKey && e.key === 'U')) {
            const isValidDevToken = (token) => {
              if (!token) return false;
              if (token === 'musiclibrary' || token === 'musiclibrary@mail.com') return true;
              if (token.startsWith('pk_')) return true;
              const currentApi = localStorage.getItem('ytm_apiKey') || localStorage.getItem('admin_api_key') || window.apiKey;
              return currentApi && token === currentApi;
            };

            if (!isValidDevToken(localStorage.getItem('dev_mode_token')) && window.adminAutoToken !== 'musiclibrary@mail.com') {
              e.preventDefault(); // Block the browser's default inspect window opening
              const pwd = prompt("Developer tools locked. Enter API Key or Admin password:");
              if (isValidDevToken(pwd)) {
                localStorage.setItem('dev_mode_token', pwd);
                alert("Access granted. You can now press the shortcut again to open DevTools.");
              } else if (pwd !== null) {
                alert("Password incorrect. You want to try exploit the site?");
              }
              return false;
            }
          }
          // Stop if user is typing in an input field
          if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') {
            if (e.code === 'Escape') {
              e.target.blur();
            }
            return;
          }

          // Global non-song shortcuts
          if (e.code === 'Escape') {
            e.preventDefault();
            const modals = document.querySelectorAll('.modal.show');
            modals.forEach(m => {
              const instance = bootstrap.Modal.getInstance(m);
              if (instance) instance.hide();
            });
            const ctxMenu = document.getElementById('context-menu');
            if (ctxMenu) ctxMenu.style.display = 'none';
            return;
          }

          if (e.shiftKey && e.code === 'KeyS') {
            e.preventDefault();
            const searchInput = window.innerWidth >= 768 ? document.getElementById('search-input-desktop') : document.getElementById('search-input-mobile');
            if (searchInput) searchInput.focus();
            return;
          }

          if (e.shiftKey && e.code === 'KeyC') {
            e.preventDefault();
            const clearBtn = document.getElementById('clear-history-btn');
            if (clearBtn && !clearBtn.closest('#history-controls').classList.contains('d-none')) {
              clearBtn.click();
            }
            return;
          }

          // Navigation & Quick Access Shortcuts (Global)
          if (e.code === 'KeyN' && !e.shiftKey && !e.ctrlKey && !e.metaKey) {
            e.preventDefault();
            if (currentUser) loadView({ type: 'get_notes', param: '', sort: 'newest', filter: 'all' });
            else showToast('Please login to view notes', 'error');
            return;
          }
          if (e.code === 'KeyK' && !e.shiftKey && !e.ctrlKey && !e.metaKey) {
            e.preventDefault();
            if (currentUser) loadView({ type: 'get_tasks', param: '', sort: 'newest', filter: 'all' });
            else showToast('Please login to view tasks', 'error');
            return;
          }
          if (e.code === 'KeyV' && !e.shiftKey && !e.ctrlKey && !e.metaKey) {
            e.preventDefault();
            if (currentUser) {
              const setModal = bootstrap.Modal.getOrCreateInstance(document.getElementById('settings-modal'));
              setModal.show();
              setTimeout(() => {
                const audioTab = document.querySelector('.phpmusic-settings-nav button[data-bs-target="#settings-audio"]');
                if (audioTab) audioTab.click();
              }, 200);
            } else {
               showToast('Please login for settings', 'error');
            }
            return;
          }
          if (e.code === 'KeyQ' && !e.shiftKey && !e.ctrlKey && !e.metaKey) {
            e.preventDefault();
            if (currentSong) {
              const pm = bootstrap.Modal.getOrCreateInstance(window.innerWidth >= 768 ? document.getElementById('desktop-player-modal') : document.getElementById('player-modal'));
              pm.show();
              setTimeout(() => {
                const qTab = window.innerWidth >= 768 ? document.getElementById('dp-queue-tab') : document.querySelector('#mp-tabs [data-bs-target="#mp-queue-pane"]');
                if (qTab) qTab.click();
              }, 200);
            }
            return;
          }
          if (e.code === 'KeyW' && !e.shiftKey && !e.ctrlKey && !e.metaKey) {
            e.preventDefault();
            if (typeof toggleWakeLock === 'function') toggleWakeLock();
            return;
          }
          if (e.shiftKey && e.code === 'KeyP') {
            e.preventDefault();
            if (currentUser) loadView({ type: 'get_user_playlists', param: '', sort: 'modified_desc', filter_user_id: '' });
            else showToast('Please login to view playlists', 'error');
            return;
          }
          if (e.shiftKey && e.code === 'KeyU') {
            e.preventDefault();
            const upBtn = document.getElementById('nav-upload-btn');
            if (upBtn) upBtn.click();
            return;
          }
          if (e.shiftKey && e.code === 'KeyM') {
            e.preventDefault();
            if (currentUser) loadView({ type: 'get_inbox', param: '', sort: '', filter_user_id: '' });
            else showToast('Please login to view messages', 'error');
            return;
          }
          if (e.shiftKey && e.code === 'KeyF') {
            e.preventDefault();
            if (currentUser) loadView({ type: 'get_favorites', param: '', sort: 'manual_order', filter_user_id: '' });
            else showToast('Please login to view favorites', 'error');
            return;
          }
          if (e.shiftKey && e.code === 'KeyA') {
            e.preventDefault();
            if (currentUser) bootstrap.Modal.getOrCreateInstance(document.getElementById('activity-modal')).show();
            else showToast('Please login to view activity', 'error');
            return;
          }

          // Global Player Shortcuts (Only if a song is loaded)
          if (!currentSong) return;

          switch (e.code) {
            case 'Space':
              e.preventDefault(); 
              togglePlayPause();
              break;
            case 'ArrowRight':
              e.preventDefault();
              if (e.shiftKey) {
                if (isFinite(audio.duration)) audio.currentTime = Math.min(audio.duration, audio.currentTime + 10);
              } else {
                playNext();
              }
              break;
            case 'ArrowLeft':
              e.preventDefault();
              if (e.shiftKey) {
                if (isFinite(audio.duration)) audio.currentTime = Math.max(0, audio.currentTime - 10);
              } else {
                playPrev();
              }
              break;
            case 'ArrowUp':
              e.preventDefault();
              audio.volume = Math.min(1, audio.volume + 0.05);
              if (playerElements.volumeSlider) {
                playerElements.volumeSlider.value = audio.volume;
                playerElements.volumeSlider.dispatchEvent(new Event('input'));
              }
              break;
            case 'ArrowDown':
              e.preventDefault();
              audio.volume = Math.max(0, audio.volume - 0.05);
              if (playerElements.volumeSlider) {
                playerElements.volumeSlider.value = audio.volume;
                playerElements.volumeSlider.dispatchEvent(new Event('input'));
              }
              break;
            case 'KeyM':
              e.preventDefault();
              if (playerElements.volumeBtn) playerElements.volumeBtn.click();
              break;
            case 'KeyS':
              if (!e.shiftKey) {
                e.preventDefault();
                toggleShuffle();
              }
              break;
            case 'KeyR':
              e.preventDefault();
              repeatMode = (repeatMode === 'none') ? 'all' : (repeatMode === 'all') ? 'one' : 'none';
              localStorage.setItem('repeatMode', repeatMode);
              updateRepeatIcons();
              break;
            case 'KeyF':
              e.preventDefault();
              const fsBtn = document.getElementById('fullscreen-btn');
              if (fsBtn) fsBtn.click();
              break;
            case 'KeyP':
              e.preventDefault();
              const pipBtn = document.getElementById('pip-btn-desktop');
              if (pipBtn) pipBtn.click();
              break;
            case 'KeyL':
              e.preventDefault();
              const lyricsSongData = await fetchData('?action=get_song_data&id=' + currentSong.id);
              if (lyricsSongData) {
                const lyricsTitleEl = document.getElementById('lyrics-modal-title');
                const lyricsBodyEl = document.getElementById('lyrics-modal-body');
                if (lyricsTitleEl) lyricsTitleEl.textContent = lyricsSongData.title;
                if (lyricsBodyEl) {
                  const lrcData = parseLRC(lyricsSongData.lyrics);
                  if (lrcData.length > 0) {
                    currentLrcData = lrcData;
                    currentLrcSongId = parseInt(currentSong.id);
                    currentLyricIndex = -1;
                    lyricsBodyEl.innerHTML = `<div id="synced-lyrics-container">` + 
                      lrcData.map((line, idx) => `<div class="lyric-line" data-index="${idx}" data-time="${line.time}">${escapeHTML(line.text)}</div>`).join('') +
                      `</div>`;
                  } else {
                    currentLrcData = null;
                    currentLrcSongId = null;
                    lyricsBodyEl.innerHTML = lyricsSongData.lyrics ? `<pre style="white-space: pre-wrap; font-family: 'Roboto', sans-serif;">${escapeHTML(lyricsSongData.lyrics)}</pre>` : '<p class="text-center text-secondary">No lyrics available.</p>';
                  }
                }
                const lyricsModalEl = document.getElementById('lyrics-modal');
                if (lyricsModalEl) {
                  bootstrap.Modal.getOrCreateInstance(lyricsModalEl).show();
                }
              }
              break;
            case 'KeyC':
              if (!e.shiftKey) {
                e.preventDefault();
                if (currentUser) {
                  window.openCommentsModal(currentSong.id);
                } else {
                  showToast('Please login to view comments', 'error');
                }
              }
              break;
            case 'KeyH':
              e.preventDefault();
              if (currentUser) toggleFavorite(currentSong.id);
              break;
            case 'KeyB':
              e.preventDefault();
              if (currentUser) {
                const res = await fetchData('?action=toggle_listen_later', { method: 'POST', body: JSON.stringify({id: parseInt(currentSong.id)}) });
                if (res) {
                  if (res.status === 'added') listenLaterSet.add(parseInt(currentSong.id));
                  else listenLaterSet.delete(parseInt(currentSong.id));
                  showToast(res.status === 'added' ? 'Added to Listen Later' : 'Removed from Listen Later', 'success'); 
                }
              }
              break;
            case 'KeyO':
              e.preventDefault();
              if (currentUser) {
                 const offRes = await fetchData('?action=toggle_offline', {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({ id: parseInt(currentSong.id) })
                });
                if (offRes) {
                  if (offRes.status === 'added') {
                    showToast('Caching offline (check menu for progress)...', 'info');
                    offlineSongsSet.add(parseInt(currentSong.id));
                  } else {
                    showToast('Removed from offline list.', 'success');
                    offlineSongsSet.delete(parseInt(currentSong.id));
                  }
                }
              }
              break;
            case 'KeyD':
              e.preventDefault();
              window.location.href = '?action=download_song&id=' + currentSong.id;
              break;
            case 'KeyI':
              e.preventDefault();
              const metaSongData = await fetchData('?action=get_song_data&id=' + parseInt(currentSong.id));
              if (metaSongData) {
                const metaBody = document.getElementById('metadata-modal-body');
                if (metaBody) {
                  metaBody.innerHTML = `
                    <ul class="list-group list-group-flush">
                      <li class="list-group-item bg-transparent border-secondary text-white d-flex justify-content-between"><strong>Title:</strong> <span class="text-truncate" style="max-width: 70%;">${metaSongData.title || 'N/A'}</span></li>
                      <li class="list-group-item bg-transparent border-secondary text-white d-flex justify-content-between"><strong>Artist:</strong> <span class="text-truncate" style="max-width: 70%;">${metaSongData.artist || 'N/A'}</span></li>
                      <li class="list-group-item bg-transparent border-secondary text-white d-flex justify-content-between"><strong>Album:</strong> <span class="text-truncate" style="max-width: 70%;">${metaSongData.album || 'N/A'}</span></li>
                      <li class="list-group-item bg-transparent border-secondary text-white d-flex justify-content-between"><strong>Genre:</strong> <span class="text-truncate" style="max-width: 70%;">${metaSongData.genre || 'N/A'}</span></li>
                      <li class="list-group-item bg-transparent border-secondary text-white d-flex justify-content-between"><strong>Year:</strong> <span>${metaSongData.year || 'N/A'}</span></li>
                      <li class="list-group-item bg-transparent border-secondary text-white d-flex justify-content-between"><strong>Duration:</strong> <span>${formatTime(metaSongData.duration)}</span></li>
                      <li class="list-group-item bg-transparent border-secondary text-white d-flex justify-content-between"><strong>Bitrate:</strong> <span>${metaSongData.bitrate ? Math.round(metaSongData.bitrate / 1000) + ' kbps' : 'N/A'}</span></li>
                    </ul>`;
                  bootstrap.Modal.getOrCreateInstance(document.getElementById('metadata-modal')).show();
                }
              }
              break;
            case 'KeyE':
              e.preventDefault();
              if (currentUser) {
                const sasModalEl = document.getElementById('song-audio-settings-modal');
                if (sasModalEl) {
                  document.getElementById('sas-song-id').value = currentSong.id;
                  document.getElementById('sas-song-title').textContent = currentSong.title;
                  const targetVol = currentSong.volume_multiplier !== null ? parseFloat(currentSong.volume_multiplier) : globalVolumeMultiplier;
                  const targetEQ = currentSong.eq_bands || [0,0,0,0,0];
                  document.getElementById('sas-vol-slider').value = targetVol;
                  document.getElementById('sas-vol-val').textContent = targetVol + 'x';
                  const sasEqBands = document.querySelectorAll('.sas-eq-band');
                  sasEqBands.forEach((band, i) => band.value = targetEQ[i] !== undefined ? targetEQ[i] : 0);
                  document.getElementById('sas-eq-preset-select').value = 'Custom';
                  bootstrap.Modal.getOrCreateInstance(sasModalEl).show();
                }
              }
              break;
            case 'KeyU':
              e.preventDefault();
              showShareModal('song', currentSong.id, currentSong.title);
              break;
            case 'Digit0':
            case 'Numpad0':
              e.preventDefault();
              audio.currentTime = 0;
              break;
            case 'Digit1':
            case 'Numpad1':
            case 'Digit2':
            case 'Numpad2':
            case 'Digit3':
            case 'Numpad3':
            case 'Digit4':
            case 'Numpad4':
            case 'Digit5':
            case 'Numpad5':
            case 'Digit6':
            case 'Numpad6':
            case 'Digit7':
            case 'Numpad7':
            case 'Digit8':
            case 'Numpad8':
            case 'Digit9':
            case 'Numpad9':
              e.preventDefault();
              const num = parseInt(e.key);
              if (isFinite(audio.duration)) {
                audio.currentTime = audio.duration * (num / 10);
              }
              break;
          }
        });

        // --- ARTIST HOVER TOOLTIP LOGIC ---
        const artistTooltip = document.createElement('div');
        artistTooltip.id = 'artist-hover-tooltip';
        document.body.appendChild(artistTooltip);

        let artistHoverTimeout;
        let artistHideTimeout;
        const artistHoverCache = {};

        const showArtistTooltip = async (target, artistRaw, userId) => {
          if (window.innerWidth < 992) return;
          
          const artistsList = decodeURIComponent(artistRaw).split(/\s*(?:;|\||\s\/\s|\s&\s|\sfeat\.?\s|\sft\.?\s|\sfeaturing\s)\s*|,\s+(?!(?:the|a|an|jr|sr)\b)/i).filter(a => a && a.trim() !== '');
          if (artistsList.length === 0) return;
          
          const rect = target.getBoundingClientRect();
          artistTooltip.style.display = 'block';
          
          let top = rect.bottom + window.scrollY + 10;
          let left = rect.left + window.scrollX;
          
          if (left + 320 > window.innerWidth) left = window.innerWidth - 340;
          // Dynamically adjust height constraint to handle multiple artists
          const estimatedHeight = artistsList.length * 100 + 40;
          if (top + estimatedHeight > window.scrollY + window.innerHeight) top = rect.top + window.scrollY - estimatedHeight - 10;
          if (top < window.scrollY) top = window.scrollY + 10;
          
          artistTooltip.style.top = top + 'px';
          artistTooltip.style.left = left + 'px';

          artistTooltip.innerHTML = '<div class="text-center p-3"><div class="spinner-border spinner-border-sm text-secondary"></div></div>';
          artistTooltip.style.opacity = '1';

          let html = '';
          for (let i = 0; i < artistsList.length; i++) {
            const artistName = artistsList[i];
            const cacheKey = (userId ? userId + '_' : '') + artistName.toLowerCase();
            let data = artistHoverCache[cacheKey];

            if (!data) {
               const res = await fetchData(`?action=get_view_data&type=artist&name=${encodeURIComponent(artistName)}&filter_user_id=${userId || ''}`);
               if (res && res.details) {
                  data = res.details;
                  artistHoverCache[cacheKey] = data;
               }
            }

            if (data) {
              let followBtn = '';
              if (data.is_user && currentUser && currentUser.id != data.user_id) {
                 const btnClass = data.is_following ? 'btn-outline-light' : 'btn-danger';
                 const btnText = data.is_following ? 'Unfollow' : 'Follow';
                 followBtn = `<button class="btn btn-sm ${btnClass} w-100 mt-2 tooltip-follow-btn fw-bold" data-user-id="${data.user_id}">${btnText}</button>`;
              }

              html += `
                <div class="artist-tooltip-card ${i < artistsList.length - 1 ? 'border-bottom border-secondary pb-3 mb-3' : ''}">
                  <div class="d-flex align-items-center gap-3 artist-tt-click" data-artist="${encodeURIComponent(data.name)}" style="cursor: pointer;">
                    <img src="${data.image_url}" style="width: 60px; height: 60px; object-fit: cover; border-radius: 50%; box-shadow: 0 4px 10px rgba(0,0,0,0.5);">
                    <div style="min-width: 0;">
                       <h6 class="text-white text-truncate mb-1 fw-bold artist-tt-name" style="font-size: 1.05rem;">${escapeHTML(data.name)}</h6>
                       <div class="text-secondary" style="font-size: 0.8rem;">${formatSongCount(data.song_count || 0)} tracks • ${formatTime(data.total_duration || 0)}</div>
                       ${data.followers_count !== undefined ? `<div class="text-info mt-1" style="font-size: 0.75rem;"><i class="bi bi-people-fill"></i> ${formatSongCount(data.followers_count)} followers</div>` : `<div class="text-secondary mt-1" style="font-size: 0.75rem;"><i class="bi bi-eye"></i> ${formatSongCount(data.play_count || 0)} plays</div>`}
                    </div>
                  </div>
                  ${followBtn}
                </div>
              `;
            } else {
              html += `<div class="text-secondary small text-center p-2 ${i < artistsList.length - 1 ? 'border-bottom border-secondary pb-3 mb-3' : ''}">${escapeHTML(artistName)}: Details not found</div>`;
            }
          }
          artistTooltip.innerHTML = html;
        };

        document.addEventListener('mouseover', e => {
          const artistEl = e.target.closest('.artist-link, .song-artist, .song-artist-name, .item-subtitle[data-artist], .mention-link, .user-profile-link');
          if (artistEl) {
            clearTimeout(artistHideTimeout);
            if (artistTooltip.contains(e.relatedTarget)) return; 
            
            let artistRaw = artistEl.dataset.artist;
            let userId = artistEl.dataset.userid || '';
            if (!artistRaw && artistEl.classList.contains('song-artist-name')) artistRaw = artistEl.textContent.trim();
            
            if (artistRaw && window.innerWidth >= 992) {
              artistHoverTimeout = setTimeout(() => {
                showArtistTooltip(artistEl, artistRaw, userId);
              }, 500);
            }
          } else if (e.target.closest('#artist-hover-tooltip')) {
            clearTimeout(artistHideTimeout);
          }
        });

        document.addEventListener('mouseout', e => {
          const artistEl = e.target.closest('.artist-link, .song-artist, .song-artist-name, .item-subtitle[data-artist], .mention-link, .user-profile-link');
          if (artistEl || e.target.closest('#artist-hover-tooltip')) {
            clearTimeout(artistHoverTimeout);
            artistHideTimeout = setTimeout(() => {
              artistTooltip.style.opacity = '0';
              setTimeout(() => { if (artistTooltip.style.opacity === '0') artistTooltip.style.display = 'none'; }, 200);
            }, 300);
          }
        });

        artistTooltip.addEventListener('click', async e => {
          const followBtn = e.target.closest('.tooltip-follow-btn');
          if (followBtn) {
            if (!currentUser) return showToast('Please log in', 'error');
            const userId = followBtn.dataset.userId;
            const res = await fetchData('?action=toggle_follow', {
              method: 'POST', body: JSON.stringify({ following_id: userId })
            });
            if (res && (res.status === 'followed' || res.status === 'unfollowed')) {
              const isFollowing = res.status === 'followed';
              followBtn.textContent = isFollowing ? 'Unfollow' : 'Follow';
              followBtn.className = `btn btn-sm w-100 mt-2 tooltip-follow-btn fw-bold ${isFollowing ? 'btn-outline-light' : 'btn-danger'}`;
                
              for (let key in artistHoverCache) {
                if (artistHoverCache[key].user_id == userId) {
                  artistHoverCache[key].is_following = isFollowing;
                  artistHoverCache[key].followers_count += isFollowing ? 1 : -1;
                  
                  // Target the specific tooltip card that contains this follow button
                  const card = followBtn.closest('.artist-tooltip-card');
                  if (card) {
                    const followersText = card.querySelector('.text-info');
                    if (followersText) {
                      followersText.innerHTML = `<i class="bi bi-people-fill"></i> ${formatSongCount(artistHoverCache[key].followers_count)} followers`;
                    }
                  }
                }
              }
              if (currentView.type === 'artist_songs' || currentView.type === 'get_following' || currentView.type === 'get_recommendations') {
                loadView(currentView);
              }
            }
          } else {
            const clickArea = e.target.closest('.artist-tt-click');
            if (clickArea) {
              artistTooltip.style.opacity = '0';
              artistTooltip.style.display = 'none';
              loadView({ type: 'artist_songs', param: decodeURIComponent(clickArea.dataset.artist), sort: 'album_asc', filter_user_id: '', artist_name: '' });
            }
          }
        });

        // Calendar Modal Logic
        const calendarModalEl = document.getElementById('calendar-modal');
        let clockInterval;
        let calCurrentMonth, calCurrentYear;
        let calSelectedDate = null;

        const updateClock = () => {
          const now = new Date();
          document.getElementById('calendar-time-display').textContent = now.toLocaleTimeString();
          document.getElementById('calendar-date-display').textContent = now.toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
        };

        const renderCalendar = (month, year) => {
          const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
          document.getElementById('cal-month-year').textContent = `${monthNames[month]} ${year}`;
          
          const daysGrid = document.getElementById('cal-days-grid');
          daysGrid.innerHTML = '';
          
          const firstDay = new Date(year, month, 1).getDay();
          const daysInMonth = new Date(year, month + 1, 0).getDate();
          const today = new Date();
          
          for (let i = 0; i < firstDay; i++) {
            daysGrid.insertAdjacentHTML('beforeend', `<div></div>`);
          }
          
          for (let i = 1; i <= daysInMonth; i++) {
            const isToday = (i === today.getDate() && month === today.getMonth() && year === today.getFullYear());
            const isSelected = (calSelectedDate && i === calSelectedDate.getDate() && month === calSelectedDate.getMonth() && year === calSelectedDate.getFullYear());
            
            let classStr = 'cal-day-item';
            if (isSelected) {
              classStr += ' selected';
            } else if (isToday) {
              classStr += ' today';
            }
            
            daysGrid.insertAdjacentHTML('beforeend', `<div class="${classStr}" data-day="${i}">${i}</div>`);
          }
        };

        if (calendarModalEl) {
          calendarModalEl.addEventListener('show.bs.modal', () => {
            const now = new Date();
            calCurrentMonth = now.getMonth();
            calCurrentYear = now.getFullYear();
            calSelectedDate = new Date();
            
            const jumpInput = document.getElementById('cal-jump-date');
            if (jumpInput) {
              const y = calSelectedDate.getFullYear();
              const m = String(calSelectedDate.getMonth() + 1).padStart(2, '0');
              const d = String(calSelectedDate.getDate()).padStart(2, '0');
              jumpInput.value = `${y}-${m}-${d}`;
            }

            updateClock();
            renderCalendar(calCurrentMonth, calCurrentYear);
            clockInterval = setInterval(updateClock, 1000);
          });
          
          calendarModalEl.addEventListener('hidden.bs.modal', () => {
            clearInterval(clockInterval);
          });
          
          document.getElementById('cal-prev-month').addEventListener('click', () => {
            calCurrentMonth--;
            if (calCurrentMonth < 0) { calCurrentMonth = 11; calCurrentYear--; }
            renderCalendar(calCurrentMonth, calCurrentYear);
          });
          
          document.getElementById('cal-next-month').addEventListener('click', () => {
            calCurrentMonth++;
            if (calCurrentMonth > 11) { calCurrentMonth = 0; calCurrentYear++; }
            renderCalendar(calCurrentMonth, calCurrentYear);
          });

          document.getElementById('cal-days-grid').addEventListener('click', (e) => {
            const dayItem = e.target.closest('.cal-day-item');
            if (dayItem && dayItem.dataset.day) {
              const day = parseInt(dayItem.dataset.day);
              calSelectedDate = new Date(calCurrentYear, calCurrentMonth, day);
              renderCalendar(calCurrentMonth, calCurrentYear);
              
              const jumpInput = document.getElementById('cal-jump-date');
              if (jumpInput) {
                const y = calSelectedDate.getFullYear();
                const m = String(calSelectedDate.getMonth() + 1).padStart(2, '0');
                const d = String(calSelectedDate.getDate()).padStart(2, '0');
                jumpInput.value = `${y}-${m}-${d}`;
              }
            }
          });

          const jumpInput = document.getElementById('cal-jump-date');
          if (jumpInput) {
            jumpInput.addEventListener('change', (e) => {
              if (e.target.value) {
                const parts = e.target.value.split('-');
                calCurrentYear = parseInt(parts[0]);
                calCurrentMonth = parseInt(parts[1]) - 1;
                const day = parseInt(parts[2]);
                calSelectedDate = new Date(calCurrentYear, calCurrentMonth, day);
                renderCalendar(calCurrentMonth, calCurrentYear);
              }
            });
          }

          document.getElementById('cal-today-btn').addEventListener('click', () => {
            const now = new Date();
            calCurrentMonth = now.getMonth();
            calCurrentYear = now.getFullYear();
            calSelectedDate = now;
            renderCalendar(calCurrentMonth, calCurrentYear);
            
            if (jumpInput) {
              const y = now.getFullYear();
              const m = String(now.getMonth() + 1).padStart(2, '0');
              const d = String(now.getDate()).padStart(2, '0');
              jumpInput.value = `${y}-${m}-${d}`;
            }
          });

          const calSearchDateBtn = document.getElementById('cal-search-date-btn');
          if (calSearchDateBtn) {
            calSearchDateBtn.addEventListener('click', () => {
              if (calSelectedDate) {
                const y = calSelectedDate.getFullYear();
                const m = String(calSelectedDate.getMonth() + 1).padStart(2, '0');
                const d = String(calSelectedDate.getDate()).padStart(2, '0');
                const query = `${y}-${m}-${d}`;
                
                const modalInstance = bootstrap.Modal.getOrCreateInstance(calendarModalEl);
                if (modalInstance) modalInstance.hide();

                hideMobileSidebar();
                performSearch(query);
              }
            });
          }
        }

        init();
      });
    </script>
  </body>
</html>